window.SUTRA_PINYIN = {"ksitigarbha-01":[{"note":"dāo lì tiān gōng shén tōng pǐn dì yī","text":"忉利天宫神通品第一"},{"note":"rú shì wǒ wén","text":"如是我闻："},{"note":"yī shí, fó zài dāo lì tiān, wèi mǔ shuō fǎ","text":"一时，佛在忉利天，为母说法。"},{"note":"ěr shí, shí fāng wú liàng shì jiè, bù kě shuō bù kě shuō yī qiè zhū fó","text":"尔时，十方无量世界，不可说不可说一切诸佛，"},{"note":"jí dà pú sà mó hē sà, jiē lái jí huì","text":"及大菩萨摩诃萨，皆来集会。"},{"note":"zàn tàn shì jiā móu ní fó, néng yú wǔ zhuó è shì, xiàn bù kě sī yì dà zhì huì shén tōng zhī lì","text":"赞叹释迦牟尼佛，能于五浊恶世，现不可思议大智慧神通之力，"},{"note":"diào fú gāng qiáng zhòng shēng, zhī kǔ lè fǎ, gè qiǎn shì zhě, wèn xùn shì zūn","text":"调伏刚强众生，知苦乐法，各遣侍者，问讯世尊。"},{"note":"shì shí, rú lái hán xiào, fàng bǎi qiān wàn yì dà guāng míng yún suǒ wèi dà yuán mǎn guāng míng yún","text":"是时，如来含笑，放百千万亿大光明云——所谓大圆满光明云、"},{"note":"dà cí bēi guāng míng yún, dà zhì huì guāng míng yún, dà bō rě guāng míng yún","text":"大慈悲光明云、大智慧光明云、大般若光明云、"},{"note":"dà sān mèi guāng míng yún, dà jí xiáng guāng míng yún, dà fú dé guāng míng yún","text":"大三昧光明云、大吉祥光明云、大福德光明云、"},{"note":"dà gōng dé guāng míng yún, dà guī yī guāng míng yún, dà zàn tàn guāng míng yún","text":"大功德光明云、大归依光明云、大赞叹光明云。"},{"note":"fàng rú shì děng bù kě shuō guāng míng yún yǐ, yòu chū zhǒng zhǒng wēi miào zhī yīn suǒ wèi tán bō luó mì yīn","text":"放如是等不可说光明云已，又出种种微妙之音——所谓檀波罗蜜音、"},{"note":"shī bō luó mì yīn, chàn tí bō luó mì yīn, pí lí yé bō luó mì yīn","text":"尸波罗蜜音、羼提波罗蜜音、毘离耶波罗蜜音、"},{"note":"chán bō luó mì yīn, bō rě bō luó mì yīn, cí bēi yīn, xǐ shě yīn","text":"禅波罗蜜音、般若波罗蜜音、慈悲音、喜舍音、"},{"note":"jiě tuō yīn, wú lòu yīn, zhì huì yīn, dà zhì huì yīn, shī zi hǒu yīn","text":"解脱音、无漏音、智慧音、大智慧音、狮子吼音、"},{"note":"dà shī zi hǒu yīn, yún léi yīn, dà yún léi yīn","text":"大狮子吼音、云雷音、大云雷音。"},{"note":"chū rú shì děng bù kě shuō bù kě shuō yīn yǐ, suō pó shì jiè jí tā fāng guó tǔ","text":"出如是等不可说不可说音已，娑婆世界及他方国土，"},{"note":"yǒu wú liàng yì tiān lóng guǐ shén, yì jí dào dāo lì tiān gōng","text":"有无量亿天龙鬼神，亦集到忉利天宫。"},{"note":"suǒ wèi sì tiān wáng tiān, dāo lì tiān, xū yàn mó tiān, dōu shuài tuó tiān","text":"所谓四天王天、忉利天、须焰摩天、兜率陀天、"},{"note":"huà lè tiān, tā huà zì zài tiān, fàn zhòng tiān, fàn fǔ tiān","text":"化乐天、他化自在天、梵众天、梵辅天、"},{"note":"dà fàn tiān, shǎo guāng tiān, wú liàng guāng tiān, guāng yīn tiān, shǎo jìng tiān","text":"大梵天、少光天、无量光天、光音天、少净天、"},{"note":"wú liàng jìng tiān, biàn jìng tiān, fú shēng tiān, fú ài tiān, guǎng guǒ tiān","text":"无量净天、遍净天、福生天、福爱天、广果天、"},{"note":"wú xiǎng tiān, wú fán tiān, wú rè tiān, shàn jiàn tiān, shàn xiàn tiān","text":"无想天、无烦天、无热天、善见天、善现天、"},{"note":"sè jiū jìng tiān, mó xī shǒu luó tiān, nǎi zhì fēi xiǎng fēi fēi xiǎng chù tiān","text":"色究竟天、摩西首罗天，乃至非想非非想处天，"},{"note":"yī qiè tiān zhòng, lóng zhòng, guǐ shén děng zhòng, xī lái jí huì","text":"一切天众、龙众、鬼神等众，悉来集会。"},{"note":"fù yǒu tā fāng guó tǔ, jí suō pó shì jiè hǎi shén, jiāng shén","text":"复有他方国土，及娑婆世界海神、江神、"},{"note":"hé shén, shù shén, shān shén, dì shén, chuān zé shén, miáo jià shén","text":"河神、树神、山神、地神、川泽神、苗稼神、"},{"note":"zhòu shén, yè shén, kōng shén, tiān shén, yǐn shí shén, cǎo mù shén","text":"昼神、夜神、空神、天神、饮食神、草木神，"},{"note":"rú shì děng shén, jiē lái jí huì","text":"如是等神，皆来集会。"},{"note":"fù yǒu tā fāng guó tǔ, jí suō pó shì jiè zhū dà guǐ wáng suǒ wèi è mù guǐ wáng","text":"复有他方国土，及娑婆世界诸大鬼王——所谓恶目鬼王、"},{"note":"dàn xuè guǐ wáng, dàn jīng qì guǐ wáng, dàn tāi luǎn guǐ wáng, xíng bìng guǐ wáng","text":"啖血鬼王、啖精气鬼王、啖胎卵鬼王、行病鬼王、"},{"note":"shè dú guǐ wáng, cí xīn guǐ wáng, fú lì guǐ wáng, dà ài jìng guǐ wáng","text":"摄毒鬼王、慈心鬼王、福利鬼王、大爱敬鬼王，"},{"note":"rú shì děng guǐ wáng, jiē lái jí huì","text":"如是等鬼王，皆来集会。"},{"note":"ěr shí, shì jiā móu ní fó gào wén shū shī lì fǎ wáng zi pú sà mó hē sà","text":"尔时，释迦牟尼佛告文殊师利法王子菩萨摩诃萨："},{"note":"rǔ guān shì yī qiè zhū fó pú sà, jí tiān lóng guǐ shén, cǐ shì jiè","text":"“汝观是一切诸佛菩萨，及天龙鬼神，此世界，"},{"note":"tā shì jiè, cǐ guó tǔ, tā guó tǔ, rú shì jīn lái jí huì","text":"他世界，此国土，他国土，如是今来集会，"},{"note":"dào dāo lì tiān zhě, rǔ zhī shù bù","text":"到忉利天者，汝知数不？”"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"ruò yǐ wǒ shén lì, qiān jié cè dù, bù néng dé zhī","text":"若以我神力，千劫测度，不能得知。”"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利："},{"note":"wú yǐ fó yǎn guān gù, yóu bù jǐn shù","text":"“吾以佛眼观故，犹不尽数。"},{"note":"cǐ jiē shì dì zàng pú sà jiǔ yuǎn jié lái, yǐ dù, dāng dù","text":"此皆是地藏菩萨久远劫来，已度、当度、"},{"note":"wèi dù, yǐ chéng jiù, dāng chéng jiù, wèi chéng jiù","text":"未度，已成就、当成就、未成就。”"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ yǐ guò qù jiǔ xiū shàn gēn, zhèng wú ài zhì, wén fó suǒ yán","text":"我已过去久修善根，证无碍智，闻佛所言，"},{"note":"jí dāng xìn shòu","text":"即当信受。"},{"note":"xiǎo guǒ shēng wén, tiān lóng bā bù, jí wèi lái shì zhū zhòng shēng děng","text":"小果声闻、天龙八部，及未来世诸众生等，"},{"note":"suī wén rú lái chéng shí zhī yǔ, bì huái yí huò, shè shǐ dǐng shòu","text":"虽闻如来诚实之语，必怀疑惑，设使顶受，"},{"note":"wèi miǎn xīng bàng","text":"未免兴谤。"},{"note":"wéi yuàn shì zūn, guǎng shuō dì zàng pú sà mó hē sà yīn dì zuò hé xíng","text":"唯愿世尊，广说地藏菩萨摩诃萨因地作何行、"},{"note":"lì hé yuàn, ér néng chéng jiù bù sī yì shì","text":"立何愿，而能成就不思议事？”"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利："},{"note":"pì rú sān qiān dà qiān shì jiè, suǒ yǒu cǎo mù cóng lín, dào má zhú wěi","text":"“譬如三千大千世界，所有草木丛林，稻麻竹苇，"},{"note":"shān shí wēi chén, yī wù yī shù, zuò yī héng hé, yī héng hé shā","text":"山石微尘，一物一数，作一恒河，一恒河沙，"},{"note":"yī shā yī jiè","text":"一沙一界。"},{"note":"yī jiè zhī nèi, yī chén yī jié, yī jié zhī nèi, suǒ jī chén shù","text":"一界之内，一尘一劫，一劫之内，所积尘数，"},{"note":"jǐn chōng wèi jié","text":"尽充为劫。"},{"note":"dì zàng pú sà zhèng shí dì guǒ wèi yǐ lái, qiān bèi duō yú shàng yù","text":"地藏菩萨证十地果位已来，千倍多于上喻。"},{"note":"hé kuàng dì zàng pú sà zài shēng wén, pì zhī fó dì","text":"何况地藏菩萨在声闻、辟支佛地。"},{"note":"wén shū shī lì","text":"文殊师利！"},{"note":"cǐ pú sà wēi shén shì yuàn, bù kě sī yì","text":"此菩萨威神誓愿，不可思议。"},{"note":"ruò wèi lái shì, yǒu shàn nán zi, shàn nǚ rén, wén shì pú sà míng zì","text":"若未来世，有善男子、善女人，闻是菩萨名字，"},{"note":"huò zàn tàn, huò zhān lǐ, huò chēng míng, huò gòng yǎng, nǎi zhì cǎi huà","text":"或赞叹，或瞻礼，或称名，或供养，乃至彩画、"},{"note":"kè lòu, sù qī xíng xiàng, shì rén dāng dé bǎi fǎn shēng yú sān shí sān tiān","text":"刻镂、塑漆形像，是人当得百返生于三十三天，"},{"note":"yǒng bù duò è dào","text":"永不堕恶道。”"},{"note":"wén shū shī lì","text":"“文殊师利！"},{"note":"shì dì zàng pú sà mó hē sà, yú guò qù jiǔ yuǎn bù kě shuō bù kě shuō jié qián","text":"是地藏菩萨摩诃萨，于过去久远不可说不可说劫前，"},{"note":"shēn wèi dà zhǎng zhě zi","text":"身为大长者子。"},{"note":"shí shì yǒu fó, hào yuē shī zi fèn xùn jù zú wàn xíng rú lái","text":"时世有佛，号曰狮子奋迅具足万行如来。"},{"note":"shí zhǎng zhě zi, jiàn fó xiāng hǎo, qiān fú zhuāng yán, yīn wèn bǐ fó","text":"时长者子，见佛相好，千福庄严，因问彼佛："},{"note":"zuò hé xíng yuàn, ér dé cǐ xiāng. shí shī zi fèn xùn jù zú wàn xíng rú lái gào zhǎng zhě zi","text":"‘作何行愿，而得此相？’时狮子奋迅具足万行如来告长者子："},{"note":"yù zhèng cǐ shēn, dāng xū jiǔ yuǎn dù tuō yī qiè shòu kǔ zhòng shēng","text":"‘欲证此身，当须久远度脱一切受苦众生。’”"},{"note":"wén shū shī lì","text":"“文殊师利！"},{"note":"shí zhǎng zhě zi, yīn fā yuàn yán","text":"时长者子，因发愿言："},{"note":"wǒ jīn jǐn wèi lái jì bù kě jì jié, wèi shì zuì kǔ liù dào zhòng shēng","text":"‘我今尽未来际不可计劫，为是罪苦六道众生，"},{"note":"guǎng shè fāng biàn, jǐn lìng jiě tuō, ér wǒ zì shēn, fāng chéng fó dào. yǐ shì yú bǐ fó qián","text":"广设方便，尽令解脱，而我自身，方成佛道。’以是于彼佛前，"},{"note":"lì sī dà yuàn, yú jīn bǎi qiān wàn yì nà yóu tā bù kě shuō jié","text":"立斯大愿，于今百千万亿那由他不可说劫，"},{"note":"shàng wèi pú sà","text":"尚为菩萨。”"},{"note":"yòu yú guò qù, bù kě sī yì ā sēng qí jié, shí shì yǒu fó","text":"“又于过去，不可思议阿僧祇劫，时世有佛，"},{"note":"hào yuē jué huá dìng zì zài wáng rú lái","text":"号曰觉华定自在王如来。"},{"note":"bǐ fó shòu mìng, sì bǎi qiān wàn yì ā sēng qí jié","text":"彼佛寿命，四百千万亿阿僧祇劫。"},{"note":"xiàng fǎ zhī zhōng, yǒu yī pó luó mén nǚ, sù fú shēn hòu, zhòng suǒ qīn jìng","text":"像法之中，有一婆罗门女，宿福深厚，众所钦敬；"},{"note":"xíng zhù zuò wò, zhū tiān wèi hù","text":"行住坐卧，诸天卫护。"},{"note":"qí mǔ xìn xié, cháng qīng sān bǎo","text":"其母信邪，常轻三宝。"},{"note":"shì shí shèng nǚ, guǎng shè fāng biàn, quàn yòu qí mǔ, lìng shēng zhèng jiàn","text":"是时圣女，广设方便，劝诱其母，令生正见。"},{"note":"ér cǐ nǚ mǔ, wèi quán shēng xìn, bù jiǔ mìng zhōng, hún shén duò zài wú jiān dì yù","text":"而此女母，未全生信，不久命终，魂神堕在无间地狱。"},{"note":"shí pó luó mén nǚ, zhī mǔ zài shì bù xìn yīn guǒ, jì dāng suí yè","text":"时婆罗门女，知母在世不信因果，计当随业，"},{"note":"bì shēng è qù","text":"必生恶趣。"},{"note":"suì mài jiā zhái, guǎng qiú xiāng huá, jí zhū gòng jù, yú xiān fó tǎ sì","text":"遂卖家宅，广求香华，及诸供具，于先佛塔寺，"},{"note":"dà xīng gòng yǎng","text":"大兴供养。"},{"note":"jiàn jué huá dìng zì zài wáng rú lái, qí xíng xiàng zài yī sì zhōng","text":"见觉华定自在王如来，其形像在一寺中，"},{"note":"sù huà wēi róng, duān yán bì bèi","text":"塑画威容，端严毕备。"},{"note":"shí pó luó mén nǚ, zhān lǐ zūn róng, bèi shēng jìng yǎng","text":"时婆罗门女，瞻礼尊容，倍生敬仰。"},{"note":"sī zì niàn yán","text":"私自念言："},{"note":"fó míng dà jué, jù yī qiè zhì, ruò zài shì shí, wǒ mǔ sǐ hòu","text":"‘佛名大觉，具一切智，若在世时，我母死后，"},{"note":"tǎng lái wèn fó, bì zhī chù suǒ. shí pó luó mén nǚ, chuí qì liáng jiǔ","text":"傥来问佛，必知处所。’时婆罗门女，垂泣良久，"},{"note":"zhān liàn rú lái","text":"瞻恋如来。"},{"note":"hū wén kōng zhōng shēng yuē","text":"忽闻空中声曰："},{"note":"qì zhě shèng nǚ","text":"‘泣者圣女！"},{"note":"wù zhì bēi āi, wǒ jīn shì rǔ mǔ zhī qù chù. pó luó mén nǚ hé zhǎng xiàng kōng","text":"勿至悲哀，我今示汝母之去处。’婆罗门女合掌向空，"},{"note":"ér bái kōng yuē","text":"而白空曰："},{"note":"shì hé shén dé, kuān wǒ yōu lǜ","text":"‘是何神德，宽我忧虑。"},{"note":"wǒ zì shī mǔ yǐ lái, zhòu yè yì liàn, wú chù kě wèn zhī mǔ shēng jiè. shí kōng zhōng yǒu shēng","text":"我自失母已来，昼夜忆恋，无处可问知母生界。’时空中有声，"},{"note":"zài bào nǚ yuē","text":"再报女曰："},{"note":"wǒ shì rǔ suǒ zhān lǐ zhě, guò qù jué huá dìng zì zài wáng rú lái","text":"‘我是汝所瞻礼者，过去觉华定自在王如来。"},{"note":"jiàn rǔ yì mǔ, bèi yú cháng qíng zhòng shēng zhī fēn, gù lái gào shì. pó luó mén nǚ wén cǐ shēng yǐ","text":"见汝忆母，倍于常情众生之分，故来告示。’婆罗门女闻此声已，"},{"note":"jǔ shēn zì pū, zhī jié jiē sǔn","text":"举身自扑，支节皆损。"},{"note":"zuǒ yòu fú chí, liáng jiǔ fāng sū, ér bái kōng yuē","text":"左右扶持，良久方苏，而白空曰："},{"note":"yuàn fó cí mǐn, sù shuō wǒ mǔ shēng jiè","text":"‘愿佛慈悯，速说我母生界。"},{"note":"wǒ jīn shēn xīn, jiāng sǐ bù jiǔ. shí jué huá dìng zì zài wáng rú lái gào shèng nǚ yuē","text":"我今身心，将死不久。’时觉华定自在王如来告圣女曰："},{"note":"rǔ gòng yǎng bì, dàn zǎo fǎn shě","text":"‘汝供养毕，但早返舍。"},{"note":"duān zuò sī wéi wú zhī míng hào, jí dāng zhī mǔ suǒ shēng qù chù","text":"端坐思惟吾之名号，即当知母所生去处。’”"},{"note":"shí pó luó mén nǚ, xún lǐ fó yǐ, jí guī qí shě","text":"“时婆罗门女，寻礼佛已，即归其舍。"},{"note":"yǐ yì mǔ gù, duān zuò niàn jué huá dìng zì zài wáng rú lái, jīng yī rì yī yè","text":"以忆母故，端坐念觉华定自在王如来，经一日一夜。"},{"note":"hū jiàn zì shēn, dào yī hǎi biān","text":"忽见自身，到一海边。"},{"note":"qí shuǐ yǒng fèi, duō zhū è shòu, jǐn fù tiě shēn, fēi zǒu hǎi shàng","text":"其水涌沸，多诸恶兽，尽复铁身，飞走海上，"},{"note":"dōng xī chí zhú","text":"东西驰逐。"},{"note":"jiàn zhū nán zi nǚ rén, bǎi qiān wàn shù, chū méi hǎi zhōng, bèi zhū è shòu zhēng qǔ shí dàn","text":"见诸男子女人，百千万数，出没海中，被诸恶兽争取食啖。"},{"note":"yòu jiàn yè chā, qí xíng gè yì, huò duō shǒu duō yǎn, duō zú duō tóu","text":"又见夜叉，其形各异，或多手多眼，多足多头，"},{"note":"kǒu yá wài chū, lì rèn rú jiàn, qū zhū zuì rén, shǐ jìn è shòu","text":"口牙外出，利刃如剑，驱诸罪人，使近恶兽，"},{"note":"fù zì bó jué, tóu zú xiāng jiù","text":"复自搏攫，头足相就。"},{"note":"qí xíng wàn lèi, bù gǎn jiǔ shì","text":"其形万类，不敢久视。"},{"note":"shí pó luó mén nǚ, yǐ niàn fó lì gù, zì rán wú jù","text":"时婆罗门女，以念佛力故，自然无惧。”"},{"note":"yǒu yī guǐ wáng, míng yuē wú dú, jī shǒu lái yíng, bái shèng nǚ yuē","text":"“有一鬼王，名曰无毒，稽首来迎，白圣女曰："},{"note":"shàn zāi","text":"‘善哉！"},{"note":"pú sà hé yuán lái cǐ. shí pó luó mén nǚ wèn guǐ wáng yuē","text":"菩萨何缘来此？’时婆罗门女问鬼王曰："},{"note":"cǐ shì hé chù. wú dú dá yuē","text":"‘此是何处？’无毒答曰："},{"note":"cǐ shì dà tiě wéi shān xī miàn dì yī zhòng hǎi. shèng nǚ wèn yuē","text":"‘此是大铁围山西面第一重海。’圣女问曰："},{"note":"wǒ wén tiě wéi zhī nèi, dì yù zài zhōng, shì shì shí bù. wú dú dá yuē","text":"‘我闻铁围之内，地狱在中，是事实不？’无毒答曰："},{"note":"shí yǒu dì yù. shèng nǚ wèn yuē","text":"‘实有地狱。’圣女问曰："},{"note":"wǒ jīn yún hé, dé dào yù suǒ. wú dú dá yuē","text":"‘我今云何，得到狱所？’无毒答曰："},{"note":"ruò fēi wēi shén, jí xū yè lì, fēi cǐ èr shì, zhōng bù néng dào. shèng nǚ yòu wèn","text":"‘若非威神，即须业力，非此二事，终不能到。’圣女又问："},{"note":"cǐ shuǐ hé yuán, ér nǎi yǒng fèi","text":"‘此水何缘，而乃涌沸？"},{"note":"duō zhū zuì rén, jí yǐ è shòu. wú dú dá yuē","text":"多诸罪人，及以恶兽？’无毒答曰："},{"note":"cǐ shì yán fú tí zào è zhòng shēng xīn sǐ zhī zhě, jīng sì shí jiǔ rì hòu","text":"‘此是阎浮提造恶众生新死之者，经四十九日后，"},{"note":"wú rén jì sì wèi zuò gōng dé, jiù bá kǔ nán, shēng shí yòu wú shàn yīn","text":"无人继嗣为作功德，救拔苦难，生时又无善因，"},{"note":"dāng jù běn yè suǒ gǎn dì yù, zì rán xiān dù cǐ hǎi","text":"当据本业所感地狱，自然先渡此海。"},{"note":"hǎi dōng shí wàn yóu xún, yòu yǒu yī hǎi, qí kǔ bèi cǐ","text":"海东十万由旬，又有一海，其苦倍此。"},{"note":"bǐ hǎi zhī dōng, yòu yǒu yī hǎi, qí kǔ fù bèi","text":"彼海之东，又有一海，其苦复倍。"},{"note":"sān yè è yīn zhī suǒ zhāo gǎn, gòng hào yè hǎi, qí chù shì yě. shèng nǚ yòu wèn guǐ wáng wú dú yuē","text":"三业恶因之所招感，共号业海，其处是也。’圣女又问鬼王无毒曰："},{"note":"dì yù hé zài. wú dú dá yuē","text":"‘地狱何在？’无毒答曰："},{"note":"sān hǎi zhī nèi, shì dà dì yù, qí shù bǎi qiān, gè gè chà bié","text":"‘三海之内，是大地狱，其数百千，各各差别。"},{"note":"suǒ wèi dà zhě, jù yǒu shí bā","text":"所谓大者，具有十八。"},{"note":"cì yǒu wǔ bǎi, kǔ dú wú liàng","text":"次有五百，苦毒无量。"},{"note":"cì yǒu qiān bǎi, yì wú liàng kǔ. shèng nǚ yòu wèn dà guǐ wáng yuē","text":"次有千百，亦无量苦。’圣女又问大鬼王曰："},{"note":"wǒ mǔ sǐ lái wèi jiǔ, bù zhī hún shén dāng zhì hé qù. guǐ wáng wèn shèng nǚ yuē","text":"‘我母死来未久，不知魂神当至何趣？’鬼王问圣女曰："},{"note":"pú sà zhī mǔ, zài shēng xí hé xíng yè. shèng nǚ dá yuē","text":"‘菩萨之母，在生习何行业？’圣女答曰："},{"note":"wǒ mǔ xié jiàn, jī huǐ sān bǎo","text":"‘我母邪见，讥毁三宝。"},{"note":"shè huò zàn xìn, xuán yòu bù jìng","text":"设或暂信，旋又不敬。"},{"note":"sǐ suī rì qiǎn, wèi zhī shēng chù. wú dú wèn yuē","text":"死虽日浅，未知生处。’无毒问曰："},{"note":"pú sà zhī mǔ, xìng shì hé děng. shèng nǚ dá yuē","text":"‘菩萨之母，姓氏何等？’圣女答曰："},{"note":"wǒ fù wǒ mǔ, jù pó luó mén zhǒng","text":"‘我父我母，俱婆罗门种。"},{"note":"fù hào shī luó shàn xiàn, mǔ hào yuè dì lì. wú dú hé zhǎng","text":"父号尸罗善现，母号悦帝利。’无毒合掌，"},{"note":"qǐ pú sà yuē","text":"启菩萨曰："},{"note":"yuàn shèng zhě què fǎn běn chù, wú zhì yōu yì bēi liàn","text":"‘愿圣者却返本处，无至忧忆悲恋。"},{"note":"yuè dì lì zuì nǚ, shēng tiān yǐ lái, jīng jīn sān rì","text":"悦帝利罪女，生天以来，经今三日。"},{"note":"yún chéng xiào shùn zhī zi, wèi mǔ shè gōng, xiū fú, bù shī jué huá dìng zì zài wáng rú lái tǎ sì","text":"云承孝顺之子，为母设供、修福，布施觉华定自在王如来塔寺。"},{"note":"fēi wéi pú sà zhī mǔ dé tuō dì yù, yīng shì wú jiān zuì rén","text":"非唯菩萨之母得脱地狱，应是无间罪人，"},{"note":"cǐ rì xī dé shòu lè, jù tóng shēng qì. guǐ wáng yán bì","text":"此日悉得受乐，俱同生讫。’鬼王言毕，"},{"note":"hé zhǎng ér tuì","text":"合掌而退。"},{"note":"pó luó mén nǚ, xún rú mèng guī","text":"婆罗门女，寻如梦归。"},{"note":"wù cǐ shì yǐ, biàn yú jué huá dìng zì zài wáng rú lái tǎ xiàng zhī qián","text":"悟此事已，便于觉华定自在王如来塔像之前，"},{"note":"lì hóng shì yuàn","text":"立弘誓愿："},{"note":"yuàn wǒ jǐn wèi lái jié, yīng yǒu zuì kǔ zhòng shēng, guǎng shè fāng biàn","text":"‘愿我尽未来劫，应有罪苦众生，广设方便，"},{"note":"shǐ lìng jiě tuō","text":"使令解脱。’”"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利："},{"note":"shí guǐ wáng wú dú zhě, dāng jīn cái shǒu pú sà shì","text":"“时鬼王无毒者，当今财首菩萨是。"},{"note":"pó luó mén nǚ zhě, jí dì zàng pú sà shì","text":"婆罗门女者，即地藏菩萨是。”"}],"ksitigarbha-02":[{"note":"fēn shēn jí huì pǐn dì èr","text":"分身集会品第二"},{"note":"ěr shí, bǎi qiān wàn yì bù kě sī, bù kě yì, bù kě liàng","text":"尔时，百千万亿不可思、不可议、不可量、"},{"note":"bù kě shuō, wú liàng ā sēng qí shì jiè, suǒ yǒu dì yù chù","text":"不可说、无量阿僧祇世界，所有地狱处，"},{"note":"fēn shēn dì zàng pú sà, jù lái jí zài dāo lì tiān gōng","text":"分身地藏菩萨，俱来集在忉利天宫。"},{"note":"yǐ rú lái shén lì gù, gè yǐ fāng miàn, yǔ zhū dé jiě tuō cóng yè dào chū zhě","text":"以如来神力故，各以方面，与诸得解脱从业道出者，"},{"note":"yì gè yǒu qiān wàn yì nà yóu tā shù, gòng chí xiāng huá, lái gòng yǎng fó","text":"亦各有千万亿那由他数，共持香华，来供养佛。"},{"note":"bǐ zhū tóng lái děng bèi, jiē yīn dì zàng pú sà jiào huà, yǒng bù tuì zhuǎn yú ā nòu duō luó sān miǎo sān pú tí","text":"彼诸同来等辈，皆因地藏菩萨教化，永不退转于阿耨多罗三藐三菩提。"},{"note":"shì zhū zhòng děng, jiǔ yuǎn jié lái, liú làng shēng sǐ, liù dào shòu kǔ","text":"是诸众等，久远劫来，流浪生死，六道受苦，"},{"note":"zàn wú xiū xī","text":"暂无休息。"},{"note":"yǐ dì zàng pú sà guǎng dà cí bēi, shēn shì yuàn gù, gè huò guǒ zhèng","text":"以地藏菩萨广大慈悲，深誓愿故，各获果证。"},{"note":"jì zhì dāo lì, xīn huái yǒng yuè, zhān yǎng rú lái, mù bù zàn shě","text":"既至忉利，心怀踊跃，瞻仰如来，目不暂舍。"},{"note":"ěr shí, shì zūn shū jīn sè bì, mó bǎi qiān wàn yì bù kě sī","text":"尔时，世尊舒金色臂，摩百千万亿不可思、"},{"note":"bù kě yì, bù kě liàng, bù kě shuō, wú liàng ā sēng qí shì jiè zhū fēn shēn dì zàng pú sà mó hē sà dǐng","text":"不可议、不可量、不可说、无量阿僧祇世界诸分身地藏菩萨摩诃萨顶，"},{"note":"ér zuò shì yán","text":"而作是言："},{"note":"wú yú wǔ zhuó è shì, jiào huà rú shì gāng qiáng zhòng shēng, lìng xīn diào fú","text":"“吾于五浊恶世，教化如是刚强众生，令心调伏，"},{"note":"shě xié guī zhèng","text":"舍邪归正。"},{"note":"shí yǒu yī èr, shàng è xí zài","text":"十有一二，尚恶习在。"},{"note":"wú yì fēn shēn qiān bǎi yì, guǎng shè fāng biàn","text":"吾亦分身千百亿，广设方便。"},{"note":"huò yǒu lì gēn, wén jí xìn shòu","text":"或有利根，闻即信受。"},{"note":"huò yǒu shàn guǒ, qín quàn chéng jiù","text":"或有善果，勤劝成就。"},{"note":"huò yǒu àn dùn, jiǔ huà fāng guī","text":"或有暗钝，久化方归。"},{"note":"huò yǒu yè zhòng, bù shēng jìng yǎng","text":"或有业重，不生敬仰。"},{"note":"rú shì děng bèi zhòng shēng, gè gè chà bié, fēn shēn dù tuō","text":"如是等辈众生，各各差别，分身度脱。"},{"note":"huò xiàn nán zi shēn, huò xiàn nǚ rén shēn, huò xiàn tiān lóng shēn","text":"或现男子身，或现女人身，或现天龙身，"},{"note":"huò xiàn shén guǐ shēn, huò xiàn shān lín chuān yuán, hé chí quán jǐng","text":"或现神鬼身，或现山林川原、河池泉井，"},{"note":"lì jí yú rén, xī jiē dù tuō","text":"利及于人，悉皆度脱。"},{"note":"huò xiàn tiān dì shēn, huò xiàn fàn wáng shēn, huò xiàn zhuǎn lún wáng shēn","text":"或现天帝身，或现梵王身，或现转轮王身，"},{"note":"huò xiàn jū shì shēn, huò xiàn guó wáng shēn, huò xiàn zǎi fǔ shēn","text":"或现居士身，或现国王身，或现宰辅身，"},{"note":"huò xiàn guān shǔ shēn, huò xiàn bǐ qiū, bǐ qiū ní, yōu pó sāi","text":"或现官属身，或现比丘、比丘尼、优婆塞、"},{"note":"yōu pó yí shēn, nǎi zhì shēng wén, luó hàn, pì zhī fó, pú sà děng shēn","text":"优婆夷身，乃至声闻、罗汉、辟支佛、菩萨等身，"},{"note":"ér yǐ huà dù","text":"而以化度。"},{"note":"fēi dàn fó shēn, dú xiàn qí qián","text":"非但佛身，独现其前。"},{"note":"rǔ guān wú lèi jié qín kǔ, dù tuō rú shì děng nán huà gāng qiáng zuì kǔ zhòng shēng","text":"汝观吾累劫勤苦，度脱如是等难化刚强罪苦众生。"},{"note":"qí yǒu wèi diào fú zhě, suí yè bào yīng","text":"其有未调伏者，随业报应。"},{"note":"ruò duò è qù, shòu dà kǔ shí, rǔ dāng yì niàn wú zài dāo lì tiān gōng","text":"若堕恶趣，受大苦时，汝当忆念吾在忉利天宫，"},{"note":"yīn qín fù zhǔ","text":"殷勤付嘱。"},{"note":"lìng suō pó shì jiè, zhì mí lè chū shì yǐ lái zhòng shēng, xī shǐ jiě tuō","text":"令娑婆世界，至弥勒出世已来众生，悉使解脱，"},{"note":"yǒng lí zhū kǔ, yù fó shòu jì","text":"永离诸苦，遇佛授记。”"},{"note":"ěr shí, zhū shì jiè fēn shēn dì zàng pú sà, gòng fù yī xíng","text":"尔时，诸世界分身地藏菩萨，共复一形，"},{"note":"tì lèi āi liàn, bái qí fó yán","text":"涕泪哀恋，白其佛言："},{"note":"wǒ cóng jiǔ yuǎn jié lái, méng fó jiē yǐn, shǐ huò bù kě sī yì shén lì","text":"“我从久远劫来，蒙佛接引，使获不可思议神力，"},{"note":"jù dà zhì huì","text":"具大智慧。"},{"note":"wǒ suǒ fēn shēn, biàn mǎn bǎi qiān wàn yì héng hé shā shì jiè","text":"我所分身，遍满百千万亿恒河沙世界。"},{"note":"měi yī shì jiè, huà bǎi qiān wàn yì shēn","text":"每一世界，化百千万亿身。"},{"note":"měi yī shēn, dù bǎi qiān wàn yì rén, lìng guī jìng sān bǎo, yǒng lí shēng sǐ","text":"每一身，度百千万亿人，令归敬三宝，永离生死，"},{"note":"zhì niè pán lè","text":"至涅槃乐。"},{"note":"dàn yú fó fǎ zhōng, suǒ wèi shàn shì, yī máo yī dì, yī shā yī chén","text":"但于佛法中，所为善事，一毛一渧，一沙一尘，"},{"note":"huò háo fā xǔ, wǒ jiàn dù tuō, shǐ huò dà lì","text":"或毫发许，我渐度脱，使获大利。"},{"note":"wéi yuàn shì zūn bù yǐ hòu shì è yè zhòng shēng wèi lǜ. rú shì sān bái fó yán","text":"唯愿世尊不以后世恶业众生为虑。”如是三白佛言："},{"note":"wéi yuàn shì zūn bù yǐ hòu shì è yè zhòng shēng wèi lǜ","text":"“唯愿世尊不以后世恶业众生为虑。”"},{"note":"ěr shí, fó zàn dì zàng pú sà yán","text":"尔时，佛赞地藏菩萨言："},{"note":"shàn zāi","text":"“善哉！"},{"note":"shàn zāi","text":"善哉！"},{"note":"wú zhù rǔ xǐ","text":"吾助汝喜。"},{"note":"rǔ néng chéng jiù jiǔ yuǎn jié lái, fā hóng shì yuàn, guǎng dù jiāng bì","text":"汝能成就久远劫来，发弘誓愿，广度将毕，"},{"note":"jí zhèng pú tí","text":"即证菩提。”"}],"ksitigarbha-03":[{"note":"guān zhòng shēng yè yuán pǐn dì sān","text":"观众生业缘品第三"},{"note":"ěr shí, fó mǔ mó yé fū rén, gōng jìng hé zhǎng, wèn dì zàng pú sà yán","text":"尔时，佛母摩耶夫人，恭敬合掌，问地藏菩萨言："},{"note":"shèng zhě","text":"“圣者！"},{"note":"yán fú zhòng shēng, zào yè chà bié, suǒ shòu bào yīng, qí shì yún hé","text":"阎浮众生，造业差别，所受报应，其事云何？”"},{"note":"dì zàng dá yán","text":"地藏答言："},{"note":"qiān wàn shì jiè, nǎi jí guó tǔ, huò yǒu dì yù, huò wú dì yù","text":"“千万世界，乃及国土，或有地狱，或无地狱，"},{"note":"huò yǒu nǚ rén, huò wú nǚ rén, huò yǒu fó fǎ, huò wú fó fǎ","text":"或有女人，或无女人，或有佛法，或无佛法，"},{"note":"nǎi zhì shēng wén, pì zhī fó, yì fù rú shì","text":"乃至声闻、辟支佛，亦复如是。"},{"note":"fēi dàn dì yù, zuì bào yī děng. mó yé fū rén zhòng bái pú sà","text":"非但地狱，罪报一等。”摩耶夫人重白菩萨："},{"note":"qiě yuàn wén yú yán fú zuì bào, suǒ gǎn è qù. dì zàng dá yán","text":"“且愿闻于阎浮罪报，所感恶趣。”地藏答言："},{"note":"shèng mǔ","text":"“圣母！"},{"note":"wéi yuàn tīng shòu, wǒ cū shuō zhī. fó mǔ bái yán","text":"唯愿听受，我粗说之。”佛母白言："},{"note":"yuàn shèng zhě shuō","text":"“愿圣者说。”"},{"note":"ěr shí, dì zàng pú sà bái shèng mǔ yán","text":"尔时，地藏菩萨白圣母言："},{"note":"nán yán fú tí zuì bào, míng hào rú shì","text":"“南阎浮提罪报，名号如是："},{"note":"ruò yǒu zhòng shēng, bù xiào fù mǔ, huò zhì shā hài, dāng duò wú jiān dì yù","text":"若有众生，不孝父母，或至杀害，当堕无间地狱，"},{"note":"qiān wàn yì jié, qiú chū wú qī","text":"千万亿劫，求出无期。"},{"note":"ruò yǒu zhòng shēng, chū fó shēn xuè, huǐ bàng sān bǎo, bù jìng zūn jīng","text":"若有众生，出佛身血，毁谤三宝，不敬尊经，"},{"note":"yì dāng duò yú wú jiān dì yù, qiān wàn yì jié, qiú chū wú qī","text":"亦当堕于无间地狱，千万亿劫，求出无期。"},{"note":"ruò yǒu zhòng shēng, qīn sǔn cháng zhù, diàn wū sēng ní, huò qié lán nèi","text":"若有众生，侵损常住，玷污僧尼，或伽蓝内，"},{"note":"zì xíng yín yù, huò shā huò hài, rú shì děng bèi, dāng duò wú jiān dì yù","text":"恣行淫欲，或杀或害，如是等辈，当堕无间地狱，"},{"note":"qiān wàn yì jié, qiú chū wú qī","text":"千万亿劫，求出无期。"},{"note":"ruò yǒu zhòng shēng, wěi zuò shā mén, xīn fēi shā mén, pò yòng cháng zhù","text":"若有众生，伪作沙门，心非沙门，破用常住，"},{"note":"qī kuáng bái yī, wéi bèi jiè lǜ, zhǒng zhǒng zào è, rú shì děng bèi","text":"欺诳白衣，违背戒律，种种造恶，如是等辈，"},{"note":"dāng duò wú jiān dì yù, qiān wàn yì jié, qiú chū wú qī","text":"当堕无间地狱，千万亿劫，求出无期。"},{"note":"ruò yǒu zhòng shēng, tōu qiè cháng zhù cái wù gǔ mǐ, yǐn shí yī fú","text":"若有众生，偷窃常住财物谷米、饮食衣服，"},{"note":"nǎi zhì yī wù bù yǔ qǔ zhě, dāng duò wú jiān dì yù, qiān wàn yì jié","text":"乃至一物不与取者，当堕无间地狱，千万亿劫，"},{"note":"qiú chū wú qī","text":"求出无期。”"},{"note":"dì zàng bái yán","text":"地藏白言："},{"note":"shèng mǔ","text":"“圣母！"},{"note":"ruò yǒu zhòng shēng, zuò rú shì zuì, dāng duò wǔ wú jiān dì yù","text":"若有众生，作如是罪，当堕五无间地狱，"},{"note":"qiú zàn tíng kǔ, yī niàn bù dé","text":"求暂停苦，一念不得。”"},{"note":"mó yé fū rén zhòng bái dì zàng pú sà yán","text":"摩耶夫人重白地藏菩萨言："},{"note":"yún hé míng wèi wú jiān dì yù","text":"“云何名为无间地狱？”"},{"note":"dì zàng bái yán","text":"地藏白言："},{"note":"shèng mǔ","text":"“圣母！"},{"note":"zhū yǒu dì yù, zài dà tiě wéi shān zhī nèi","text":"诸有地狱，在大铁围山之内。"},{"note":"qí dà dì yù, yǒu yī shí bā suǒ","text":"其大地狱，有一十八所。"},{"note":"cì yǒu wǔ bǎi, míng hào gè bié","text":"次有五百，名号各别。"},{"note":"cì yǒu qiān bǎi, míng zì yì bié","text":"次有千百，名字亦别。"},{"note":"wú jiān yù zhě, qí yù chéng zhōu zā bā wàn yú lǐ, qí chéng chún tiě","text":"无间狱者，其狱城周匝八万余里，其城纯铁，"},{"note":"gāo yī wàn lǐ, chéng shàng huǒ jù, shǎo yǒu kōng quē","text":"高一万里，城上火聚，少有空缺。"},{"note":"qí yù chéng zhōng, zhū yù xiāng lián, míng hào gè bié","text":"其狱城中，诸狱相连，名号各别。"},{"note":"dú yǒu yī yù, míng yuē wú jiān","text":"“独有一狱，名曰无间。"},{"note":"qí yù zhōu zā wàn bā qiān lǐ, yù qiáng gāo yī qiān lǐ, xī shì tiě wéi","text":"其狱周匝万八千里，狱墙高一千里，悉是铁围，"},{"note":"shàng huǒ chè xià, xià huǒ chè shàng, tiě shé tiě gǒu, tǔ huǒ chí zhú","text":"上火彻下，下火彻上，铁蛇铁狗，吐火驰逐，"},{"note":"yù qiáng zhī shàng, dōng xī ér zǒu","text":"狱墙之上，东西而走。"},{"note":"yù zhōng yǒu chuáng, biàn mǎn wàn lǐ","text":"狱中有床，遍满万里。"},{"note":"yī rén shòu zuì, zì jiàn qí shēn, biàn wò mǎn chuáng","text":"一人受罪，自见其身，遍卧满床。"},{"note":"qiān wàn rén shòu zuì, yì gè zì jiàn, shēn mǎn chuáng shàng","text":"千万人受罪，亦各自见，身满床上。"},{"note":"zhòng yè suǒ gǎn, huò bào rú shì","text":"众业所感，获报如是。"},{"note":"yòu zhū zuì rén, bèi shòu zhòng kǔ","text":"又诸罪人，备受众苦。"},{"note":"qiān bǎi yè chā, jí yǐ è guǐ, kǒu yá rú jiàn, yǎn rú diàn guāng","text":"千百夜叉，及以恶鬼，口牙如剑，眼如电光，"},{"note":"shǒu fù tóng zhǎo, tuō zhuāi zuì rén","text":"手复铜爪，拖拽罪人。"},{"note":"fù yǒu yè chā, zhí dà tiě jǐ, zhōng zuì rén shēn, huò zhōng kǒu bí","text":"复有夜叉，执大铁戟，中罪人身，或中口鼻，"},{"note":"huò zhōng fù bèi, pāo kōng fān jiē, huò zhì chuáng shàng","text":"或中腹背，抛空翻接，或置床上。"},{"note":"fù yǒu tiě yīng, dàn zuì rén mù","text":"复有铁鹰，啖罪人目。"},{"note":"fù yǒu tiě shé, jiǎo zuì rén jǐng","text":"复有铁蛇，缴罪人颈。"},{"note":"bǎi zhī jié nèi, xī xià zhǎng dīng, bá shé gēng lí, chōu cháng cuò zhǎn","text":"百肢节内，悉下长钉，拔舌耕犁，抽肠锉斩，"},{"note":"yáng tóng guàn kǒu, rè tiě chán shēn","text":"洋铜灌口，热铁缠身。"},{"note":"wàn sǐ qiān shēng, yè gǎn rú shì","text":"万死千生，业感如是。"},{"note":"dòng jīng yì jié, qiú chū wú qī","text":"动经亿劫，求出无期。"},{"note":"cǐ jiè huài shí, jì shēng tā jiè","text":"此界坏时，寄生他界。"},{"note":"tā jiè cì huài, zhuǎn jì tā fāng","text":"他界次坏，转寄他方。"},{"note":"tā fāng huài shí, zhǎn zhuǎn xiāng jì","text":"他方坏时，展转相寄。"},{"note":"cǐ jiè chéng hòu, hái fù ér lái","text":"此界成后，还复而来。"},{"note":"wú jiān zuì bào, qí shì rú shì","text":"无间罪报，其事如是。"},{"note":"yòu wǔ shì yè gǎn, gù chēng wú jiān","text":"“又五事业感，故称无间。"},{"note":"hé děng wèi wǔ","text":"何等为五？"},{"note":"yī zhě, rì yè shòu zuì, yǐ zhì jié shù, wú shí jiān jué","text":"一者，日夜受罪，以至劫数，无时间绝，"},{"note":"gù chēng wú jiān","text":"故称无间。"},{"note":"èr zhě, yī rén yì mǎn, duō rén yì mǎn, gù chēng wú jiān","text":"二者，一人亦满，多人亦满，故称无间。"},{"note":"sān zhě, zuì qì chā bàng, yīng shé láng quǎn, duì mó jù záo","text":"三者，罪器叉棒，鹰蛇狼犬，碓磨锯凿，"},{"note":"cuò zhuó huò tāng, tiě wǎng tiě shéng, tiě lǘ tiě mǎ, shēng gé luò shǒu","text":"锉斫镬汤，铁网铁绳，铁驴铁马，生革络首，"},{"note":"rè tiě jiāo shēn, jī tūn tiě wán, kě yǐn tiě zhī","text":"热铁浇身，饥吞铁丸，渴饮铁汁。"},{"note":"cóng nián jìng jié, shù nà yóu tā, kǔ chǔ xiāng lián, gèng wú jiān duàn","text":"从年竟劫，数那由他，苦楚相连，更无间断，"},{"note":"gù chēng wú jiān","text":"故称无间。"},{"note":"sì zhě, bù wèn nán zi nǚ rén, qiāng hú yí dí, lǎo yòu guì jiàn","text":"四者，不问男子女人，羌胡夷狄，老幼贵贱，"},{"note":"huò lóng huò shén, huò tiān huò guǐ, zuì xíng yè gǎn, xī tóng shòu zhī","text":"或龙或神，或天或鬼，罪行业感，悉同受之，"},{"note":"gù chēng wú jiān","text":"故称无间。"},{"note":"wǔ zhě, ruò duò cǐ yù, cóng chū rù shí, zhì bǎi qiān jié","text":"五者，若堕此狱，从初入时，至百千劫，"},{"note":"yī rì yī yè, wàn sǐ wàn shēng","text":"一日一夜，万死万生。"},{"note":"qiú yī niàn jiān, zàn zhù bù dé","text":"求一念间，暂住不得。"},{"note":"chú fēi yè jǐn, fāng dé shòu shēng","text":"除非业尽，方得受生。"},{"note":"yǐ cǐ lián mián, gù chēng wú jiān","text":"以此连绵，故称无间。”"},{"note":"dì zàng pú sà bái shèng mǔ yán","text":"地藏菩萨白圣母言："},{"note":"wú jiān dì yù, cū shuō rú shì","text":"“无间地狱，粗说如是。"},{"note":"ruò guǎng shuō dì yù zuì qì děng míng, jí zhū kǔ shì, yī jié zhī zhōng","text":"若广说地狱罪器等名，及诸苦事，一劫之中，"},{"note":"qiú shuō bù jǐn","text":"求说不尽。”"},{"note":"mó yé fū rén wén yǐ, chóu yōu hé zhǎng, dǐng lǐ ér tuì","text":"摩耶夫人闻已，愁忧合掌，顶礼而退。"}],"ksitigarbha-04":[{"note":"yán fú zhòng shēng yè gǎn pǐn dì sì","text":"阎浮众生业感品第四"},{"note":"ěr shí, dì zàng pú sà mó hē sà bái fó yán","text":"尔时，地藏菩萨摩诃萨白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ chéng fó rú lái wēi shén lì gù, biàn bǎi qiān wàn yì shì jiè","text":"我承佛如来威神力故，遍百千万亿世界，"},{"note":"fēn shì shēn xíng, jiù bá yī qiè yè bào zhòng shēng","text":"分是身形，救拔一切业报众生。"},{"note":"ruò fēi rú lái dà cí lì gù, jí bù néng zuò rú shì biàn huà","text":"若非如来大慈力故，即不能作如是变化。"},{"note":"wǒ jīn yòu méng fó fù zhǔ, zhì ā yì duō chéng fó yǐ lái, liù dào zhòng shēng","text":"我今又蒙佛付嘱，至阿逸多成佛已来，六道众生，"},{"note":"qiǎn lìng dù tuō","text":"遣令度脱。"},{"note":"wéi rán, shì zūn, yuàn bù yǒu lǜ","text":"唯然，世尊，愿不有虑。”"},{"note":"ěr shí, fó gào dì zàng pú sà","text":"尔时，佛告地藏菩萨："},{"note":"yī qiè zhòng shēng, wèi jiě tuō zhě, xìng shí wú dìng","text":"“一切众生，未解脱者，性识无定。"},{"note":"è xí jié yè, shàn xí jié guǒ, wèi shàn wèi è, zhú jìng ér shēng","text":"恶习结业，善习结果，为善为恶，逐境而生。"},{"note":"lún zhuǎn wǔ dào, zàn wú xiū xī, dòng jīng chén jié, mí huò zhàng nán","text":"轮转五道，暂无休息，动经尘劫，迷惑障难。"},{"note":"rú yú yóu wǎng, jiāng shì zhǎng liú, tuō rù zàn chū, yòu fù zāo wǎng","text":"如鱼游网，将是长流，脱入暂出，又复遭网。"},{"note":"yǐ shì děng bèi, wú dāng yōu niàn","text":"以是等辈，吾当忧念。"},{"note":"rǔ jì bì shì wǎng yuàn, lèi jié zhòng shì, guǎng dù zuì bèi, wú fù hé lǜ","text":"汝既毕是往愿，累劫重誓，广度罪辈，吾复何虑？”"},{"note":"shuō shì yǔ shí, huì zhōng yǒu yī pú sà mó hē sà, míng dìng zì zài wáng","text":"说是语时，会中有一菩萨摩诃萨，名定自在王，"},{"note":"bái fó yán","text":"白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"dì zàng pú sà lèi jié yǐ lái, gè fā hé yuàn","text":"地藏菩萨累劫已来，各发何愿？"},{"note":"jīn méng shì zūn, yīn qín zàn tàn","text":"今蒙世尊，殷勤赞叹。"},{"note":"wéi yuàn shì zūn, lüè ér shuō zhī","text":"唯愿世尊，略而说之。”"},{"note":"ěr shí, shì zūn gào dìng zì zài wáng pú sà","text":"尔时，世尊告定自在王菩萨："},{"note":"dì tīng","text":"“谛听！"},{"note":"dì tīng","text":"谛听！"},{"note":"shàn sī niàn zhī, wú dāng wèi rǔ, fēn bié jiě shuō","text":"善思念之，吾当为汝，分别解说。"},{"note":"nǎi wǎng guò qù, wú liàng ā sēng qí nà yóu tā bù kě shuō jié","text":"乃往过去，无量阿僧祇那由他不可说劫，"},{"note":"ěr shí yǒu fó, hào yī qiè zhì chéng jiù rú lái, yīng gōng, zhèng biàn zhī","text":"尔时有佛，号一切智成就如来、应供、正遍知、"},{"note":"míng xíng zú, shàn shì, shì jiān jiě, wú shàng shì, diào yù zhàng fū","text":"明行足、善逝、世间解、无上士、调御丈夫、"},{"note":"tiān rén shī, fó, shì zūn, qí fó shòu mìng liù wàn jié","text":"天人师、佛、世尊，其佛寿命六万劫。"},{"note":"wèi chū jiā shí, wèi xiǎo guó wáng, yǔ yī lín guó wáng wèi yǒu","text":"未出家时，为小国王，与一邻国王为友，"},{"note":"tóng xíng shí shàn, ráo yì zhòng shēng","text":"同行十善，饶益众生。"},{"note":"qí lín guó nèi, suǒ yǒu rén mín, duō zào zhòng è","text":"其邻国内，所有人民，多造众恶。"},{"note":"èr wáng yì jì, guǎng shè fāng biàn","text":"二王议计，广设方便。"},{"note":"yī wáng fā yuàn, zǎo chéng fó dào, dāng dù shì bèi, lìng shǐ wú yú","text":"一王发愿，早成佛道，当度是辈，令使无馀。"},{"note":"yī wáng fā yuàn, ruò bù xiān dù zuì kǔ, lìng shì ān lè, dé zhì pú tí","text":"一王发愿，若不先度罪苦，令是安乐，得至菩提，"},{"note":"wǒ zhōng wèi yuàn chéng fó","text":"我终未愿成佛。”"},{"note":"fó gào dìng zì zài wáng pú sà","text":"佛告定自在王菩萨："},{"note":"yī wáng fā yuàn zǎo chéng fó zhě, jí yī qiè zhì chéng jiù rú lái shì","text":"“一王发愿早成佛者，即一切智成就如来是。"},{"note":"yī wáng fā yuàn yǒng dù zuì kǔ zhòng shēng, wèi yuàn chéng fó zhě, jí dì zàng pú sà shì","text":"一王发愿永度罪苦众生，未愿成佛者，即地藏菩萨是。"},{"note":"fù yú guò qù wú liàng ā sēng qí jié, yǒu fó chū shì, míng qīng jìng lián huá mù rú lái","text":"复于过去无量阿僧祇劫，有佛出世，名清净莲华目如来，"},{"note":"qí fó shòu mìng sì shí jié","text":"其佛寿命四十劫。"},{"note":"xiàng fǎ zhī zhōng, yǒu yī luó hàn, fú dù zhòng shēng","text":"像法之中，有一罗汉，福度众生。"},{"note":"yīn cì jiào huà, yù yī nǚ rén, zì yuē guāng mù, shè shí gòng yǎng","text":"因次教化，遇一女人，字曰光目，设食供养。"},{"note":"luó hàn wèn zhī","text":"罗汉问之："},{"note":"yù yuàn hé děng. guāng mù dá yán","text":"‘欲愿何等？’光目答言："},{"note":"wǒ yǐ mǔ wáng zhī rì, zī fú jiù bá, wèi zhī wǒ mǔ shēng chù hé qù. luó hàn mǐn zhī","text":"‘我以母亡之日，资福救拔，未知我母生处何趣？’罗汉愍之，"},{"note":"wèi rù dìng guān, jiàn guāng mù nǚ mǔ duò zài è qù, shòu jí dà kǔ","text":"为入定观，见光目女母堕在恶趣，受极大苦。"},{"note":"luó hàn wèn guāng mù yán","text":"罗汉问光目言："},{"note":"rǔ mǔ zài shēng, zuò hé xíng yè","text":"‘汝母在生，作何行业？"},{"note":"jīn zài è qù, shòu jí dà kǔ. guāng mù dá yán","text":"今在恶趣，受极大苦。’光目答言："},{"note":"wǒ mǔ suǒ xí, wéi hǎo shí dàn yú biē zhī shǔ","text":"‘我母所习，唯好食啖鱼鳖之属。"},{"note":"suǒ shí yú biē duō shí qí zi, huò chǎo huò zhǔ, zì qíng shí dàn","text":"所食鱼鳖多食其子，或炒或煮，恣情食啖。"},{"note":"jì qí mìng shù, qiān wàn fù bèi","text":"计其命数，千万复倍。"},{"note":"zūn zhě cí mǐn, rú hé āi jiù. luó hàn mǐn zhī, wèi zuò fāng biàn","text":"尊者慈愍，如何哀救？’罗汉愍之，为作方便，"},{"note":"quàn guāng mù yán","text":"劝光目言："},{"note":"rǔ kě zhì chéng niàn qīng jìng lián huá mù rú lái, jiān sù huà xíng xiàng","text":"‘汝可志诚念清净莲华目如来，兼塑画形像，"},{"note":"cún wáng huò bào","text":"存亡获报。’”"},{"note":"guāng mù wén yǐ, jí shě suǒ ài, xún huà fó xiàng, ér gòng yǎng zhī","text":"“光目闻已，即舍所爱，寻画佛像，而供养之。"},{"note":"fù gōng jìng xīn, bēi qì zhān lǐ","text":"复恭敬心，悲泣瞻礼。"},{"note":"hū yú yè hòu, mèng jiàn fó shēn, jīn sè huǎng yào, rú xū mí shān","text":"忽于夜后，梦见佛身，金色晃耀，如须弥山，"},{"note":"fàng dà guāng míng, ér gào guāng mù","text":"放大光明，而告光目："},{"note":"rǔ mǔ bù jiǔ, dāng shēng rǔ jiā, cái jué jī hán, jí dāng yán shuō","text":"‘汝母不久，当生汝家，才觉饥寒，即当言说。’”"},{"note":"qí hòu jiā nèi, bì shēng yī zi, wèi mǎn sān rì, ér nǎi yán shuō","text":"“其后家内，婢生一子，未满三日，而乃言说，"},{"note":"jī shǒu bēi qì, gào yú guāng mù","text":"稽首悲泣，告于光目："},{"note":"shēng sǐ yè yuán, guǒ bào zì shòu","text":"‘生死业缘，果报自受。"},{"note":"wú shì rǔ mǔ, jiǔ chù àn míng, zì bié rǔ lái, lèi duò dà dì yù","text":"吾是汝母，久处暗冥，自别汝来，累堕大地狱。"},{"note":"méng rǔ fú lì, fāng dé shòu shēng","text":"蒙汝福力，方得受生。"},{"note":"wèi xià jiàn rén, yòu fù duǎn mìng, shòu nián shí sān, gèng luò è dào","text":"为下贱人，又复短命，寿年十三，更落恶道。"},{"note":"rǔ yǒu hé jì, lìng wú tuō miǎn. guāng mù wén shuō, zhī mǔ wú yí","text":"汝有何计，令吾脱免？’光目闻说，知母无疑，"},{"note":"gěng yàn bēi tí, ér bái bì zi","text":"哽咽悲啼，而白婢子："},{"note":"jì shì wǒ mǔ, hé zhī běn zuì, zuò hé xíng yè, duò yú è dào. bì zi dá yán","text":"‘既是我母，合知本罪，作何行业，堕于恶道？’婢子答言："},{"note":"yǐ shā hài huǐ mà èr yè shòu bào","text":"‘以杀害毁骂二业受报。"},{"note":"ruò fēi méng fú, jiù bá wú nán, yǐ shì yè gù, wèi hé jiě tuō. guāng mù wèn yán","text":"若非蒙福，救拔吾难，以是业故，未合解脱。’光目问言："},{"note":"dì yù zuì bào, qí shì yún hé. bì zi dá yán","text":"‘地狱罪报，其事云何？’婢子答言："},{"note":"zuì kǔ zhī shì, bù rěn chēng shuō, bǎi qiān suì zhōng, zú bái nán jìng","text":"‘罪苦之事，不忍称说，百千岁中，卒白难竟。’”"},{"note":"guāng mù wén yǐ, tí lèi hào qì, ér bái kōng jiè","text":"“光目闻已，啼泪号泣，而白空界："},{"note":"yuàn wǒ zhī mǔ, yǒng tuō dì yù","text":"‘愿我之母，永脱地狱。"},{"note":"bì shí sān suì, gèng wú zhòng zuì, jí lì è dào","text":"毕十三岁，更无重罪，及历恶道。"},{"note":"shí fāng zhū fó, cí āi mǐn wǒ, tīng wǒ wèi mǔ suǒ fā guǎng dà shì yuàn","text":"十方诸佛，慈哀愍我，听我为母所发广大誓愿："},{"note":"ruò dé wǒ mǔ yǒng lí sān tú, jí sī xià jiàn, nǎi zhì nǚ rén zhī shēn","text":"若得我母永离三涂，及斯下贱，乃至女人之身，"},{"note":"yǒng jié bù shòu zhě, yuàn wǒ zì jīn rì hòu, duì qīng jìng lián huá mù rú lái xiàng qián","text":"永劫不受者，愿我自今日后，对清净莲华目如来像前，"},{"note":"què hòu bǎi qiān wàn yì jié zhōng, yīng yǒu shì jiè, suǒ yǒu dì yù","text":"却后百千万亿劫中，应有世界，所有地狱，"},{"note":"jí sān è dào zhū zuì kǔ zhòng shēng, shì yuàn jiù bá, lìng lí dì yù è qù","text":"及三恶道诸罪苦众生，誓愿救拔，令离地狱恶趣、"},{"note":"chù shēng, è guǐ děng","text":"畜生、饿鬼等。"},{"note":"rú shì zuì bào děng rén, jǐn chéng fó jìng, wǒ rán hòu fāng chéng zhèng jué","text":"如是罪报等人，尽成佛竟，我然后方成正觉。’”"},{"note":"fā shì yuàn yǐ, jù wén qīng jìng lián huá mù rú lái ér gào zhī yuē","text":"“发誓愿已，具闻清净莲华目如来而告之曰："},{"note":"guāng mù","text":"‘光目！"},{"note":"rǔ dà cí mǐn, shàn néng wèi mǔ fā rú shì dà yuàn","text":"汝大慈愍，善能为母发如是大愿。"},{"note":"wú guān rǔ mǔ, shí sān suì bì, shě cǐ bào yǐ, shēng wèi fàn zhì","text":"吾观汝母，十三岁毕，舍此报已，生为梵志，"},{"note":"shòu nián bǎi suì","text":"寿年百岁。"},{"note":"guò shì bào hòu, dāng shēng wú yōu guó tǔ, shòu mìng bù kě jì jié","text":"过是报后，当生无忧国土，寿命不可计劫。"},{"note":"hòu chéng fó guǒ, guǎng dù rén tiān, shù rú héng hé shā","text":"后成佛果，广度人天，数如恒河沙。’”"},{"note":"fó gào dìng zì zài wáng","text":"佛告定自在王："},{"note":"ěr shí luó hàn fú dù guāng mù zhě, jí wú jǐn yì pú sà shì","text":"“尔时罗汉福度光目者，即无尽意菩萨是。"},{"note":"guāng mù mǔ zhě, jí jiě tuō pú sà shì","text":"光目母者，即解脱菩萨是。"},{"note":"guāng mù nǚ zhě, jí dì zàng pú sà shì","text":"光目女者，即地藏菩萨是。"},{"note":"guò qù jiǔ yuǎn jié zhōng, rú shì cí mǐn fā héng hé shā yuàn, guǎng dù zhòng shēng","text":"过去久远劫中，如是慈愍发恒河沙愿，广度众生。”"},{"note":"wèi lái shì zhōng, ruò yǒu nán zi nǚ rén, bù xíng shàn zhě","text":"“未来世中，若有男子女人，不行善者，"},{"note":"xíng è zhě, nǎi zhì bù xìn yīn guǒ zhě, xié yín wàng yǔ zhě","text":"行恶者，乃至不信因果者，邪淫妄语者，"},{"note":"liǎng shé è kǒu zhě, huǐ bàng dà chéng zhě, rú shì zhū yè zhòng shēng","text":"两舌恶口者，毁谤大乘者，如是诸业众生，"},{"note":"bì duò è qù","text":"必堕恶趣。"},{"note":"ruò yù shàn zhī shí, quàn lìng yī dàn zhǐ jiān guī yī dì zàng pú sà","text":"若遇善知识，劝令一弹指间归依地藏菩萨，"},{"note":"shì zhū zhòng shēng, jí dé jiě tuō sān è dào bào","text":"是诸众生，即得解脱三恶道报。"},{"note":"ruò néng zhì xīn guī jìng, jí zhān lǐ zàn tàn, xiāng huá yī fú","text":"若能志心归敬，及瞻礼赞叹，香华衣服，"},{"note":"zhǒng zhǒng zhēn bǎo, huò fù yǐn shí, rú shì fèng shì zhě, wèi lái bǎi qiān wàn yì jié zhōng","text":"种种珍宝，或复饮食，如是奉事者，未来百千万亿劫中，"},{"note":"cháng zài zhū tiān shòu shèng miào lè","text":"常在诸天受胜妙乐。"},{"note":"ruò tiān fú jǐn, xià shēng rén jiān, yóu bǎi qiān jié, cháng wèi dì wáng","text":"若天福尽，下生人间，犹百千劫，常为帝王，"},{"note":"néng yì sù mìng yīn guǒ běn mò","text":"能忆宿命因果本末。"},{"note":"dìng zì zài wáng, rú shì dì zàng pú sà, yǒu rú cǐ bù kě sī yì dà wēi shén lì","text":"定自在王，如是地藏菩萨，有如此不可思议大威神力，"},{"note":"guǎng lì zhòng shēng, rǔ děng zhū pú sà, dāng jì shì jīng, guǎng xuān liú bù","text":"广利众生，汝等诸菩萨，当记是经，广宣流布。”"},{"note":"dìng zì zài wáng bái fó yán","text":"定自在王白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"yuàn bù yǒu lǜ","text":"愿不有虑。"},{"note":"wǒ děng qiān wàn yì pú sà mó hē sà, bì néng chéng fó wēi shén","text":"我等千万亿菩萨摩诃萨，必能承佛威神，"},{"note":"guǎng yǎn shì jīng yú yán fú tí, lì yì zhòng shēng","text":"广演是经于阎浮提，利益众生。”"},{"note":"dìng zì zài wáng pú sà bái shì zūn yǐ, hé zhǎng gōng jìng, zuò lǐ ér tuì","text":"定自在王菩萨白世尊已，合掌恭敬，作礼而退。"},{"note":"ěr shí, sì fāng tiān wáng, jù cóng zuò qǐ, hé zhǎng gōng jìng","text":"尔时，四方天王，俱从座起，合掌恭敬，"},{"note":"bái fó yán","text":"白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"dì zàng pú sà yú jiǔ yuǎn jié lái, fā rú shì dà yuàn, yún hé zhì jīn","text":"地藏菩萨于久远劫来，发如是大愿，云何至今，"},{"note":"yóu dù wèi jué, gèng fā guǎng dà shì yán","text":"犹度未绝，更发广大誓言？"},{"note":"wéi yuàn shì zūn, wèi wǒ děng shuō","text":"唯愿世尊，为我等说。”"},{"note":"fó gào sì tiān wáng","text":"佛告四天王："},{"note":"shàn zāi","text":"“善哉！"},{"note":"shàn zāi","text":"善哉！"},{"note":"wú jīn wèi rǔ, jí wèi lái xiàn zài tiān rén zhòng děng, guǎng lì yì gù","text":"吾今为汝，及未来现在天人众等，广利益故，"},{"note":"shuō dì zàng pú sà yú suō pó shì jiè, yán fú tí nèi, shēng sǐ dào zhōng","text":"说地藏菩萨于娑婆世界，阎浮提内，生死道中，"},{"note":"cí āi jiù bá, dù tuō yī qiè zuì kǔ zhòng shēng fāng biàn zhī shì","text":"慈哀救拔，度脱一切罪苦众生方便之事。”"},{"note":"sì tiān wáng yán","text":"四天王言："},{"note":"wéi rán, shì zūn","text":"“唯然，世尊！"},{"note":"yuàn lè yù wén","text":"愿乐欲闻。”"},{"note":"fó gào sì tiān wáng","text":"佛告四天王："},{"note":"dì zàng pú sà jiǔ yuǎn jié lái, qì zhì yú jīn, dù tuō zhòng shēng","text":"“地藏菩萨久远劫来，迄至于今，度脱众生，"},{"note":"yóu wèi bì yuàn","text":"犹未毕愿。"},{"note":"cí mǐn cǐ shì zuì kǔ zhòng shēng, fù guān wèi lái wú liàng jié zhōng","text":"慈愍此世罪苦众生，复观未来无量劫中，"},{"note":"yīn màn bù duàn, yǐ shì zhī gù, yòu fā zhòng yuàn","text":"因蔓不断，以是之故，又发重愿。"},{"note":"rú shì pú sà, yú suō pó shì jiè, yán fú tí zhōng, bǎi qiān wàn yì fāng biàn","text":"如是菩萨，于娑婆世界，阎浮提中，百千万亿方便，"},{"note":"ér wèi jiào huà","text":"而为教化。”"},{"note":"sì tiān wáng","text":"“四天王！"},{"note":"dì zàng pú sà ruò yù shā shēng zhě, shuō sù yāng duǎn mìng bào","text":"地藏菩萨若遇杀生者，说宿殃短命报。"},{"note":"ruò yù qiè dào zhě, shuō pín qióng kǔ chǔ bào","text":"若遇窃盗者，说贫穷苦楚报。"},{"note":"ruò yù xié yín zhě, shuō què gē yuān yāng bào","text":"若遇邪淫者，说雀鸽鸳鸯报。"},{"note":"ruò yù è kǒu zhě, shuō juàn shǔ dòu zhèng bào","text":"若遇恶口者，说眷属斗诤报。"},{"note":"ruò yù huǐ bàng zhě, shuō wú shé chuāng kǒu bào","text":"若遇毁谤者，说无舌疮口报。"},{"note":"ruò yù chēn huì zhě, shuō chǒu lòu lóng cán bào","text":"若遇瞋恚者，说丑陋癃残报。"},{"note":"ruò yù qiān lìn zhě, shuō suǒ qiú wéi yuàn bào","text":"若遇悭悋者，说所求违愿报。"},{"note":"ruò yù yǐn shí wú dù zhě, shuō jī kě yàn bìng bào","text":"若遇饮食无度者，说饥渴咽病报。"},{"note":"ruò yù tián liè zì qíng zhě, shuō jīng kuáng sàng mìng bào","text":"若遇畋猎恣情者，说惊狂丧命报。"},{"note":"ruò yù bèi nì fù mǔ zhě, shuō tiān dì zāi shā bào","text":"若遇悖逆父母者，说天地灾杀报。"},{"note":"ruò yù shāo shān lín mù zhě, shuō kuáng mí qǔ sǐ bào","text":"若遇烧山林木者，说狂迷取死报。"},{"note":"ruò yù qián hòu fù mǔ è dú zhě, shuō fǎn shēng biān tà xiàn shòu bào","text":"若遇前后父母恶毒者，说返生鞭挞现受报。"},{"note":"ruò yù wǎng bǔ shēng chú zhě, shuō gǔ ròu fēn lí bào","text":"若遇网捕生雏者，说骨肉分离报。"},{"note":"ruò yù huǐ bàng sān bǎo zhě, shuō máng lóng yīn yǎ bào","text":"若遇毁谤三宝者，说盲聋喑痖报。"},{"note":"ruò yù qīng fǎ màn jiào zhě, shuō yǒng chù è dào bào","text":"若遇轻法慢教者，说永处恶道报。"},{"note":"ruò yù pò yòng cháng zhù zhě, shuō yì jié lún huí dì yù bào","text":"若遇破用常住者，说亿劫轮回地狱报。"},{"note":"ruò yù wū fàn wū sēng zhě, shuō yǒng zài chù shēng bào","text":"若遇污梵诬僧者，说永在畜生报。"},{"note":"ruò yù tāng huǒ zhǎn zhuó shāng shēng zhě, shuō lún huí dì cháng bào","text":"若遇汤火斩斫伤生者，说轮回递偿报。"},{"note":"ruò yù pò jiè fàn zhāi zhě, shuō qín shòu jī è bào","text":"若遇破戒犯斋者，说禽兽饥饿报。"},{"note":"ruò yù fēi lǐ huǐ yòng zhě, shuō suǒ qiú quē jué bào","text":"若遇非理毁用者，说所求阙绝报。"},{"note":"ruò yù wú wǒ gòng gāo zhě, shuō bēi shǐ xià jiàn bào","text":"若遇吾我贡高者，说卑使下贱报。"},{"note":"ruò yù liǎng shé dòu luàn zhě, shuō wú shé bǎi shé bào","text":"若遇两舌斗乱者，说无舌百舌报。"},{"note":"ruò yù xié jiàn zhě, shuō biān dì shòu shēng bào","text":"若遇邪见者，说边地受生报。”"},{"note":"rú shì děng yán fú tí zhòng shēng, shēn kǒu yì yè, è xí jié guǒ","text":"“如是等阎浮提众生，身口意业，恶习结果，"},{"note":"bǎi qiān bào yīng, jīn cū lüè shuō","text":"百千报应，今粗略说。"},{"note":"rú shì děng yán fú tí zhòng shēng, yè gǎn chà bié, dì zàng pú sà bǎi qiān fāng biàn","text":"如是等阎浮提众生，业感差别，地藏菩萨百千方便，"},{"note":"ér jiào huà zhī","text":"而教化之。"},{"note":"shì zhū zhòng shēng, xiān shòu rú shì děng bào, hòu duò dì yù, dòng jīng jié shù","text":"是诸众生，先受如是等报，后堕地狱，动经劫数，"},{"note":"wú yǒu chū qī","text":"无有出期。"},{"note":"shì gù rǔ děng, hù rén hù guó, wú lìng shì zhū zhòng yè, mí huò zhòng shēng","text":"是故汝等，护人护国，无令是诸众业，迷惑众生。”"},{"note":"sì tiān wáng wén yǐ, tì lèi bēi tàn, hé zhǎng ér tuì","text":"四天王闻已，涕泪悲叹，合掌而退。"},{"note":"dì zàng pú sà běn yuàn jīng juǎn shàng","text":"地藏菩萨本愿经卷上"},{"note":"zàn","text":"赞"},{"note":"rú lái cí mǐn, zhuǎn dà fǎ lún, pó luó mén nǚ jiù cí qīn","text":"如来慈愍，转大法轮，婆罗门女救慈亲，"},{"note":"jué huá dù mí jīn, mó yé fū rén, qǐng wèn dì zàng yīn","text":"觉华度迷津，摩耶夫人，请问地藏因。"},{"note":"nā mó cháng zhù shí fāng fó sān chēng","text":"南无常住十方佛（三称）"}],"ksitigarbha-05":[{"note":"dì yù míng hào pǐn dì wǔ","text":"地狱名号品第五"},{"note":"ěr shí, pǔ xián pú sà mó hē sà bái dì zàng pú sà yán","text":"尔时，普贤菩萨摩诃萨白地藏菩萨言："},{"note":"rén zhě","text":"“仁者！"},{"note":"yuàn wèi tiān lóng sì zhòng, jí wèi lái xiàn zài yī qiè zhòng shēng, shuō suō pó shì jiè jí yán fú tí zuì kǔ zhòng shēng","text":"愿为天龙四众，及未来现在一切众生，说娑婆世界及阎浮提罪苦众生，"},{"note":"suǒ shòu bào chù, dì yù míng hào jí è bào děng shì, shǐ wèi lái shì mò fǎ zhòng shēng","text":"所受报处、地狱名号及恶报等事，使未来世末法众生，"},{"note":"zhī shì guǒ bào","text":"知是果报。”"},{"note":"dì zàng dá yán","text":"地藏答言："},{"note":"rén zhě","text":"“仁者！"},{"note":"wǒ jīn chéng fó wēi shén, jí dà shì zhī lì, lüè shuō dì yù míng hào","text":"我今承佛威神，及大士之力，略说地狱名号，"},{"note":"jí zuì bào è bào zhī shì","text":"及罪报恶报之事。"},{"note":"rén zhě, yán fú tí dōng fāng yǒu shān, hào yuē tiě wéi, qí shān hēi suì","text":"仁者，阎浮提东方有山，号曰铁围，其山黑邃，"},{"note":"wú rì yuè guāng","text":"无日月光。"},{"note":"yǒu dà dì yù, hào jí wú jiān","text":"有大地狱，号极无间。"},{"note":"yòu yǒu dì yù, míng dà ā bí","text":"又有地狱，名大阿鼻。"},{"note":"fù yǒu dì yù, míng yuē sì jiǎo","text":"复有地狱，名曰四角。"},{"note":"fù yǒu dì yù, míng yuē fēi dāo","text":"复有地狱，名曰飞刀。"},{"note":"fù yǒu dì yù, míng yuē huǒ jiàn","text":"复有地狱，名曰火箭。"},{"note":"fù yǒu dì yù, míng yuē jiā shān","text":"复有地狱，名曰夹山。"},{"note":"fù yǒu dì yù, míng yuē tōng qiāng","text":"复有地狱，名曰通枪。"},{"note":"fù yǒu dì yù, míng yuē tiě chē","text":"复有地狱，名曰铁车。"},{"note":"fù yǒu dì yù, míng yuē tiě chuáng","text":"复有地狱，名曰铁床。"},{"note":"fù yǒu dì yù, míng yuē tiě niú","text":"复有地狱，名曰铁牛。"},{"note":"fù yǒu dì yù, míng yuē tiě yī","text":"复有地狱，名曰铁衣。"},{"note":"fù yǒu dì yù, míng yuē qiān rèn","text":"复有地狱，名曰千刃。"},{"note":"fù yǒu dì yù, míng yuē tiě lǘ","text":"复有地狱，名曰铁驴。"},{"note":"fù yǒu dì yù, míng yuē yáng tóng","text":"复有地狱，名曰烊铜。"},{"note":"fù yǒu dì yù, míng yuē bào zhù","text":"复有地狱，名曰抱柱。"},{"note":"fù yǒu dì yù, míng yuē liú huǒ","text":"复有地狱，名曰流火。"},{"note":"fù yǒu dì yù, míng yuē gēng shé","text":"复有地狱，名曰耕舌。"},{"note":"fù yǒu dì yù, míng wèi cuò shǒu","text":"复有地狱，名为锉首。"},{"note":"fù yǒu dì yù, míng yuē shāo jiǎo","text":"复有地狱，名曰烧脚。"},{"note":"fù yǒu dì yù, míng yuē dàn yǎn","text":"复有地狱，名曰啖眼。"},{"note":"fù yǒu dì yù, míng yuē tiě wán","text":"复有地狱，名曰铁丸。"},{"note":"fù yǒu dì yù, míng yuē zhèng lùn","text":"复有地狱，名曰诤论。"},{"note":"fù yǒu dì yù, míng yuē tiě","text":"复有地狱，名曰铁𫓧。"},{"note":"fù yǒu dì yù, míng yuē duō chēn","text":"复有地狱，名曰多瞋。”"},{"note":"dì zàng bái yán","text":"地藏白言："},{"note":"rén zhě","text":"“仁者！"},{"note":"tiě wéi zhī nèi, yǒu rú shì děng dì yù, qí shù wú xiàn","text":"铁围之内，有如是等地狱，其数无限。"},{"note":"gèng yǒu jiào huàn dì yù, bá shé dì yù, fèn niào dì yù, tóng suǒ dì yù","text":"更有叫唤地狱、拔舌地狱、粪尿地狱、铜锁地狱、"},{"note":"huǒ xiàng dì yù, huǒ gǒu dì yù, huǒ mǎ dì yù, huǒ niú dì yù","text":"火象地狱、火狗地狱、火马地狱、火牛地狱、"},{"note":"huǒ shān dì yù, huǒ shí dì yù, huǒ chuáng dì yù, huǒ liáng dì yù","text":"火山地狱、火石地狱、火床地狱、火梁地狱、"},{"note":"huǒ yīng dì yù, jù yá dì yù, bō pí dì yù, yǐn xuè dì yù","text":"火鹰地狱、锯牙地狱、剥皮地狱、饮血地狱、"},{"note":"shāo shǒu dì yù, shāo jiǎo dì yù, dào cì dì yù, huǒ wū dì yù","text":"烧手地狱、烧脚地狱、倒刺地狱、火屋地狱、"},{"note":"tiě wū dì yù, huǒ láng dì yù","text":"铁屋地狱、火狼地狱。"},{"note":"rú shì děng dì yù, qí zhōng gè gè fù yǒu zhū xiǎo dì yù, huò yī huò èr","text":"如是等地狱，其中各各复有诸小地狱，或一或二，"},{"note":"huò sān huò sì, nǎi zhì bǎi qiān","text":"或三或四，乃至百千。"},{"note":"qí zhōng míng hào, gè gè bù tóng","text":"其中名号，各各不同。”"},{"note":"dì zàng pú sà gào pǔ xián pú sà yán","text":"地藏菩萨告普贤菩萨言："},{"note":"rén zhě","text":"“仁者！"},{"note":"cǐ zhě jiē shì nán yán fú tí xíng è zhòng shēng, yè gǎn rú shì","text":"此者皆是南阎浮提行恶众生，业感如是。"},{"note":"yè lì shèn dà, néng dí xū mí, néng shēn jù hǎi, néng zhàng shèng dào","text":"业力甚大，能敌须弥，能深巨海，能障圣道。"},{"note":"shì gù zhòng shēng mò qīng xiǎo è, yǐ wèi wú zuì, sǐ hòu yǒu bào","text":"是故众生莫轻小恶，以为无罪，死后有报，"},{"note":"xiān háo shòu zhī","text":"纤毫受之。"},{"note":"fù zi zhì qīn, qí lù gè bié, zòng rán xiāng féng, wú kěn dài shòu","text":"父子至亲，岐路各别，纵然相逢，无肯代受。"},{"note":"wǒ jīn chéng fó wēi lì, lüè shuō dì yù zuì bào zhī shì","text":"我今承佛威力，略说地狱罪报之事。"},{"note":"wéi yuàn rén zhě, zàn tīng shì yán","text":"唯愿仁者，暂听是言。”"},{"note":"pǔ xián dá yán","text":"普贤答言："},{"note":"wú yǐ jiǔ zhī sān è dào bào, wàng rén zhě shuō, lìng hòu shì mò fǎ yī qiè è xíng zhòng shēng","text":"“吾已久知三恶道报，望仁者说，令后世末法一切恶行众生，"},{"note":"wén rén zhě shuō, shǐ lìng guī fó","text":"闻仁者说，使令归佛。”"},{"note":"dì zàng bái yán","text":"地藏白言："},{"note":"rén zhě","text":"“仁者！"},{"note":"dì yù zuì bào, qí shì rú shì","text":"地狱罪报，其事如是："},{"note":"huò yǒu dì yù, qǔ zuì rén shé, shǐ niú gēng zhī","text":"或有地狱，取罪人舌，使牛耕之。"},{"note":"huò yǒu dì yù, qǔ zuì rén xīn, yè chā shí zhī","text":"或有地狱，取罪人心，夜叉食之。"},{"note":"huò yǒu dì yù, huò tāng shèng fèi, zhǔ zuì rén shēn","text":"或有地狱，镬汤盛沸，煮罪人身。"},{"note":"huò yǒu dì yù, chì shāo tóng zhù, shǐ zuì rén bào","text":"或有地狱，赤烧铜柱，使罪人抱。"},{"note":"huò yǒu dì yù, shǐ zhū huǒ shāo, chèn jí zuì rén","text":"或有地狱，使诸火烧，趁及罪人。"},{"note":"huò yǒu dì yù, yī xiàng hán bīng","text":"或有地狱，一向寒冰。"},{"note":"huò yǒu dì yù, wú xiàn fèn niào","text":"或有地狱，无限粪尿。"},{"note":"huò yǒu dì yù, chún fēi sà lí","text":"或有地狱，纯飞钑鑗。"},{"note":"huò yǒu dì yù, duō zǎn huǒ qiāng","text":"或有地狱，多攒火枪。"},{"note":"huò yǒu dì yù, wéi zhuàng xiōng bèi","text":"或有地狱，唯撞胸背。"},{"note":"huò yǒu dì yù, dàn shāo shǒu zú","text":"或有地狱，但烧手足。"},{"note":"huò yǒu dì yù, pán jiǎo tiě shé","text":"或有地狱，盘绞铁蛇。"},{"note":"huò yǒu dì yù, qū zhú tiě gǒu","text":"或有地狱，驱逐铁狗。"},{"note":"huò yǒu dì yù, jǐn jià tiě luó","text":"或有地狱，尽驾铁骡。"},{"note":"rén zhě, rú shì děng bào, gè gè yù zhōng, yǒu bǎi qiān zhǒng yè dào zhī qì","text":"仁者，如是等报，各各狱中，有百千种业道之器，"},{"note":"wú fēi shì tóng, shì tiě, shì shí, shì huǒ","text":"无非是铜，是铁，是石，是火。"},{"note":"cǐ sì zhǒng wù, zhòng yè xíng gǎn","text":"此四种物，众业行感。"},{"note":"ruò guǎng shuō dì yù zuì bào děng shì, yī yī yù zhōng, gèng yǒu bǎi qiān zhǒng kǔ chǔ","text":"若广说地狱罪报等事，一一狱中，更有百千种苦楚，"},{"note":"hé kuàng duō yù","text":"何况多狱。"},{"note":"wǒ jīn chéng fó wēi shén, jí rén zhě wèn, lüè shuō rú shì","text":"我今承佛威神，及仁者问，略说如是。"},{"note":"ruò guǎng jiě shuō, qióng jié bù jǐn","text":"若广解说，穷劫不尽。”"}],"ksitigarbha-06":[{"note":"rú lái zàn tàn pǐn dì liù","text":"如来赞叹品第六"},{"note":"ěr shí, shì zūn jǔ shēn fàng dà guāng míng, biàn zhào bǎi qiān wàn yì héng hé shā děng zhū fó shì jiè","text":"尔时，世尊举身放大光明，遍照百千万亿恒河沙等诸佛世界，"},{"note":"chū dà yīn shēng, pǔ gào zhū fó shì jiè yī qiè zhū pú sà mó hē sà","text":"出大音声，普告诸佛世界一切诸菩萨摩诃萨，"},{"note":"jí tiān lóng guǐ shén, rén, fēi rén děng","text":"及天龙鬼神、人、非人等："},{"note":"tīng wú jīn rì chēng yáng zàn tàn dì zàng pú sà mó hē sà, yú shí fāng shì jiè","text":"“听吾今日称扬赞叹地藏菩萨摩诃萨，于十方世界，"},{"note":"xiàn dà bù kě sī yì wēi shén cí bēi zhī lì, jiù hù yī qiè zuì kǔ zhī shì","text":"现大不可思议威神慈悲之力，救护一切罪苦之事。"},{"note":"wú miè dù hòu, rǔ děng zhū pú sà dà shì, jí tiān lóng guǐ shén děng","text":"吾灭度后，汝等诸菩萨大士，及天龙鬼神等，"},{"note":"guǎng zuò fāng biàn, wèi hù shì jīng, lìng yī qiè zhòng shēng, zhèng niè pán lè","text":"广作方便，卫护是经，令一切众生，证涅槃乐。”"},{"note":"shuō shì yǔ yǐ, huì zhōng yǒu yī pú sà, míng yuē pǔ guǎng, hé zhǎng gōng jìng","text":"说是语已，会中有一菩萨，名曰普广，合掌恭敬，"},{"note":"ér bái fó yán","text":"而白佛言："},{"note":"jīn jiàn shì zūn zàn tàn dì zàng pú sà, yǒu rú shì bù kě sī yì dà wēi shén dé","text":"“今见世尊赞叹地藏菩萨，有如是不可思议大威神德。"},{"note":"wéi yuàn shì zūn wèi wèi lái shì mò fǎ zhòng shēng, xuān shuō dì zàng pú sà lì yì rén tiān yīn guǒ děng shì","text":"唯愿世尊为未来世末法众生，宣说地藏菩萨利益人天因果等事，"},{"note":"shǐ zhū tiān lóng bā bù, jí wèi lái shì zhòng shēng, dǐng shòu fó yǔ","text":"使诸天龙八部，及未来世众生，顶受佛语。”"},{"note":"ěr shí, shì zūn gào pǔ guǎng pú sà jí sì zhòng děng","text":"尔时，世尊告普广菩萨及四众等："},{"note":"dì tīng","text":"“谛听！"},{"note":"dì tīng","text":"谛听！"},{"note":"wú dāng wèi rǔ lüè shuō dì zàng pú sà lì yì rén tiān fú dé zhī shì","text":"吾当为汝略说地藏菩萨利益人天福德之事。”"},{"note":"pǔ guǎng bái yán","text":"普广白言："},{"note":"wéi rán, shì zūn","text":"“唯然，世尊！"},{"note":"yuàn lè yù wén","text":"愿乐欲闻。”"},{"note":"fó gào pǔ guǎng pú sà","text":"佛告普广菩萨："},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, wén shì dì zàng pú sà mó hē sà míng zhě","text":"“未来世中，若有善男子、善女人，闻是地藏菩萨摩诃萨名者，"},{"note":"huò hé zhǎng zhě, zàn tàn zhě, zuò lǐ zhě, liàn mù zhě, shì rén chāo yuè sān shí jié zuì","text":"或合掌者、赞叹者、作礼者、恋慕者，是人超越三十劫罪。”"},{"note":"pǔ guǎng","text":"“普广！"},{"note":"ruò yǒu shàn nán zi, shàn nǚ rén, huò cǎi huà xíng xiàng, huò tǔ shí jiāo qī","text":"若有善男子、善女人，或彩画形像，或土石胶漆、"},{"note":"jīn, yín, tóng, tiě, zuò cǐ pú sà, yī zhān yī lǐ zhě","text":"金、银、铜、铁，作此菩萨，一瞻一礼者，"},{"note":"shì rén bǎi fǎn shēng yú sān shí sān tiān, yǒng bù duò yú è dào","text":"是人百返生于三十三天，永不堕于恶道。"},{"note":"jiǎ rú tiān fú jǐn gù, xià shēng rén jiān, yóu wèi guó wáng, bù shī dà lì","text":"假如天福尽故，下生人间，犹为国王，不失大利。"},{"note":"ruò yǒu nǚ rén, yàn nǚ rén shēn, jǐn xīn gòng yǎng dì zàng pú sà huà xiàng","text":"若有女人，厌女人身，尽心供养地藏菩萨画像，"},{"note":"jí tǔ shí jiāo qī tóng tiě děng xiàng, rú shì rì rì bù tuì, cháng yǐ huá","text":"及土石胶漆铜铁等像，如是日日不退，常以华、"},{"note":"xiāng, yǐn shí, yī fú, zēng cǎi, chuáng fān, qián, bǎo wù děng gòng yǎng","text":"香、饮食、衣服、缯彩、幢旛、钱、宝物等供养。"},{"note":"shì shàn nǚ rén, jǐn cǐ yī bào nǚ shēn, bǎi qiān wàn jié, gèng bù shēng yǒu nǚ rén shì jiè","text":"是善女人，尽此一报女身，百千万劫，更不生有女人世界，"},{"note":"hé kuàng fù shòu","text":"何况复受。"},{"note":"chú fēi cí yuàn lì gù, yào shòu nǚ shēn, dù tuō zhòng shēng","text":"除非慈愿力故，要受女身，度脱众生。"},{"note":"chéng sī gòng yǎng dì zàng lì gù, jí gōng dé lì, bǎi qiān wàn jié","text":"承斯供养地藏力故，及功德力，百千万劫，"},{"note":"bù shòu nǚ shēn","text":"不受女身。”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò yǒu nǚ rén, yàn shì chǒu lòu, duō jí bìng zhě, dàn yú dì zàng xiàng qián","text":"若有女人，厌是丑陋、多疾病者，但于地藏像前，"},{"note":"zhì xīn zhān lǐ, shí qǐng zhī jiān, shì rén qiān wàn jié zhōng, suǒ shòu shēng shēn","text":"志心瞻礼，食顷之间，是人千万劫中，所受生身，"},{"note":"xiāng mào yuán mǎn","text":"相貌圆满。"},{"note":"shì chǒu lòu nǚ rén, rú bù yàn nǚ shēn, jí bǎi qiān wàn yì shēng zhōng","text":"是丑陋女人，如不厌女身，即百千万亿生中，"},{"note":"cháng wèi wáng nǚ, nǎi jí wáng fēi, zǎi fǔ dà xìng, dà zhǎng zhě nǚ","text":"常为王女，乃及王妃、宰辅大姓、大长者女，"},{"note":"duān zhèng shòu shēng, zhū xiāng yuán mǎn","text":"端正受生，诸相圆满。"},{"note":"yóu zhì xīn gù, zhān lǐ dì zàng pú sà, huò fú rú shì","text":"由志心故，瞻礼地藏菩萨，获福如是。”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò yǒu shàn nán zi, shàn nǚ rén, néng duì pú sà xiàng qián, zuò zhū jì lè","text":"若有善男子、善女人，能对菩萨像前，作诸伎乐，"},{"note":"jí gē yǒng zàn tàn, xiāng huá gòng yǎng, nǎi zhì quàn yú yī rén duō rén","text":"及歌咏赞叹，香华供养，乃至劝于一人多人，"},{"note":"rú shì děng bèi, xiàn zài shì zhōng, jí wèi lái shì, cháng dé bǎi qiān guǐ shén rì yè wèi hù","text":"如是等辈，现在世中，及未来世，常得百千鬼神日夜卫护，"},{"note":"bù lìng è shì zhé wén qí ěr, hé kuàng qīn shòu zhū héng","text":"不令恶事辄闻其耳，何况亲受诸横？”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"wèi lái shì zhōng, ruò yǒu è rén, jí è shén è guǐ, jiàn yǒu shàn nán zi shàn nǚ rén","text":"未来世中，若有恶人，及恶神恶鬼，见有善男子善女人，"},{"note":"guī jìng gòng yǎng zàn tàn zhān lǐ dì zàng pú sà xíng xiàng, huò wàng shēng jī huǐ","text":"归敬供养赞叹瞻礼地藏菩萨形像，或妄生讥毁，"},{"note":"bàng wú gōng dé jí lì yì shì, huò lù chǐ xiào, huò bèi miàn fēi","text":"谤无功德及利益事，或露齿笑，或背面非，"},{"note":"huò quàn rén gòng fēi, huò yī rén fēi, huò duō rén fēi, nǎi zhì yī niàn shēng jī huǐ zhě","text":"或劝人共非，或一人非，或多人非，乃至一念生讥毁者，"},{"note":"rú shì zhī rén, xián jié qiān fó miè dù, jī huǐ zhī bào, shàng zài ā bí dì yù","text":"如是之人，贤劫千佛灭度，讥毁之报，尚在阿鼻地狱，"},{"note":"shòu jí zhòng zuì","text":"受极重罪。"},{"note":"guò shì jié yǐ, fāng shòu è guǐ","text":"过是劫已，方受饿鬼。"},{"note":"yòu jīng qiān jié, fù shòu chù shēng","text":"又经千劫，复受畜生。"},{"note":"yòu jīng qiān jié, fāng dé rén shēn","text":"又经千劫，方得人身。"},{"note":"zòng shòu rén shēn, pín qióng xià jiàn, zhū gēn bù jù, duō bèi è yè","text":"纵受人身，贫穷下贱，诸根不具，多被恶业，"},{"note":"lái jié qí xīn, bù jiǔ zhī jiān, fù duò è dào","text":"来结其心，不久之间，复堕恶道。"},{"note":"shì gù, pǔ guǎng","text":"是故，普广！"},{"note":"jī huǐ tā rén gòng yǎng, shàng huò cǐ bào, hé kuàng bié shēng è jiàn huǐ miè","text":"讥毁他人供养，尚获此报，何况别生恶见毁灭？”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò wèi lái shì, yǒu nán zi nǚ rén, jiǔ chù chuáng zhěn, qiú shēng qiú sǐ","text":"若未来世，有男子女人，久处床枕，求生求死，"},{"note":"le bù kě dé, huò yè mèng è guǐ, nǎi jí jiā qīn, huò yóu xiǎn dào","text":"了不可得，或夜梦恶鬼，乃及家亲，或游险道，"},{"note":"huò duō yǎn mèi, gòng guǐ shén yóu, rì yuè suì shēn, zhuǎn fù wāng zhài","text":"或多魇寐，共鬼神游，日月岁深，转复尫瘵，"},{"note":"mián zhōng jiào kǔ, cǎn qī bù lè zhě, cǐ jiē shì yè dào lùn duì","text":"眠中叫苦，惨凄不乐者，此皆是业道论对，"},{"note":"wèi dìng qīng zhòng, huò nán shě shòu, huò bù dé yù","text":"未定轻重，或难舍寿，或不得愈。"},{"note":"nán nǚ sú yǎn, bù biàn shì shì","text":"男女俗眼，不辨是事。"},{"note":"dàn dāng duì zhū fó pú sà xiàng qián, gāo shēng zhuǎn dú cǐ jīng yī biàn","text":"但当对诸佛菩萨像前，高声转读此经一遍。"},{"note":"huò qǔ bìng rén kě ài zhī wù, huò yī fú bǎo bèi, zhuāng yuán shě zhái","text":"或取病人可爱之物，或衣服宝贝、庄园舍宅，"},{"note":"duì bìng rén qián, gāo shēng chàng yán","text":"对病人前，高声唱言："},{"note":"wǒ mǒu jiǎ děng, wèi shì bìng rén, duì jīng xiàng qián, shě zhū děng wù","text":"‘我某甲等，为是病人，对经像前，舍诸等物，"},{"note":"huò gòng yǎng jīng xiàng, huò zào fó pú sà xíng xiàng, huò zào tǎ sì","text":"或供养经像，或造佛菩萨形像，或造塔寺，"},{"note":"huò rán yóu dēng, huò shī cháng zhù. rú shì sān bái bìng rén","text":"或然油灯，或施常住。’如是三白病人，"},{"note":"qiǎn lìng wén zhī","text":"遣令闻知。"},{"note":"jiǎ lìng zhū shí fēn sàn, zhì qì jǐn zhě, nǎi zhì yī rì, èr rì","text":"假令诸识分散，至气尽者，乃至一日、二日、"},{"note":"sān rì, sì rì, zhì qī rì yǐ lái, dàn gāo shēng bái, gāo shēng dú jīng","text":"三日、四日，至七日已来，但高声白，高声读经。"},{"note":"shì rén mìng zhōng zhī hòu, sù yāng zhòng zuì, zhì yú wǔ wú jiān zuì","text":"是人命终之后，宿殃重罪，至于五无间罪，"},{"note":"yǒng dé jiě tuō","text":"永得解脱。"},{"note":"suǒ shòu shēng chù, cháng zhī sù mìng","text":"所受生处，常知宿命。"},{"note":"hé kuàng shàn nán zi, shàn nǚ rén, zì shū cǐ jīng, huò jiào rén shū","text":"何况善男子、善女人，自书此经，或教人书，"},{"note":"huò zì sù huà pú sà xíng xiàng, nǎi zhì jiào rén sù huà, suǒ shòu guǒ bào","text":"或自塑画菩萨形像，乃至教人塑画，所受果报，"},{"note":"bì huò dà lì","text":"必获大利。”"},{"note":"shì gù, pǔ guǎng","text":"“是故，普广！"},{"note":"ruò jiàn yǒu rén dú sòng shì jīng, nǎi zhì yī niàn zàn tàn shì jīng","text":"若见有人读诵是经，乃至一念赞叹是经，"},{"note":"huò gōng jìng zhě, rǔ xū bǎi qiān fāng biàn, quàn shì děng rén, qín xīn mò tuì","text":"或恭敬者，汝须百千方便，劝是等人，勤心莫退，"},{"note":"néng dé wèi lái xiàn zài qiān wàn yì bù kě sī yì gōng dé","text":"能得未来现在千万亿不可思议功德。"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò wèi lái shì zhū zhòng shēng děng, huò mèng huò mèi, jiàn zhū guǐ shén nǎi jí zhū xíng","text":"若未来世诸众生等，或梦或寐，见诸鬼神乃及诸形，"},{"note":"huò bēi huò tí, huò chóu huò tàn, huò kǒng huò bù","text":"或悲或啼，或愁或叹，或恐或怖。"},{"note":"cǐ jiē shì yī shēng shí shēng, bǎi shēng qiān shēng, guò qù fù mǔ","text":"此皆是一生十生，百生千生，过去父母、"},{"note":"nán nǚ dì mèi, fū qī juàn shǔ, zài yú è qù, wèi dé chū lí","text":"男女弟妹、夫妻眷属，在于恶趣，未得出离，"},{"note":"wú chù xī wàng fú lì jiù bá, dāng gào sù shì gǔ ròu, shǐ zuò fāng biàn","text":"无处希望福力救拔，当告宿世骨肉，使作方便，"},{"note":"yuàn lí è dào","text":"愿离恶道。"},{"note":"pǔ guǎng","text":"普广！"},{"note":"rǔ yǐ shén lì, qiǎn shì juàn shǔ, lìng duì zhū fó pú sà xiàng qián","text":"汝以神力，遣是眷属，令对诸佛菩萨像前，"},{"note":"zhì xīn zì dú cǐ jīng, huò qǐng rén dú","text":"志心自读此经，或请人读。"},{"note":"qí shù sān biàn huò qī biàn","text":"其数三遍或七遍。"},{"note":"rú shì è dào juàn shǔ, jīng shēng bì shì biàn shù, dāng dé jiě tuō","text":"如是恶道眷属，经声毕是遍数，当得解脱。"},{"note":"nǎi zhì mèng mèi zhī zhōng, yǒng bù fù jiàn","text":"乃至梦寐之中，永不复见。”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò wèi lái shì yǒu zhū xià jiàn děng rén, huò nú huò bì, nǎi zhì zhū bù zì yóu zhī rén","text":"若未来世有诸下贱等人，或奴或婢，乃至诸不自由之人，"},{"note":"jué zhī sù yè, yào chàn huǐ zhě, zhì xīn zhān lǐ dì zàng pú sà xíng xiàng","text":"觉知宿业，要忏悔者，志心瞻礼地藏菩萨形像，"},{"note":"nǎi zhì yī qī rì zhōng, niàn pú sà míng, kě mǎn wàn biàn","text":"乃至一七日中，念菩萨名，可满万遍。"},{"note":"rú shì děng rén, jǐn cǐ bào hòu, qiān wàn shēng zhōng, cháng shēng zūn guì","text":"如是等人，尽此报后，千万生中，常生尊贵，"},{"note":"gèng bù jīng sān è dào kǔ","text":"更不经三恶道苦。”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò wèi lái shì zhōng, yán fú tí nèi, shā lì, pó luó mén","text":"若未来世中，阎浮提内，刹利、婆罗门、"},{"note":"zhǎng zhě, jū shì, yī qiè rén děng, jí yì xìng zhǒng zú, yǒu xīn chǎn zhě","text":"长者、居士、一切人等，及异姓种族，有新产者，"},{"note":"huò nán huò nǚ, qī rì zhī zhōng, zǎo yǔ dú sòng cǐ bù sī yì jīng diǎn","text":"或男或女，七日之中，早与读诵此不思议经典，"},{"note":"gèng wèi niàn pú sà míng, kě mǎn wàn biàn","text":"更为念菩萨名，可满万遍。"},{"note":"shì xīn shēng zi, huò nán huò nǚ, sù yǒu yāng bào, biàn dé jiě tuō","text":"是新生子，或男或女，宿有殃报，便得解脱，"},{"note":"ān lè yì yǎng, shòu mìng zēng zhǎng","text":"安乐易养，寿命增长。"},{"note":"ruò shì chéng fú shēng zhě, zhuǎn zēng ān lè, jí yǔ shòu mìng","text":"若是承福生者，转增安乐，及与寿命。”"},{"note":"fù cì, pǔ guǎng","text":"“复次，普广！"},{"note":"ruò wèi lái shì zhòng shēng, yú yuè yī rì, bā rì, shí sì rì","text":"若未来世众生，于月一日、八日、十四日、"},{"note":"shí wǔ rì, shí bā rì, èr shí sān, èr shí sì, èr shí bā","text":"十五日、十八日、二十三、二十四、二十八、"},{"note":"èr shí jiǔ rì, nǎi zhì sān shí rì, shì zhū rì děng, zhū zuì jié jí","text":"二十九日，乃至三十日，是诸日等，诸罪结集，"},{"note":"dìng qí qīng zhòng","text":"定其轻重。"},{"note":"nán yán fú tí zhòng shēng, jǔ zhǐ dòng niàn, wú bù shì yè, wú bù shì zuì","text":"南阎浮提众生，举止动念，无不是业，无不是罪，"},{"note":"hé kuàng zì qíng shā hài, qiè dào, xié yín, wàng yǔ, bǎi qiān zuì zhuàng","text":"何况恣情杀害、窃盗、邪淫、妄语，百千罪状。"},{"note":"néng yú shì shí zhāi rì, duì fó pú sà zhū xián shèng xiàng qián, dú shì jīng yī biàn","text":"能于是十斋日，对佛菩萨诸贤圣像前，读是经一遍，"},{"note":"dōng xī nán běi, bǎi yóu xún nèi, wú zhū zāi nán","text":"东西南北，百由旬内，无诸灾难。"},{"note":"dāng cǐ jū jiā, ruò zhǎng ruò yòu, xiàn zài wèi lái bǎi qiān suì zhōng","text":"当此居家，若长若幼，现在未来百千岁中，"},{"note":"yǒng lí è qù","text":"永离恶趣。"},{"note":"néng yú shí zhāi rì měi zhuǎn yī biàn, xiàn shì lìng cǐ jū jiā wú zhū héng bìng","text":"能于十斋日每转一遍，现世令此居家无诸横病，"},{"note":"yī shí fēng yì","text":"衣食丰溢。”"},{"note":"shì gù, pǔ guǎng","text":"“是故，普广！"},{"note":"dāng zhī dì zàng pú sà yǒu rú shì děng bù kě shuō bǎi qiān wàn yì dà wēi shén lì lì yì zhī shì","text":"当知地藏菩萨有如是等不可说百千万亿大威神力利益之事。"},{"note":"yán fú zhòng shēng, yú cǐ dà shì yǒu dà yīn yuán","text":"阎浮众生，于此大士有大因缘。"},{"note":"shì zhū zhòng shēng, wén pú sà míng, jiàn pú sà xiàng, nǎi zhì wén shì jīng","text":"是诸众生，闻菩萨名，见菩萨像，乃至闻是经，"},{"note":"sān zì wǔ zì, huò yī jì yī jù zhě, xiàn zài shū miào ān lè","text":"三字五字，或一偈一句者，现在殊妙安乐，"},{"note":"wèi lái zhī shì, bǎi qiān wàn shēng, cháng dé duān zhèng, shēng zūn guì jiā","text":"未来之世，百千万生，常得端正，生尊贵家。”"},{"note":"ěr shí, pǔ guǎng pú sà wén fó rú lái chēng yáng zàn tàn dì zàng pú sà yǐ","text":"尔时，普广菩萨闻佛如来称扬赞叹地藏菩萨已，"},{"note":"hú guì hé zhǎng, fù bái fó yán","text":"胡跪合掌，复白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ jiǔ zhī shì dà shì yǒu rú cǐ bù kě sī yì shén lì, jí dà shì yuàn lì","text":"我久知是大士有如此不可思议神力，及大誓愿力。"},{"note":"wèi wèi lái zhòng shēng, qiǎn zhī lì yì, gù wèn rú lái, wéi rán dǐng shòu","text":"为未来众生，遣知利益，故问如来，唯然顶受。"},{"note":"shì zūn","text":"世尊！"},{"note":"dāng hé míng cǐ jīng","text":"当何名此经？"},{"note":"shǐ wǒ yún hé liú bù","text":"使我云何流布？”"},{"note":"fó gào pǔ guǎng","text":"佛告普广："},{"note":"cǐ jīng yǒu sān míng","text":"“此经有三名："},{"note":"yī míng dì zàng běn yuàn, yì míng dì zàng běn xíng, yì míng dì zàng běn shì lì jīng","text":"一名地藏本愿，亦名地藏本行，亦名地藏本誓力经。"},{"note":"yuán cǐ pú sà, jiǔ yuǎn jié lái, fā dà zhòng yuàn, lì yì zhòng shēng","text":"缘此菩萨，久远劫来，发大重愿，利益众生，"},{"note":"shì gù rǔ děng, yī yuàn liú bù","text":"是故汝等，依愿流布。”"},{"note":"pǔ guǎng wén yǐ, hé zhǎng gōng jìng, zuò lǐ ér tuì","text":"普广闻已，合掌恭敬，作礼而退。"}],"ksitigarbha-07":[{"note":"lì yì cún wáng pǐn dì qī","text":"利益存亡品第七"},{"note":"ěr shí, dì zàng pú sà mó hē sà bái fó yán","text":"尔时，地藏菩萨摩诃萨白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ guān shì yán fú zhòng shēng, jǔ xīn dòng niàn, wú fēi shì zuì","text":"我观是阎浮众生，举心动念，无非是罪。"},{"note":"tuō huò shàn lì, duō tuì chū xīn","text":"脱获善利，多退初心；"},{"note":"ruò yù è yuán, niàn niàn zēng yì","text":"若遇恶缘，念念增益。"},{"note":"shì děng bèi rén, rú lǚ ní tú, fù yú zhòng shí, jiàn kùn jiàn zhòng","text":"是等辈人，如履泥涂，负于重石，渐困渐重，"},{"note":"zú bù shēn suì","text":"足步深邃。"},{"note":"ruò dé yù zhī shí, tì yǔ jiǎn fù, huò quán yǔ fù, shì zhī shí yǒu dà lì gù","text":"若得遇知识，替与减负，或全与负，是知识有大力故，"},{"note":"fù xiāng fú zhù, quàn lìng láo jiǎo, ruò dá píng dì, xū shěng è lù","text":"复相扶助，劝令牢脚，若达平地，须省恶路，"},{"note":"wú zài jīng lì","text":"无再经历。”"},{"note":"shì zūn","text":"“世尊！"},{"note":"xí è zhòng shēng, cóng xiān háo jiān, biàn zhì wú liàng","text":"习恶众生，从纤毫间，便至无量。"},{"note":"shì zhū zhòng shēng, yǒu rú cǐ xí, lín mìng zhōng shí, fù mǔ juàn shǔ yí wèi shè fú","text":"是诸众生，有如此习，临命终时，父母眷属宜为设福，"},{"note":"yǐ zī qián lù","text":"以资前路。"},{"note":"huò xuán fān gài, jí rán yóu dēng, huò zhuǎn dú zūn jīng, huò gòng yǎng fó xiàng jí zhū shèng xiàng","text":"或悬旛盖，及然油灯，或转读尊经，或供养佛像及诸圣像。"},{"note":"nǎi zhì niàn fó pú sà jí pì zhī fó míng zì, yī míng yī hào","text":"乃至念佛菩萨及辟支佛名字，一名一号，"},{"note":"lì lín zhōng rén ěr gēn, huò wén zài běn shí","text":"历临终人耳根，或闻在本识。"},{"note":"shì zhū zhòng shēng suǒ zào è yè, jì qí gǎn guǒ, bì duò è qù","text":"是诸众生所造恶业，计其感果，必堕恶趣，"},{"note":"yuán shì juàn shǔ wèi lín zhōng rén xiū cǐ shèng yīn, rú shì zhòng zuì","text":"缘是眷属为临终人修此圣因，如是众罪，"},{"note":"xī jiē xiāo miè","text":"悉皆销灭。"},{"note":"ruò néng gèng wèi shēn sǐ zhī hòu, qī qī rì nèi, guǎng zào zhòng shàn","text":"若能更为身死之后，七七日内，广造众善，"},{"note":"néng shǐ shì zhū zhòng shēng, yǒng lí è qù, dé shēng rén tiān, shòu shèng miào lè","text":"能使是诸众生，永离恶趣，得生人天，受胜妙乐，"},{"note":"xiàn zài juàn shǔ, lì yì wú liàng","text":"现在眷属，利益无量。”"},{"note":"shì gù wǒ jīn duì fó shì zūn, jí tiān lóng bā bù, rén","text":"“是故我今对佛世尊，及天龙八部、人、"},{"note":"fēi rén děng, quàn yú yán fú tí zhòng shēng","text":"非人等，劝于阎浮提众生："},{"note":"lín zhōng zhī rì, shèn wù shā hài, jí zào è yuán bài jì guǐ shén","text":"临终之日，慎勿杀害，及造恶缘——拜祭鬼神，"},{"note":"qiú zhū wǎng liǎng","text":"求诸魍魉。"},{"note":"hé yǐ gù","text":"何以故？"},{"note":"ěr suǒ shā hài, nǎi zhì bài jì, wú xiān háo zhī lì lì yì wáng rén","text":"尔所杀害，乃至拜祭，无纤毫之力利益亡人，"},{"note":"dàn jié zuì yuán, zhuǎn zēng shēn zhòng","text":"但结罪缘，转增深重。"},{"note":"jiǎ shǐ lái shì, huò xiàn zài shēng, dé huò shèng fēn, shēng rén tiān zhōng","text":"假使来世，或现在生，得获圣分，生人天中，"},{"note":"yuán shì lín zhōng bèi zhū juàn shǔ zào shì è yīn, yì lìng shì mìng zhōng rén","text":"缘是临终被诸眷属造是恶因，亦令是命终人，"},{"note":"yāng lèi duì biàn, wǎn shēng shàn chù","text":"殃累对辩，晚生善处。"},{"note":"hé kuàng lín mìng zhōng rén, zài shēng wèi céng yǒu shǎo shàn gēn, gè jù běn yè","text":"何况临命终人，在生未曾有少善根，各据本业，"},{"note":"zì shòu è qù, hé rěn juàn shǔ, gèng wèi zēng yè","text":"自受恶趣，何忍眷属，更为增业？"},{"note":"pì rú yǒu rén, cóng yuǎn dì lái, jué liáng sān rì, suǒ fù dān wù","text":"譬如有人，从远地来，绝粮三日，所负担物，"},{"note":"qiáng guò bǎi jīn","text":"强过百斤。"},{"note":"hū yù lín rén, gèng fù shǎo wù, yǐ shì zhī gù, zhuǎn fù kùn zhòng","text":"忽遇邻人，更附少物，以是之故，转复困重。"},{"note":"shì zūn","text":"世尊！"},{"note":"wǒ guān yán fú zhòng shēng, dàn néng yú zhū fó jiào zhōng, nǎi zhì shàn shì","text":"我观阎浮众生，但能于诸佛教中，乃至善事，"},{"note":"yī máo yī dì, yī shā yī chén, rú shì lì yì, xī jiē zì dé","text":"一毛一渧，一沙一尘，如是利益，悉皆自得。”"},{"note":"shuō shì yǔ shí, huì zhōng yǒu yī zhǎng zhě, míng yuē dà biàn, shì zhǎng zhě jiǔ zhèng wú shēng","text":"说是语时，会中有一长者，名曰大辩，是长者久证无生，"},{"note":"huà dù shí fāng, xiàn zhǎng zhě shēn, hé zhǎng gōng jìng, wèn dì zàng pú sà yán","text":"化度十方，现长者身，合掌恭敬，问地藏菩萨言："},{"note":"dà shì","text":"“大士！"},{"note":"shì nán yán fú tí zhòng shēng, mìng zhōng zhī hòu, xiǎo dà juàn shǔ","text":"是南阎浮提众生，命终之后，小大眷属，"},{"note":"wèi xiū gōng dé, nǎi zhì shè zhāi, zào zhòng shàn yīn, shì mìng zhōng rén","text":"为修功德，乃至设斋，造众善因，是命终人，"},{"note":"dé dà lì yì jí jiě tuō bù","text":"得大利益及解脱不？”"},{"note":"dì zàng dá yán","text":"地藏答言："},{"note":"zhǎng zhě","text":"“长者！"},{"note":"wǒ jīn wèi wèi lái xiàn zài yī qiè zhòng shēng, chéng fó wēi lì, lüè shuō shì shì","text":"我今为未来现在一切众生，承佛威力，略说是事。"},{"note":"zhǎng zhě, wèi lái xiàn zài zhū zhòng shēng děng, lín mìng zhōng rì, dé wén yī fó míng","text":"长者，未来现在诸众生等，临命终日，得闻一佛名、"},{"note":"yī pú sà míng, yī pì zhī fó míng, bù wèn yǒu zuì wú zuì","text":"一菩萨名、一辟支佛名，不问有罪无罪，"},{"note":"xī dé jiě tuō","text":"悉得解脱。”"},{"note":"ruò yǒu nán zi nǚ rén, zài shēng bù xiū shàn yīn, duō zào zhòng zuì","text":"“若有男子女人，在生不修善因，多造众罪，"},{"note":"mìng zhōng zhī hòu, juàn shǔ xiǎo dà wèi zào fú lì yī qiè shèng shì","text":"命终之后，眷属小大为造福利一切圣事，"},{"note":"qī fēn zhī zhōng, ér nǎi huò yī, liù fēn gōng dé, shēng zhě zì lì","text":"七分之中，而乃获一，六分功德，生者自利。"},{"note":"yǐ shì zhī gù, wèi lái xiàn zài shàn nán nǚ děng, wén jiàn zì xiū","text":"以是之故，未来现在善男女等，闻健自修，"},{"note":"fēn fēn jǐ huò","text":"分分己获。"},{"note":"wú cháng dà guǐ, bù qī ér dào, míng míng yóu shén, wèi zhī zuì fú","text":"无常大鬼，不期而到，冥冥游神，未知罪福，"},{"note":"qī qī rì nèi, rú chī rú lóng","text":"七七日内，如痴如聋。"},{"note":"huò zài zhū sī, biàn lùn yè guǒ, shěn dìng zhī hòu, jù yè shòu shēng","text":"或在诸司，辩论业果，审定之后，据业受生。"},{"note":"wèi cè zhī jiān, qiān wàn chóu kǔ, hé kuàng duò yú zhū è qù děng","text":"未测之间，千万愁苦，何况堕于诸恶趣等？"},{"note":"shì mìng zhōng rén, wèi dé shòu shēng, zài qī qī rì nèi, niàn niàn zhī jiān","text":"是命终人，未得受生，在七七日内，念念之间，"},{"note":"wàng zhū gǔ ròu juàn shǔ, yǔ zào fú lì jiù bá","text":"望诸骨肉眷属，与造福力救拔。"},{"note":"guò shì rì hòu, suí yè shòu bào, ruò shì zuì rén, dòng jīng qiān bǎi suì zhōng","text":"过是日后，随业受报，若是罪人，动经千百岁中，"},{"note":"wú jiě tuō rì","text":"无解脱日。"},{"note":"ruò shì wǔ wú jiān zuì, duò dà dì yù, qiān jié wàn jié, yǒng shòu zhòng kǔ","text":"若是五无间罪，堕大地狱，千劫万劫，永受众苦。”"},{"note":"fù cì, zhǎng zhě","text":"“复次，长者！"},{"note":"rú shì zuì yè zhòng shēng, mìng zhōng zhī hòu, juàn shǔ gǔ ròu, wèi xiū yíng zhāi","text":"如是罪业众生，命终之后，眷属骨肉，为修营斋，"},{"note":"zī zhù yè dào","text":"资助业道。"},{"note":"wèi zhāi shí jìng, jí yíng zhāi zhī cì, mǐ gān cài yè, bù qì yú dì","text":"未斋食竟，及营斋之次，米泔菜叶，不弃于地。"},{"note":"nǎi zhì zhū shí wèi xiàn fó sēng, wù dé xiān shí","text":"乃至诸食未献佛僧，勿得先食。"},{"note":"rú yǒu wéi shí jí bù jīng qín, shì mìng zhōng rén, le bù dé lì","text":"如有违食及不精勤，是命终人，了不得力。"},{"note":"rú jīng qín hù jìng, fèng xiàn fó sēng, shì mìng zhōng rén, qī fēn huò yī","text":"如精勤护净，奉献佛僧，是命终人，七分获一。"},{"note":"shì gù, zhǎng zhě","text":"是故，长者！"},{"note":"yán fú zhòng shēng, ruò néng wèi qí fù mǔ, nǎi zhì juàn shǔ, mìng zhōng zhī hòu","text":"阎浮众生，若能为其父母，乃至眷属，命终之后，"},{"note":"shè zhāi gòng yǎng, zhì xīn qín kěn, rú shì zhī rén, cún wáng huò lì","text":"设斋供养，志心勤恳，如是之人，存亡获利。”"},{"note":"shuō shì yǔ shí, dāo lì tiān gōng yǒu qiān wàn yì nà yóu tā yán fú guǐ shén","text":"说是语时，忉利天宫有千万亿那由他阎浮鬼神，"},{"note":"xī fā wú liàng pú tí zhī xīn","text":"悉发无量菩提之心。"},{"note":"dà biàn zhǎng zhě, zuò lǐ ér tuì","text":"大辩长者，作礼而退。"}],"ksitigarbha-08":[{"note":"yán luó wáng zhòng zàn tàn pǐn dì bā","text":"阎罗王众赞叹品第八"},{"note":"ěr shí, tiě wéi shān nèi, yǒu wú liàng guǐ wáng, yǔ yán luó tiān zi","text":"尔时，铁围山内，有无量鬼王，与阎罗天子，"},{"note":"jù yì dāo lì, lái dào fó suǒ","text":"俱诣忉利，来到佛所。"},{"note":"suǒ wèi è dú guǐ wáng, duō è guǐ wáng, dà zhèng guǐ wáng, bái hǔ guǐ wáng","text":"所谓恶毒鬼王、多恶鬼王、大诤鬼王、白虎鬼王、"},{"note":"xuè hǔ guǐ wáng, chì hǔ guǐ wáng, sàn yāng guǐ wáng, fēi shēn guǐ wáng","text":"血虎鬼王、赤虎鬼王、散殃鬼王、飞身鬼王、"},{"note":"diàn guāng guǐ wáng, láng yá guǐ wáng, qiān yǎn guǐ wáng, dàn shòu guǐ wáng","text":"电光鬼王、狼牙鬼王、千眼鬼王、啖兽鬼王、"},{"note":"fù shí guǐ wáng, zhǔ hào guǐ wáng, zhǔ huò guǐ wáng, zhǔ shí guǐ wáng","text":"负石鬼王、主耗鬼王、主祸鬼王、主食鬼王、"},{"note":"zhǔ cái guǐ wáng, zhǔ chù guǐ wáng, zhǔ qín guǐ wáng, zhǔ shòu guǐ wáng","text":"主财鬼王、主畜鬼王、主禽鬼王、主兽鬼王、"},{"note":"zhǔ mèi guǐ wáng, zhǔ chǎn guǐ wáng, zhǔ mìng guǐ wáng, zhǔ jí guǐ wáng","text":"主魅鬼王、主产鬼王、主命鬼王、主疾鬼王、"},{"note":"zhǔ xiǎn guǐ wáng, sān mù guǐ wáng, sì mù guǐ wáng, wǔ mù guǐ wáng","text":"主险鬼王、三目鬼王、四目鬼王、五目鬼王、"},{"note":"qí lì shī wáng, dà qí lì shī wáng, qí lì chā wáng, dà qí lì chā wáng","text":"祁利失王、大祁利失王、祁利叉王、大祁利叉王、"},{"note":"ā nà zhà wáng, dà ā nà zhà wáng","text":"阿那吒王、大阿那吒王。"},{"note":"rú shì děng dà guǐ wáng, gè gè yǔ bǎi qiān zhū xiǎo guǐ wáng, jǐn jū yán fú tí","text":"如是等大鬼王，各各与百千诸小鬼王，尽居阎浮提，"},{"note":"gè yǒu suǒ zhí, gè yǒu suǒ zhǔ","text":"各有所执，各有所主。"},{"note":"shì zhū guǐ wáng, yǔ yán luó tiān zi, chéng fó wēi shén, jí dì zàng pú sà mó hē sà lì","text":"是诸鬼王，与阎罗天子，承佛威神，及地藏菩萨摩诃萨力，"},{"note":"jù yì dāo lì, zài yī miàn lì","text":"俱诣忉利，在一面立。"},{"note":"ěr shí, yán luó tiān zi, hú guì hé zhǎng, bái fó yán","text":"尔时，阎罗天子，胡跪合掌，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ děng jīn zhě yǔ zhū guǐ wáng, chéng fó wēi shén, jí dì zàng pú sà mó hē sà lì","text":"我等今者与诸鬼王，承佛威神，及地藏菩萨摩诃萨力，"},{"note":"fāng dé yì cǐ dāo lì dà huì, yì shì wǒ děng huò shàn lì gù","text":"方得诣此忉利大会，亦是我等获善利故。"},{"note":"wǒ jīn yǒu xiǎo yí shì, gǎn wèn shì zūn, wéi yuàn shì zūn, cí bēi xuān shuō","text":"我今有小疑事，敢问世尊，唯愿世尊，慈悲宣说。”"},{"note":"fó gào yán luó tiān zi","text":"佛告阎罗天子："},{"note":"zì rǔ suǒ wèn, wú wèi rǔ shuō","text":"“恣汝所问，吾为汝说。”"},{"note":"shì shí, yán luó tiān zi zhān lǐ shì zūn, jí huí shì dì zàng pú sà","text":"是时，阎罗天子瞻礼世尊，及回视地藏菩萨，"},{"note":"ér bái fó yán","text":"而白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ guān dì zàng pú sà, zài liù dào zhōng, bǎi qiān fāng biàn, ér dù zuì kǔ zhòng shēng","text":"我观地藏菩萨，在六道中，百千方便，而度罪苦众生，"},{"note":"bù cí pí juàn","text":"不辞疲倦。"},{"note":"shì dà pú sà, yǒu rú shì bù kě sī yì shén tōng zhī shì","text":"是大菩萨，有如是不可思议神通之事。"},{"note":"rán zhū zhòng shēng, tuō huò zuì bào, wèi jiǔ zhī jiān, yòu duò è dào","text":"然诸众生，脱获罪报，未久之间，又堕恶道。"},{"note":"shì zūn","text":"世尊！"},{"note":"shì dì zàng pú sà jì yǒu rú shì bù kě sī yì shén lì, yún hé zhòng shēng ér bù yī zhǐ shàn dào","text":"是地藏菩萨既有如是不可思议神力，云何众生而不依止善道，"},{"note":"yǒng qǔ jiě tuō","text":"永取解脱？"},{"note":"wéi yuàn shì zūn, wèi wǒ jiě shuō","text":"唯愿世尊，为我解说。”"},{"note":"fó gào yán luó tiān zi","text":"佛告阎罗天子："},{"note":"nán yán fú tí zhòng shēng, qí xìng gāng qiáng, nán diào nán fú","text":"“南阎浮提众生，其性刚强，难调难伏。"},{"note":"shì dà pú sà, yú bǎi qiān jié, tóu tóu jiù bá rú shì zhòng shēng","text":"是大菩萨，于百千劫，头头救拔如是众生，"},{"note":"zǎo lìng jiě tuō","text":"早令解脱。"},{"note":"shì zuì bào rén, nǎi zhì duò dà è qù","text":"是罪报人，乃至堕大恶趣。"},{"note":"pú sà yǐ fāng biàn lì, bá chū gēn běn yè yuán, ér qiǎn wù sù shì zhī shì","text":"菩萨以方便力，拔出根本业缘，而遣悟宿世之事。"},{"note":"zì shì yán fú zhòng shēng, jié è xí zhòng, xuán chū xuán rù","text":"自是阎浮众生，结恶习重，旋出旋入。"},{"note":"láo sī pú sà, jiǔ jīng jié shù, ér zuò dù tuō","text":"劳斯菩萨，久经劫数，而作度脱。”"},{"note":"pì rú yǒu rén, mí shī běn jiā, wù rù xiǎn dào","text":"“譬如有人，迷失本家，误入险道。"},{"note":"qí xiǎn dào zhōng, duō zhū yè chā, jí hǔ láng shī zi, yuán shé fù xiē","text":"其险道中，多诸夜叉，及虎狼师子、蚖蛇蝮蝎。"},{"note":"rú shì mí rén, zài xiǎn dào zhōng, xū yú zhī jiān, jí zāo zhū dú","text":"如是迷人，在险道中，须臾之间，即遭诸毒。"},{"note":"yǒu yī zhī shí, duō jiě dà shù, shàn jìn shì dú, nǎi jí yè chā zhū è dú děng","text":"有一知识，多解大术，善禁是毒，乃及夜叉诸恶毒等。"},{"note":"hū féng mí rén, yù jìn xiǎn dào, ér yǔ zhī yán","text":"忽逢迷人，欲进险道，而语之言："},{"note":"duō zāi","text":"‘咄哉！"},{"note":"nán zi","text":"男子！"},{"note":"wèi hé shì gù, ér rù cǐ lù","text":"为何事故，而入此路？"},{"note":"yǒu hé yì shù, néng zhì zhū dú. shì mí lù rén, hū wén shì yǔ","text":"有何异术，能制诸毒？’是迷路人，忽闻是语，"},{"note":"fāng zhī xiǎn dào, jí biàn tuì bù, qiú chū cǐ lù","text":"方知险道，即便退步，求出此路。"},{"note":"shì shàn zhī shí, tí xié jiē shǒu, yǐn chū xiǎn dào, miǎn zhū è dú","text":"是善知识，提携接手，引出险道，免诸恶毒，"},{"note":"zhì yú hǎo dào, lìng dé ān lè, ér yǔ zhī yán","text":"至于好道，令得安乐，而语之言："},{"note":"duō zāi","text":"‘咄哉！"},{"note":"mí rén","text":"迷人！"},{"note":"zì jīn yǐ hòu, wù lǚ shì dào","text":"自今已后，勿履是道。"},{"note":"cǐ lù rù zhě, zú nán dé chū, fù sǔn xìng mìng. shì mí lù rén","text":"此路入者，卒难得出，复损性命。’是迷路人，"},{"note":"yì shēng gǎn zhòng","text":"亦生感重。"},{"note":"lín bié zhī shí, zhī shí yòu yán","text":"临别之时，知识又言："},{"note":"ruò jiàn qīn zhī jí zhū lù rén, ruò nán ruò nǚ, yán yú cǐ lù duō zhū dú è","text":"‘若见亲知及诸路人，若男若女，言于此路多诸毒恶，"},{"note":"sàng shī xìng mìng","text":"丧失性命。"},{"note":"wú lìng shì zhòng, zì qǔ qí sǐ","text":"无令是众，自取其死。’”"},{"note":"shì gù dì zàng pú sà jù dà cí bēi, jiù bá zuì kǔ zhòng shēng","text":"“是故地藏菩萨具大慈悲，救拔罪苦众生，"},{"note":"shēng tiān rén zhōng, lìng shòu miào lè","text":"生天人中，令受妙乐。"},{"note":"shì zhū zuì zhòng, zhī yè dào kǔ, tuō dé chū lí, yǒng bù zài lì","text":"是诸罪众，知业道苦，脱得出离，永不再历。"},{"note":"rú mí lù rén, wù rù xiǎn dào, yù shàn zhī shí, yǐn jiē lìng chū","text":"如迷路人，误入险道，遇善知识，引接令出，"},{"note":"yǒng bù fù rù","text":"永不复入。"},{"note":"féng jiàn tā rén, fù quàn mò rù, zì yán","text":"逢见他人，复劝莫入，自言："},{"note":"yīn shì mí gù, dé jiě tuō jìng, gèng bù fù rù. ruò zài lǚ jiàn","text":"‘因是迷故，得解脱竟，更不复入。’若再履践，"},{"note":"yóu shàng mí wù, bù jué jiù céng suǒ luò xiǎn dào, huò zhì shī mìng","text":"犹尚迷误，不觉旧曾所落险道，或致失命，"},{"note":"rú duò è qù","text":"如堕恶趣。"},{"note":"dì zàng pú sà fāng biàn lì gù, shǐ lìng jiě tuō, shēng rén tiān zhōng","text":"地藏菩萨方便力故，使令解脱，生人天中。"},{"note":"xuán yòu zài rù, ruò yè jié zhòng, yǒng chù dì yù, wú jiě tuō shí","text":"旋又再入，若业结重，永处地狱，无解脱时。”"},{"note":"ěr shí, è dú guǐ wáng hé zhǎng gōng jìng, bái fó yán","text":"尔时，恶毒鬼王合掌恭敬，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ děng zhū guǐ wáng, qí shù wú liàng, zài yán fú tí, huò lì yì rén","text":"我等诸鬼王，其数无量，在阎浮提，或利益人，"},{"note":"huò sǔn hài rén, gè gè bù tóng","text":"或损害人，各各不同。"},{"note":"rán shì yè bào, shǐ wǒ juàn shǔ, yóu xíng shì jiè, duō è shǎo shàn","text":"然是业报，使我眷属，游行世界，多恶少善。"},{"note":"guò rén jiā tíng, huò chéng yì jù luò, zhuāng yuán fáng shě","text":"过人家庭，或城邑聚落，庄园房舍。"},{"note":"huò yǒu nán zi nǚ rén, xiū máo fā shàn shì, nǎi zhì xuán yī fān yī gài","text":"或有男子女人，修毛发善事，乃至悬一旛一盖，"},{"note":"shǎo xiāng shǎo huá, gòng yǎng fó xiàng jí pú sà xiàng, huò zhuǎn dú zūn jīng","text":"少香少华，供养佛像及菩萨像，或转读尊经，"},{"note":"shāo xiāng gòng yǎng yī jù yī jì","text":"烧香供养一句一偈。"},{"note":"wǒ děng guǐ wáng, jìng lǐ shì rén, rú guò qù, xiàn zài, wèi lái zhū fó","text":"我等鬼王，敬礼是人，如过去、现在、未来诸佛。"},{"note":"chì zhū xiǎo guǐ, gè yǒu dà lì, jí tǔ dì fēn, biàn lìng wèi hù","text":"敕诸小鬼，各有大力，及土地分，便令卫护。"},{"note":"bù lìng è shì héng shì, è bìng héng bìng, nǎi zhì bù rú yì shì","text":"不令恶事横事、恶病横病，乃至不如意事，"},{"note":"jìn yú cǐ shě děng chù, hé kuàng rù mén. fó zàn guǐ wáng","text":"近于此舍等处，何况入门？”佛赞鬼王："},{"note":"shàn zāi","text":"“善哉！"},{"note":"shàn zāi","text":"善哉！"},{"note":"rǔ děng jí yǔ yán luó, néng rú shì yōng hù shàn nán nǚ děng, wú yì gào fàn wáng dì shì","text":"汝等及与阎罗，能如是拥护善男女等，吾亦告梵王帝释，"},{"note":"lìng wèi hù rǔ","text":"令卫护汝。”"},{"note":"shuō shì yǔ shí, huì zhōng yǒu yī guǐ wáng, míng yuē zhǔ mìng, bái fó yán","text":"说是语时，会中有一鬼王，名曰主命，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ běn yè yuán, zhǔ yán fú rén mìng, shēng shí sǐ shí, wǒ jiē zhǔ zhī","text":"我本业缘，主阎浮人命，生时死时，我皆主之。"},{"note":"zài wǒ běn yuàn, shèn yù lì yì","text":"在我本愿，甚欲利益。"},{"note":"zì shì zhòng shēng, bù huì wǒ yì, zhì lìng shēng sǐ, jù bù dé ān","text":"自是众生，不会我意，致令生死，俱不得安。”"},{"note":"hé yǐ gù","text":"“何以故？"},{"note":"shì yán fú tí rén, chū shēng zhī shí, bù wèn nán nǚ, huò yù shēng shí","text":"是阎浮提人，初生之时，不问男女，或欲生时，"},{"note":"dàn zuò shàn shì, zēng yì shě zhái","text":"但作善事，增益舍宅。"},{"note":"zì lìng tǔ dì wú liàng huān xǐ, yōng hù zi mǔ, dé dà ān lè","text":"自令土地无量欢喜，拥护子母，得大安乐，"},{"note":"lì yì juàn shǔ","text":"利益眷属。"},{"note":"huò yǐ shēng xià, shèn wù shā hài, qǔ zhū xiān wèi, gōng gěi chǎn mǔ","text":"或已生下，慎勿杀害，取诸鲜味，供给产母。"},{"note":"jí guǎng jù juàn shǔ, yǐn jiǔ shí ròu, gē lè xián guǎn, néng lìng zi mǔ","text":"及广聚眷属，饮酒食肉，歌乐弦管，能令子母，"},{"note":"bù dé ān lè","text":"不得安乐。”"},{"note":"hé yǐ gù","text":"“何以故？"},{"note":"shì chǎn nán shí, yǒu wú shù è guǐ, jí wǎng liǎng jīng mèi, yù shí xīng xuè","text":"是产难时，有无数恶鬼，及魍魉精魅，欲食腥血。"},{"note":"shì wǒ zǎo lìng shě zhái tǔ dì líng qí, hé hù zi mǔ, shǐ lìng ān lè","text":"是我早令舍宅土地灵祁，荷护子母，使令安乐，"},{"note":"ér dé lì yì","text":"而得利益。"},{"note":"rú shì zhī rén, jiàn ān lè gù, biàn hé shè fú, dá zhū tǔ dì","text":"如是之人，见安乐故，便合设福，答诸土地。"},{"note":"fān wèi shā hài, jí jù juàn shǔ, yǐ shì zhī gù, fàn yāng zì shòu","text":"翻为杀害，集聚眷属，以是之故，犯殃自受，"},{"note":"zi mǔ jù sǔn","text":"子母俱损。”"},{"note":"yòu yán fú tí lín mìng zhōng rén, bù wèn shàn è, wǒ yù lìng shì mìng zhōng zhī rén","text":"“又阎浮提临命终人，不问善恶，我欲令是命终之人，"},{"note":"bù luò è dào, hé kuàng zì xiū shàn gēn, zēng wǒ lì gù","text":"不落恶道，何况自修善根，增我力故。"},{"note":"shì yán fú tí xíng shàn zhī rén, lín mìng zhōng shí, yì yǒu bǎi qiān è dào guǐ shén","text":"是阎浮提行善之人，临命终时，亦有百千恶道鬼神，"},{"note":"huò biàn zuò fù mǔ, nǎi zhì zhū juàn shǔ, yǐn jiē wáng rén, lìng luò è dào","text":"或变作父母，乃至诸眷属，引接亡人，令落恶道，"},{"note":"hé kuàng běn zào è zhě","text":"何况本造恶者？”"},{"note":"shì zūn","text":"“世尊！"},{"note":"rú shì yán fú tí nán zi nǚ rén, lín mìng zhōng shí, shén shí hūn mèi","text":"如是阎浮提男子女人，临命终时，神识惛昧，"},{"note":"bù biàn shàn è, nǎi zhì yǎn ěr, gèng wú jiàn wén","text":"不辩善恶，乃至眼耳，更无见闻。"},{"note":"shì zhū juàn shǔ, dāng xū shè dà gòng yǎng, zhuǎn dú zūn jīng, niàn fó pú sà míng hào","text":"是诸眷属，当须设大供养，转读尊经，念佛菩萨名号。"},{"note":"rú shì shàn yuán, néng lìng wáng zhě, lí zhū è dào, zhū mó guǐ shén","text":"如是善缘，能令亡者，离诸恶道，诸魔鬼神，"},{"note":"xī jiē tuì sàn","text":"悉皆退散。"},{"note":"shì zūn","text":"世尊！"},{"note":"yī qiè zhòng shēng lín mìng zhōng shí, ruò dé wén yī fó míng, yī pú sà míng","text":"一切众生临命终时，若得闻一佛名、一菩萨名，"},{"note":"huò dà chéng jīng diǎn yī jù yī jì, wǒ guān rú shì bèi rén, chú wǔ wú jiān shā hài zhī zuì","text":"或大乘经典一句一偈，我观如是辈人，除五无间杀害之罪，"},{"note":"xiǎo xiǎo è yè, hé duò è qù zhě, xún jí jiě tuō","text":"小小恶业，合堕恶趣者，寻即解脱。”"},{"note":"fó gào zhǔ mìng guǐ wáng","text":"佛告主命鬼王："},{"note":"rǔ dà cí gù, néng fā rú shì dà yuàn, yú shēng sǐ zhōng","text":"“汝大慈故，能发如是大愿，于生死中，"},{"note":"hù zhū zhòng shēng","text":"护诸众生。"},{"note":"ruò wèi lái shì zhōng, yǒu nán zi nǚ rén, zhì shēng sǐ shí, rǔ mò tuì shì yuàn","text":"若未来世中，有男子女人，至生死时，汝莫退是愿，"},{"note":"zǒng lìng jiě tuō, yǒng dé ān lè","text":"总令解脱，永得安乐。”"},{"note":"guǐ wáng bái fó yán","text":"鬼王白佛言："},{"note":"yuàn bù yǒu lǜ, wǒ bì shì xíng, niàn niàn yōng hù yán fú zhòng shēng","text":"“愿不有虑，我毕是形，念念拥护阎浮众生，"},{"note":"shēng shí sǐ shí, jù dé ān lè","text":"生时死时，俱得安乐。"},{"note":"dàn yuàn zhū zhòng shēng, yú shēng sǐ shí, xìn shòu wǒ yǔ, wú bù jiě tuō","text":"但愿诸众生，于生死时，信受我语，无不解脱，"},{"note":"huò dà lì yì","text":"获大利益。”"},{"note":"ěr shí, fó gào dì zàng pú sà","text":"尔时，佛告地藏菩萨："},{"note":"shì dà guǐ wáng zhǔ mìng zhě, yǐ céng jīng bǎi qiān shēng, zuò dà guǐ wáng","text":"“是大鬼王主命者，已曾经百千生，作大鬼王，"},{"note":"yú shēng sǐ zhōng, yōng hù zhòng shēng","text":"于生死中，拥护众生。"},{"note":"shì dà shì cí bēi yuàn gù, xiàn dà guǐ shēn, shí fēi guǐ yě","text":"是大士慈悲愿故，现大鬼身，实非鬼也。"},{"note":"què hòu guò yī bǎi qī shí jié, dāng dé chéng fó, hào yuē wú xiāng rú lái","text":"却后过一百七十劫，当得成佛，号曰无相如来，"},{"note":"jié míng ān lè, shì jiè míng jìng zhù, qí fó shòu mìng, bù kě jì jié","text":"劫名安乐，世界名净住，其佛寿命，不可计劫。"},{"note":"dì zàng","text":"地藏！"},{"note":"shì dà guǐ wáng, qí shì rú shì, bù kě sī yì, suǒ dù rén tiān","text":"是大鬼王，其事如是，不可思议，所度人天，"},{"note":"yì bù kě xiàn liàng","text":"亦不可限量。”"}],"ksitigarbha-09":[{"note":"chēng fó míng hào pǐn dì jiǔ","text":"称佛名号品第九"},{"note":"ěr shí, dì zàng pú sà mó hē sà bái fó yán","text":"尔时，地藏菩萨摩诃萨白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ jīn wèi wèi lái zhòng shēng, yǎn lì yì shì, yú shēng sǐ zhōng","text":"我今为未来众生，演利益事，于生死中，"},{"note":"dé dà lì yì","text":"得大利益。"},{"note":"wéi yuàn shì zūn, tīng wǒ shuō zhī","text":"唯愿世尊，听我说之。”"},{"note":"fó gào dì zàng pú sà","text":"佛告地藏菩萨："},{"note":"rǔ jīn yù xīng cí bēi, jiù bá yī qiè zuì kǔ liù dào zhòng shēng","text":"“汝今欲兴慈悲，救拔一切罪苦六道众生，"},{"note":"yǎn bù sī yì shì, jīn zhèng shì shí, wéi dāng sù shuō","text":"演不思议事，今正是时，唯当速说。"},{"note":"wú jí niè pán, shǐ rǔ zǎo bì shì yuàn, wú yì wú yōu xiàn zài wèi lái yī qiè zhòng shēng","text":"吾即涅槃，使汝早毕是愿，吾亦无忧现在未来一切众生。”"},{"note":"dì zàng pú sà bái fó yán","text":"地藏菩萨白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"guò qù wú liàng ā sēng qí jié, yǒu fó chū shì, hào wú biān shēn rú lái","text":"过去无量阿僧祇劫，有佛出世，号无边身如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, zàn shēng gōng jìng, jí dé chāo yuè sì shí jié shēng sǐ zhòng zuì","text":"若有男子女人，闻是佛名，暂生恭敬，即得超越四十劫生死重罪。"},{"note":"hé kuàng sù huà xíng xiàng, gòng yǎng zàn tàn","text":"何况塑画形像、供养赞叹？"},{"note":"qí rén huò fú, wú liàng wú biān","text":"其人获福，无量无边。"},{"note":"yòu yú guò qù héng hé shā jié, yǒu fó chū shì, hào bǎo xìng rú lái","text":"“又于过去恒河沙劫，有佛出世，号宝性如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, yī dàn zhǐ qǐng, fā xīn guī yī","text":"若有男子女人，闻是佛名，一弹指顷，发心归依，"},{"note":"shì rén yú wú shàng dào, yǒng bù tuì zhuǎn","text":"是人于无上道，永不退转。”"},{"note":"yòu yú guò qù, yǒu fó chū shì, hào bō tóu mó shèng rú lái","text":"“又于过去，有佛出世，号波头摩胜如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, lì yú ěr gēn, shì rén dāng dé qiān fǎn shēng yú liù yù tiān zhōng","text":"若有男子女人，闻是佛名，历于耳根，是人当得千返生于六欲天中，"},{"note":"hé kuàng zhì xīn chēng niàn","text":"何况志心称念。”"},{"note":"yòu yú guò qù bù kě shuō bù kě shuō ā sēng qí jié, yǒu fó chū shì","text":"“又于过去不可说不可说阿僧祇劫，有佛出世，"},{"note":"hào shī zi hǒu rú lái","text":"号狮子吼如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, yī niàn guī yī, shì rén dé yù wú liàng zhū fó","text":"若有男子女人，闻是佛名，一念归依，是人得遇无量诸佛，"},{"note":"mó dǐng shòu jì","text":"摩顶授记。”"},{"note":"yòu yú guò qù, yǒu fó chū shì, hào jū liú sūn fó","text":"“又于过去，有佛出世，号拘留孙佛。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, zhì xīn zhān lǐ, huò fù zàn tàn","text":"若有男子女人，闻是佛名，志心瞻礼，或复赞叹，"},{"note":"shì rén yú xián jié qiān fó huì zhōng, wèi dà fàn wáng, dé shòu shàng jì","text":"是人于贤劫千佛会中，为大梵王，得授上记。”"},{"note":"yòu yú guò qù, yǒu fó chū shì, hào pí pó shī fó","text":"“又于过去，有佛出世，号毘婆尸佛。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, yǒng bù duò è dào","text":"若有男子女人，闻是佛名，永不堕恶道，"},{"note":"cháng shēng rén tiān, shòu shèng miào lè","text":"常生人天，受胜妙乐。”"},{"note":"yòu yú guò qù wú liàng wú shù héng hé shā jié, yǒu fó chū shì","text":"“又于过去无量无数恒河沙劫，有佛出世，"},{"note":"hào bǎo shèng rú lái","text":"号宝胜如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, bì jìng bù duò è dào","text":"若有男子女人，闻是佛名，毕竟不堕恶道，"},{"note":"cháng zài tiān shàng, shòu shèng miào lè","text":"常在天上，受胜妙乐。”"},{"note":"yòu yú guò qù, yǒu fó chū shì, hào bǎo xiāng rú lái","text":"“又于过去，有佛出世，号宝相如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng, shēng gōng jìng xīn, shì rén bù jiǔ","text":"若有男子女人，闻是佛名，生恭敬心，是人不久，"},{"note":"dé ā luó hàn guǒ","text":"得阿罗汉果。”"},{"note":"yòu yú guò qù, wú liàng ā sēng qí jié, yǒu fó chū shì","text":"“又于过去，无量阿僧祇劫，有佛出世，"},{"note":"hào jiā shā chuáng rú lái","text":"号袈裟幢如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng zhě, chāo yī bǎi dà jié shēng sǐ zhī zuì","text":"若有男子女人，闻是佛名者，超一百大劫生死之罪。”"},{"note":"yòu yú guò qù, yǒu fó chū shì, hào dà tōng shān wáng rú lái","text":"“又于过去，有佛出世，号大通山王如来。"},{"note":"ruò yǒu nán zi nǚ rén, wén shì fó míng zhě, shì rén dé yù héng hé shā fó","text":"若有男子女人，闻是佛名者，是人得遇恒河沙佛，"},{"note":"guǎng wèi shuō fǎ, bì chéng pú tí","text":"广为说法，必成菩提。”"},{"note":"yòu yú guò qù, yǒu jìng yuè fó, shān wáng fó, zhì shèng fó","text":"“又于过去，有净月佛、山王佛、智胜佛、"},{"note":"jìng míng wáng fó, zhì chéng jiù fó, wú shàng fó, miào shēng fó","text":"净名王佛、智成就佛、无上佛、妙声佛、"},{"note":"mǎn yuè fó, yuè miàn fó, yǒu rú shì děng bù kě shuō fó","text":"满月佛、月面佛，有如是等不可说佛。"},{"note":"shì zūn","text":"世尊！"},{"note":"xiàn zài wèi lái yī qiè zhòng shēng, ruò tiān ruò rén, ruò nán ruò nǚ","text":"现在未来一切众生，若天若人，若男若女，"},{"note":"dàn niàn dé yī fó míng hào, gōng dé wú liàng, hé kuàng duō míng","text":"但念得一佛名号，功德无量，何况多名？"},{"note":"shì zhòng shēng děng, shēng shí sǐ shí, zì dé dà lì, zhōng bù duò è dào","text":"是众生等，生时死时，自得大利，终不堕恶道。"},{"note":"ruò yǒu lín mìng zhōng rén, jiā zhōng juàn shǔ, nǎi zhì yī rén, wèi shì bìng rén","text":"若有临命终人，家中眷属，乃至一人，为是病人，"},{"note":"gāo shēng niàn yī fó míng, shì mìng zhōng rén, chú wǔ wú jiān zuì","text":"高声念一佛名，是命终人，除五无间罪，"},{"note":"yú yè bào děng, xī dé xiāo miè","text":"馀业报等，悉得销灭。"},{"note":"shì wǔ wú jiān zuì, suī zhì jí zhòng, dòng jīng yì jié, le bù dé chū","text":"是五无间罪，虽至极重，动经亿劫，了不得出，"},{"note":"chéng sī lín mìng zhōng shí, tā rén wèi qí chēng niàn fó míng, yú shì zuì zhōng yì jiàn xiāo miè","text":"承斯临命终时，他人为其称念佛名，于是罪中亦渐销灭。"},{"note":"hé kuàng zhòng shēng, zì chēng zì niàn, huò fú wú liàng, miè wú liàng zuì","text":"何况众生，自称自念，获福无量，灭无量罪。”"},{"note":"dì zàng pú sà běn yuàn jīng juǎn zhōng","text":"地藏菩萨本愿经卷中"},{"note":"zàn","text":"赞"},{"note":"pǔ xián qǐ wèn, dì zàng hóng kāi, sān tú liù dào jué chén āi","text":"普贤启问，地藏宏开，三途六道绝尘埃，"},{"note":"pǔ guǎng wèn rú lái, shòu jì shí zhāi, jiē yǐn shàng lián tái","text":"普广问如来，授记十斋，接引上莲台。"},{"note":"nā mó cháng zhù shí fāng fǎ sān chēng","text":"南无常住十方法（三称）"}],"ksitigarbha-10":[{"note":"xiào liàng bù shī gōng dé yuán pǐn dì shí","text":"校量布施功德缘品第十"},{"note":"ěr shí, dì zàng pú sà mó hē sà chéng fó wēi shén, cóng zuò ér qǐ","text":"尔时，地藏菩萨摩诃萨承佛威神，从座而起，"},{"note":"hú guì hé zhǎng, bái fó yán","text":"胡跪合掌，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ guān yè dào zhòng shēng, xiào liàng bù shī, yǒu qīng yǒu zhòng","text":"我观业道众生，校量布施，有轻有重："},{"note":"yǒu yī shēng shòu fú, yǒu shí shēng shòu fú, yǒu bǎi shēng qiān shēng shòu dà fú lì zhě","text":"有一生受福，有十生受福，有百生千生受大福利者。"},{"note":"shì shì yún hé","text":"是事云何？"},{"note":"wéi yuàn shì zūn, wèi wǒ shuō zhī","text":"唯愿世尊，为我说之。”"},{"note":"ěr shí, fó gào dì zàng pú sà","text":"尔时，佛告地藏菩萨："},{"note":"wú jīn yú dāo lì tiān gōng, yī qiè zhòng huì, shuō yán fú tí bù shī xiào liàng gōng dé qīng zhòng","text":"“吾今于忉利天宫，一切众会，说阎浮提布施校量功德轻重。"},{"note":"rǔ dāng dì tīng, wú wèi rǔ shuō","text":"汝当谛听，吾为汝说。”"},{"note":"dì zàng bái fó yán","text":"地藏白佛言："},{"note":"wǒ yí shì shì, yuàn lè yù wén","text":"“我疑是事，愿乐欲闻。”"},{"note":"fó gào dì zàng pú sà","text":"佛告地藏菩萨："},{"note":"nán yán fú tí, yǒu zhū guó wáng, zǎi fǔ dà chén, dà zhǎng zhě","text":"“南阎浮提，有诸国王、宰辅大臣、大长者、"},{"note":"dà shā lì, dà pó luó mén děng, ruò yù zuì xià pín qióng, nǎi zhì lóng cán yīn yǎ","text":"大刹利、大婆罗门等，若遇最下贫穷，乃至癃残喑痖，"},{"note":"lóng chī wú mù, rú shì zhǒng zhǒng bù wán jù zhě","text":"聋痴无目，如是种种不完具者。"},{"note":"shì dà guó wáng děng, yù bù shī shí, ruò néng jù dà cí bēi","text":"是大国王等，欲布施时，若能具大慈悲，"},{"note":"xià xīn hán xiào, qīn shǒu biàn bù shī, huò shǐ rén shī, ruǎn yán wèi yù","text":"下心含笑，亲手遍布施，或使人施，软言慰谕。"},{"note":"shì guó wáng děng, suǒ huò fú lì, rú bù shī bǎi héng hé shā fó gōng dé zhī lì","text":"是国王等，所获福利，如布施百恒河沙佛功德之利。"},{"note":"hé yǐ gù","text":"何以故？"},{"note":"yuán shì guó wáng děng, yú shì zuì pín jiàn bèi, jí bù wán jù zhě","text":"缘是国王等，于是最贫贱辈，及不完具者，"},{"note":"fā dà cí xīn, shì gù fú lì, yǒu rú cǐ bào","text":"发大慈心，是故福利，有如此报："},{"note":"bǎi qiān shēng zhōng, cháng dé qī bǎo jù zú, hé kuàng yī shí shòu yòng","text":"百千生中，常得七宝具足，何况衣食受用。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"ruò wèi lái shì, yǒu zhū guó wáng, zhì pó luó mén děng, yù fó tǎ sì","text":"若未来世，有诸国王，至婆罗门等，遇佛塔寺，"},{"note":"huò fó xíng xiàng, nǎi zhì pú sà, shēng wén, pì zhī fó xiàng","text":"或佛形像，乃至菩萨、声闻、辟支佛像，"},{"note":"gōng zì yíng bàn, gòng yǎng bù shī","text":"躬自营办，供养布施。"},{"note":"shì guó wáng děng, dāng dé sān jié wèi dì shì shēn, shòu shèng miào lè","text":"是国王等，当得三劫为帝释身，受胜妙乐。"},{"note":"ruò néng yǐ cǐ bù shī fú lì, huí xiàng fǎ jiè, shì dà guó wáng děng","text":"若能以此布施福利，回向法界，是大国王等，"},{"note":"yú shí jié zhōng, cháng wèi dà fàn tiān wáng","text":"于十劫中，常为大梵天王。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"ruò wèi lái shì, yǒu zhū guó wáng, zhì pó luó mén děng, yù xiān fó tǎ miào","text":"若未来世，有诸国王，至婆罗门等，遇先佛塔庙，"},{"note":"huò zhì jīng xiàng, huǐ huài pò luò, nǎi néng fā xīn xiū bǔ","text":"或至经像，毁坏破落，乃能发心修补。"},{"note":"shì guó wáng děng, huò zì yíng bàn, huò quàn tā rén, nǎi zhì bǎi qiān rén děng","text":"是国王等，或自营办，或劝他人，乃至百千人等，"},{"note":"bù shī jié yuán","text":"布施结缘。"},{"note":"shì guó wáng děng, bǎi qiān shēng zhōng, cháng wèi zhuǎn lún wáng shēn","text":"是国王等，百千生中，常为转轮王身。"},{"note":"rú shì tā rén tóng bù shī zhě, bǎi qiān shēng zhōng, cháng wèi xiǎo guó wáng shēn","text":"如是他人同布施者，百千生中，常为小国王身。"},{"note":"gèng néng yú tǎ miào qián, fā huí xiàng xīn, rú shì guó wáng, nǎi jí zhū rén","text":"更能于塔庙前，发回向心，如是国王，乃及诸人，"},{"note":"jǐn chéng fó dào, yǐ cǐ guǒ bào, wú liàng wú biān","text":"尽成佛道，以此果报，无量无边。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"wèi lái shì zhōng, yǒu zhū guó wáng, jí pó luó mén děng, jiàn zhū lǎo bìng","text":"未来世中，有诸国王，及婆罗门等，见诸老病，"},{"note":"jí shēng chǎn fù nǚ, ruò yī niàn jiān, jù dà cí xīn, bù shī yī yào","text":"及生产妇女，若一念间，具大慈心，布施医药、"},{"note":"yǐn shí, wò jù, shǐ lìng ān lè","text":"饮食、卧具，使令安乐。"},{"note":"rú shì fú lì, zuì bù sī yì","text":"如是福利，最不思议："},{"note":"yī bǎi jié zhōng, cháng wèi jìng jū tiān zhǔ","text":"一百劫中，常为净居天主；"},{"note":"èr bǎi jié zhōng, cháng wèi liù yù tiān zhǔ","text":"二百劫中，常为六欲天主；"},{"note":"bì jìng chéng fó, yǒng bù duò è dào, nǎi zhì bǎi qiān shēng zhōng","text":"毕竟成佛，永不堕恶道，乃至百千生中，"},{"note":"ěr bù wén kǔ shēng","text":"耳不闻苦声。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"ruò wèi lái shì zhōng, yǒu zhū guó wáng, jí pó luó mén děng, néng zuò rú shì bù shī","text":"若未来世中，有诸国王，及婆罗门等，能作如是布施，"},{"note":"huò fú wú liàng, gèng néng huí xiàng, bù wèn duō shǎo, bì jìng chéng fó","text":"获福无量，更能回向，不问多少，毕竟成佛，"},{"note":"hé kuàng shì fàn zhuǎn lún zhī bào","text":"何况释梵转轮之报。"},{"note":"shì gù, dì zàng","text":"是故，地藏！"},{"note":"pǔ quàn zhòng shēng, dāng rú shì xué","text":"普劝众生，当如是学。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"wèi lái shì zhōng, ruò shàn nán zi, shàn nǚ rén, yú fó fǎ zhōng","text":"未来世中，若善男子、善女人，于佛法中，"},{"note":"zhǒng shǎo shàn gēn, máo fā shā chén děng xǔ, suǒ shòu fú lì, bù kě wèi yù","text":"种少善根，毛发沙尘等许，所受福利，不可为谕。"},{"note":"fù cì, dì zàng","text":"复次，地藏！"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, yù fó xíng xiàng","text":"未来世中，若有善男子、善女人，遇佛形像、"},{"note":"pú sà xíng xiàng, pì zhī fó xíng xiàng, zhuǎn lún wáng xíng xiàng, bù shī gòng yǎng","text":"菩萨形像、辟支佛形像、转轮王形像，布施供养，"},{"note":"dé wú liàng fú, cháng zài rén tiān, shòu shèng miào lè","text":"得无量福，常在人天，受胜妙乐。"},{"note":"ruò néng huí xiàng fǎ jiè, shì rén fú lì, bù kě wèi yù","text":"若能回向法界，是人福利，不可为谕。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, yù dà chéng jīng diǎn","text":"未来世中，若有善男子、善女人，遇大乘经典，"},{"note":"huò tīng wén yī jì yī jù, fā yīn zhòng xīn, zàn tàn gōng jìng","text":"或听闻一偈一句，发殷重心，赞叹恭敬，"},{"note":"bù shī gòng yǎng","text":"布施供养。"},{"note":"shì rén huò dà guǒ bào, wú liàng wú biān","text":"是人获大果报，无量无边。"},{"note":"ruò néng huí xiàng fǎ jiè, qí fú bù kě wèi yù","text":"若能回向法界，其福不可为谕。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"ruò wèi lái shì zhōng, yǒu shàn nán zi, shàn nǚ rén, yù fó tǎ sì","text":"若未来世中，有善男子、善女人，遇佛塔寺、"},{"note":"dà chéng jīng diǎn, xīn zhě bù shī gòng yǎng, zhān lǐ zàn tàn, gōng jìng hé zhǎng","text":"大乘经典，新者布施供养，瞻礼赞叹，恭敬合掌；"},{"note":"ruò yù gù zhě huò huǐ huài zhě, xiū bǔ yíng lǐ, huò dú fā xīn","text":"若遇故者或毁坏者，修补营理，或独发心，"},{"note":"huò quàn duō rén tóng gòng fā xīn","text":"或劝多人同共发心。"},{"note":"rú shì děng bèi, sān shí shēng zhōng, cháng wèi zhū xiǎo guó wáng","text":"如是等辈，三十生中，常为诸小国王。"},{"note":"tán yuè zhī rén, cháng wèi lún wáng, hái yǐ shàn fǎ, jiào huà zhū xiǎo guó wáng","text":"檀越之人，常为轮王，还以善法，教化诸小国王。”"},{"note":"fù cì, dì zàng","text":"“复次，地藏！"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, yú fó fǎ zhōng","text":"未来世中，若有善男子、善女人，于佛法中，"},{"note":"suǒ zhǒng shàn gēn, huò bù shī gòng yǎng, huò xiū bǔ tǎ sì, huò zhuāng lǐ jīng diǎn","text":"所种善根，或布施供养，或修补塔寺，或装理经典，"},{"note":"nǎi zhì yī máo yī chén, yī shā yī dì","text":"乃至一毛一尘，一沙一渧。"},{"note":"rú shì shàn shì, dàn néng huí xiàng fǎ jiè, shì rén gōng dé, bǎi qiān shēng zhōng","text":"如是善事，但能回向法界，是人功德，百千生中，"},{"note":"shòu shàng miào lè","text":"受上妙乐。"},{"note":"rú dàn huí xiàng zì jiā juàn shǔ, huò zì shēn lì yì, rú shì zhī guǒ","text":"如但回向自家眷属，或自身利益，如是之果，"},{"note":"jí sān shēng shòu lè, shě yī dé wàn bào","text":"即三生受乐，舍一得万报。"},{"note":"shì gù, dì zàng","text":"是故，地藏！"},{"note":"bù shī yīn yuán, qí shì rú shì","text":"布施因缘，其事如是。”"}],"ksitigarbha-11":[{"note":"dì shén hù fǎ pǐn dì shí yī","text":"地神护法品第十一"},{"note":"ěr shí, jiān láo dì shén bái fó yán","text":"尔时，坚牢地神白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ cóng xī lái, zhān shì dǐng lǐ wú liàng pú sà mó hē sà, jiē shì dà bù kě sī yì shén tōng zhì huì","text":"我从昔来，瞻视顶礼无量菩萨摩诃萨，皆是大不可思议神通智慧，"},{"note":"guǎng dù zhòng shēng","text":"广度众生。"},{"note":"shì dì zàng pú sà mó hē sà, yú zhū pú sà, shì yuàn shēn zhòng","text":"是地藏菩萨摩诃萨，于诸菩萨，誓愿深重。"},{"note":"shì zūn","text":"世尊！"},{"note":"shì dì zàng pú sà, yú yán fú tí, yǒu dà yīn yuán","text":"是地藏菩萨，于阎浮提，有大因缘。"},{"note":"rú wén shū, pǔ xián, guān yīn, mí lè, yì huà bǎi qiān shēn xíng","text":"如文殊、普贤、观音、弥勒，亦化百千身形，"},{"note":"dù yú liù dào, qí yuàn shàng yǒu bì jìng","text":"度于六道，其愿尚有毕竟。"},{"note":"shì dì zàng pú sà, jiào huà liù dào yī qiè zhòng shēng, suǒ fā shì yuàn jié shù","text":"是地藏菩萨，教化六道一切众生，所发誓愿劫数，"},{"note":"rú qiān bǎi yì héng hé shā","text":"如千百亿恒河沙。”"},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ guān wèi lái jí xiàn zài zhòng shēng, yú suǒ zhù chù, yú nán fāng qīng jié zhī dì","text":"我观未来及现在众生，于所住处，于南方清洁之地，"},{"note":"yǐ tǔ shí zhú mù, zuò qí kān shì","text":"以土石竹木，作其龛室。"},{"note":"shì zhōng néng sù huà, nǎi zhì jīn yín tóng tiě, zuò dì zàng xíng xiàng","text":"是中能塑画，乃至金银铜铁，作地藏形像，"},{"note":"shāo xiāng gòng yǎng, zhān lǐ zàn tàn","text":"烧香供养，瞻礼赞叹。"},{"note":"shì rén jū chù, jí dé shí zhǒng lì yì","text":"是人居处，即得十种利益。"},{"note":"hé děng wèi shí","text":"何等为十？"},{"note":"yī zhě, tǔ dì fēng rǎng","text":"一者，土地丰壤。"},{"note":"èr zhě, jiā zhái yǒng ān","text":"二者，家宅永安。"},{"note":"sān zhě, xiān wáng shēng tiān","text":"三者，先亡生天。"},{"note":"sì zhě, xiàn cún yì shòu","text":"四者，现存益寿。"},{"note":"wǔ zhě, suǒ qiú suì yì","text":"五者，所求遂意。"},{"note":"liù zhě, wú shuǐ huǒ zāi","text":"六者，无水火灾。"},{"note":"qī zhě, xū hào pì chú","text":"七者，虚耗辟除。"},{"note":"bā zhě, dù jué è mèng","text":"八者，杜绝恶梦。"},{"note":"jiǔ zhě, chū rù shén hù","text":"九者，出入神护。"},{"note":"shí zhě, duō yù shèng yīn","text":"十者，多遇圣因。”"},{"note":"shì zūn","text":"“世尊！"},{"note":"wèi lái shì zhōng, jí xiàn zài zhòng shēng, ruò néng yú suǒ zhù chù fāng miàn","text":"未来世中，及现在众生，若能于所住处方面，"},{"note":"zuò rú shì gòng yǎng, dé rú shì lì yì","text":"作如是供养，得如是利益。”"},{"note":"fù bái fó yán","text":"复白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, yú suǒ zhù chù","text":"未来世中，若有善男子、善女人，于所住处，"},{"note":"yǒu cǐ jīng diǎn jí pú sà xiàng, shì rén gèng néng zhuǎn dú jīng diǎn","text":"有此经典及菩萨像，是人更能转读经典，"},{"note":"gòng yǎng pú sà","text":"供养菩萨。"},{"note":"wǒ cháng rì yè, yǐ běn shén lì, wèi hù shì rén, nǎi zhì shuǐ huǒ dào zéi","text":"我常日夜，以本神力，卫护是人，乃至水火盗贼，"},{"note":"dà héng xiǎo héng, yī qiè è shì, xī jiē xiāo miè","text":"大横小横，一切恶事，悉皆消灭。”"},{"note":"fó gào jiān láo dì shén","text":"佛告坚牢地神："},{"note":"rǔ dà shén lì, zhū shén shǎo jí","text":"“汝大神力，诸神少及。"},{"note":"hé yǐ gù","text":"何以故？"},{"note":"yán fú tǔ dì, xī méng rǔ hù","text":"阎浮土地，悉蒙汝护。"},{"note":"nǎi zhì cǎo mù shā shí, dào má zhú wěi, gǔ mǐ bǎo bèi, cóng dì ér yǒu","text":"乃至草木沙石，稻麻竹苇，谷米宝贝，从地而有，"},{"note":"jiē yīn rǔ lì","text":"皆因汝力。"},{"note":"yòu cháng chēng yáng dì zàng pú sà lì yì zhī shì, rǔ zhī gōng dé","text":"又常称扬地藏菩萨利益之事，汝之功德，"},{"note":"jí yǐ shén tōng, bǎi qiān bèi yú cháng fēn dì shén","text":"及以神通，百千倍于常分地神。"},{"note":"ruò wèi lái shì zhōng, yǒu shàn nán zi, shàn nǚ rén, gòng yǎng pú sà","text":"若未来世中，有善男子、善女人，供养菩萨，"},{"note":"jí zhuǎn dú shì jīng, dàn yī dì zàng běn yuàn jīng yī shì xiū xíng zhě","text":"及转读是经，但依地藏本愿经一事修行者，"},{"note":"rǔ yǐ běn shén lì, ér yōng hù zhī","text":"汝以本神力，而拥护之。"},{"note":"wù lìng yī qiè zāi hài, jí bù rú yì shì, zhé wén yú ěr","text":"勿令一切灾害，及不如意事，辄闻于耳，"},{"note":"hé kuàng lìng shòu","text":"何况令受？"},{"note":"fēi dàn rǔ dú hù shì rén gù, yì yǒu shì fàn juàn shǔ, zhū tiān juàn shǔ","text":"非但汝独护是人故，亦有释梵眷属、诸天眷属，"},{"note":"yōng hù shì rén","text":"拥护是人。"},{"note":"hé gù dé rú shì shèng xián yōng hù","text":"何故得如是圣贤拥护？"},{"note":"jiē yóu zhān lǐ dì zàng xíng xiàng, jí zhuǎn dú shì běn yuàn jīng gù","text":"皆由瞻礼地藏形像，及转读是本愿经故。"},{"note":"zì rán bì jìng chū lí kǔ hǎi, zhèng niè pán lè","text":"自然毕竟出离苦海，证涅槃乐。"},{"note":"yǐ shì zhī gù, dé dà yōng hù","text":"以是之故，得大拥护。”"}],"ksitigarbha-12":[{"note":"jiàn wén lì yì pǐn dì shí èr","text":"见闻利益品第十二"},{"note":"ěr shí, shì zūn cóng dǐng mén shàng, fàng bǎi qiān wàn yì dà háo xiāng guāng suǒ wèi bái háo xiāng guāng","text":"尔时，世尊从顶门上，放百千万亿大毫相光——所谓白毫相光、"},{"note":"dà bái háo xiāng guāng, ruì háo xiāng guāng, dà ruì háo xiāng guāng, yù háo xiāng guāng","text":"大白毫相光、瑞毫相光、大瑞毫相光、玉毫相光、"},{"note":"dà yù háo xiāng guāng, zǐ háo xiāng guāng, dà zǐ háo xiāng guāng, qīng háo xiāng guāng","text":"大玉毫相光、紫毫相光、大紫毫相光、青毫相光、"},{"note":"dà qīng háo xiāng guāng, bì háo xiāng guāng, dà bì háo xiāng guāng, hóng háo xiāng guāng","text":"大青毫相光、碧毫相光、大碧毫相光、红毫相光、"},{"note":"dà hóng háo xiāng guāng, lǜ háo xiāng guāng, dà lǜ háo xiāng guāng, jīn háo xiāng guāng","text":"大红毫相光、绿毫相光、大绿毫相光、金毫相光、"},{"note":"dà jīn háo xiāng guāng, qìng yún háo xiāng guāng, dà qìng yún háo xiāng guāng","text":"大金毫相光、庆云毫相光、大庆云毫相光、"},{"note":"qiān lún háo guāng, dà qiān lún háo guāng, bǎo lún háo guāng, dà bǎo lún háo guāng","text":"千轮毫光、大千轮毫光、宝轮毫光、大宝轮毫光、"},{"note":"rì lún háo guāng, dà rì lún háo guāng, yuè lún háo guāng, dà yuè lún háo guāng","text":"日轮毫光、大日轮毫光、月轮毫光、大月轮毫光、"},{"note":"gōng diàn háo guāng, dà gōng diàn háo guāng, hǎi yún háo guāng, dà hǎi yún háo guāng","text":"宫殿毫光、大宫殿毫光、海云毫光、大海云毫光。"},{"note":"yú dǐng mén shàng, fàng rú shì děng háo xiāng guāng yǐ, chū wēi miào yīn","text":"于顶门上，放如是等毫相光已，出微妙音，"},{"note":"gào zhū dà zhòng, tiān lóng bā bù, rén, fēi rén děng","text":"告诸大众、天龙八部、人、非人等："},{"note":"tīng wú jīn rì yú dāo lì tiān gōng, chēng yáng zàn tàn dì zàng pú sà yú rén tiān zhōng lì yì děng shì","text":"“听吾今日于忉利天宫，称扬赞叹地藏菩萨于人天中利益等事、"},{"note":"bù sī yì shì, chāo shèng yīn shì, zhèng shí dì shì, bì jìng bù tuì ā nòu duō luó sān miǎo sān pú tí shì","text":"不思议事、超圣因事、证十地事、毕竟不退阿耨多罗三藐三菩提事。”"},{"note":"shuō shì yǔ shí, huì zhōng yǒu yī pú sà mó hē sà, míng guān shì yīn","text":"说是语时，会中有一菩萨摩诃萨，名观世音，"},{"note":"cóng zuò ér qǐ, hú guì hé zhǎng, bái fó yán","text":"从座而起，胡跪合掌，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"shì dì zàng pú sà mó hē sà, jù dà cí bēi, lián mǐn zuì kǔ zhòng shēng","text":"是地藏菩萨摩诃萨，具大慈悲，怜愍罪苦众生，"},{"note":"yú qiān wàn yì shì jiè, huà qiān wàn yì shēn","text":"于千万亿世界，化千万亿身。"},{"note":"suǒ yǒu gōng dé, jí bù sī yì wēi shén zhī lì, wǒ wén shì zūn yǔ shí fāng wú liàng zhū fó","text":"所有功德，及不思议威神之力，我闻世尊与十方无量诸佛，"},{"note":"yì kǒu tóng yīn, zàn tàn dì zàng pú sà yún","text":"异口同音，赞叹地藏菩萨云："},{"note":"zhèng shǐ guò qù xiàn zài wèi lái zhū fó, shuō qí gōng dé, yóu bù néng jǐn","text":"正使过去现在未来诸佛，说其功德，犹不能尽。"},{"note":"xiàng zhě, yòu méng shì zūn pǔ gào dà zhòng, yù chēng yáng dì zàng lì yì děng shì","text":"向者，又蒙世尊普告大众，欲称扬地藏利益等事。"},{"note":"wéi yuàn shì zūn, wèi xiàn zài wèi lái yī qiè zhòng shēng, chēng yáng dì zàng bù sī yì shì","text":"唯愿世尊，为现在未来一切众生，称扬地藏不思议事，"},{"note":"lìng tiān lóng bā bù, zhān lǐ huò fú","text":"令天龙八部，瞻礼获福。”"},{"note":"fó gào guān shì yīn pú sà","text":"佛告观世音菩萨："},{"note":"rǔ yú suō pó shì jiè, yǒu dà yīn yuán","text":"“汝于娑婆世界，有大因缘。"},{"note":"ruò tiān ruò lóng, ruò nán ruò nǚ, ruò shén ruò guǐ, nǎi zhì liù dào zuì kǔ zhòng shēng","text":"若天若龙、若男若女、若神若鬼，乃至六道罪苦众生，"},{"note":"wén rǔ míng zhě, jiàn rǔ xíng zhě, liàn mù rǔ zhě, zàn tàn rǔ zhě","text":"闻汝名者、见汝形者、恋慕汝者、赞叹汝者，"},{"note":"shì zhū zhòng shēng, yú wú shàng dào, bì bù tuì zhuǎn, cháng shēng rén tiān","text":"是诸众生，于无上道，必不退转，常生人天，"},{"note":"jù shòu miào lè, yīn guǒ jiāng shú, yù fó shòu jì","text":"具受妙乐，因果将熟，遇佛授记。"},{"note":"rǔ jīn jù dà cí bēi, lián mǐn zhòng shēng, jí tiān lóng bā bù","text":"汝今具大慈悲，怜愍众生，及天龙八部，"},{"note":"tīng wú xuān shuō dì zàng pú sà bù sī yì lì yì zhī shì","text":"听吾宣说地藏菩萨不思议利益之事。"},{"note":"rǔ dāng dì tīng, wú jīn shuō zhī","text":"汝当谛听，吾今说之。”"},{"note":"guān shì yīn yán","text":"观世音言："},{"note":"wéi rán, shì zūn","text":"“唯然，世尊！"},{"note":"yuàn lè yù wén","text":"愿乐欲闻。”"},{"note":"fó gào guān shì yīn pú sà","text":"佛告观世音菩萨："},{"note":"wèi lái xiàn zài zhū shì jiè zhōng, yǒu tiān rén shòu tiān fú jǐn","text":"“未来现在诸世界中，有天人受天福尽，"},{"note":"yǒu wǔ shuāi xiāng xiàn, huò yǒu duò yú è dào zhī zhě","text":"有五衰相现，或有堕于恶道之者。"},{"note":"rú shì tiān rén, ruò nán ruò nǚ, dāng xiàn xiāng shí, huò jiàn dì zàng pú sà xíng xiàng","text":"如是天人，若男若女，当现相时，或见地藏菩萨形像，"},{"note":"huò wén dì zàng pú sà míng, yī zhān yī lǐ, shì zhū tiān rén","text":"或闻地藏菩萨名，一瞻一礼，是诸天人，"},{"note":"zhuǎn zēng tiān fú, shòu dà kuài lè, yǒng bù duò sān è dào bào","text":"转增天福，受大快乐，永不堕三恶道报。"},{"note":"hé kuàng jiàn wén pú sà, yǐ zhū xiāng, huá, yī fú, yǐn shí","text":"何况见闻菩萨，以诸香、华、衣服、饮食、"},{"note":"bǎo bèi, yīng luò, bù shī gòng yǎng, suǒ huò gōng dé fú lì","text":"宝贝、璎珞，布施供养，所获功德福利，"},{"note":"wú liàng wú biān","text":"无量无边。”"},{"note":"fù cì, guān shì yīn","text":"“复次，观世音！"},{"note":"ruò wèi lái xiàn zài zhū shì jiè zhōng, liù dào zhòng shēng, lín mìng zhōng shí","text":"若未来现在诸世界中，六道众生，临命终时，"},{"note":"dé wén dì zàng pú sà míng, yī shēng lì ěr gēn zhě, shì zhū zhòng shēng","text":"得闻地藏菩萨名，一声历耳根者，是诸众生，"},{"note":"yǒng bù lì sān è dào kǔ","text":"永不历三恶道苦。"},{"note":"hé kuàng lín mìng zhōng shí, fù mǔ juàn shǔ, jiāng shì mìng zhōng rén shě zhái","text":"何况临命终时，父母眷属，将是命终人舍宅、"},{"note":"cái wù, bǎo bèi, yī fú, sù huà dì zàng xíng xiàng","text":"财物、宝贝、衣服，塑画地藏形像。"},{"note":"huò shǐ bìng rén wèi zhōng zhī shí, yǎn ěr jiàn wén, zhī dào juàn shǔ jiāng shě zhái bǎo bèi děng","text":"或使病人未终之时，眼耳见闻，知道眷属将舍宅宝贝等，"},{"note":"wèi qí zì shēn, sù huà dì zàng pú sà xíng xiàng","text":"为其自身，塑画地藏菩萨形像。"},{"note":"shì rén ruò shì yè bào hé shòu zhòng bìng zhě, chéng sī gōng dé, xún jí chú yù","text":"是人若是业报合受重病者，承斯功德，寻即除愈，"},{"note":"shòu mìng zēng yì","text":"寿命增益。"},{"note":"shì rén ruò shì yè bào mìng jǐn, yīng yǒu yī qiè zuì zhàng yè zhàng","text":"是人若是业报命尽，应有一切罪障业障，"},{"note":"hé duò è qù zhě, chéng sī gōng dé, mìng zhōng zhī hòu, jí shēng rén tiān","text":"合堕恶趣者，承斯功德，命终之后，即生人天，"},{"note":"shòu shèng miào lè, yī qiè zuì zhàng, xī jiē xiāo miè","text":"受胜妙乐，一切罪障，悉皆销灭。”"},{"note":"fù cì, guān shì yīn pú sà","text":"“复次，观世音菩萨！"},{"note":"ruò wèi lái shì, yǒu nán zi nǚ rén, huò rǔ bǔ shí, huò sān suì","text":"若未来世，有男子女人，或乳哺时，或三岁、"},{"note":"wǔ suì, shí suì yǐ xià, wáng shī fù mǔ, nǎi jí wáng shī xiōng dì zǐ mèi","text":"五岁、十岁已下，亡失父母，乃及亡失兄弟姊妹。"},{"note":"shì rén nián jì zhǎng dà, sī yì fù mǔ, jí zhū juàn shǔ, bù zhī luò zài hé qù","text":"是人年既长大，思忆父母，及诸眷属，不知落在何趣？"},{"note":"shēng hé shì jiè","text":"生何世界？"},{"note":"shēng hé tiān zhōng","text":"生何天中？"},{"note":"shì rén ruò néng sù huà dì zàng pú sà xíng xiàng, nǎi zhì wén míng","text":"是人若能塑画地藏菩萨形像，乃至闻名，"},{"note":"yī zhān yī lǐ, yī rì zhì qī rì, mò tuì chū xīn, wén míng jiàn xíng","text":"一瞻一礼，一日至七日，莫退初心，闻名见形，"},{"note":"zhān lǐ gòng yǎng","text":"瞻礼供养。"},{"note":"shì rén juàn shǔ, jiǎ yīn yè gù, duò è qù zhě, jì dāng jié shù","text":"是人眷属，假因业故，堕恶趣者，计当劫数，"},{"note":"chéng sī nán nǚ xiōng dì zǐ mèi sù huà dì zàng xíng xiàng, zhān lǐ gōng dé","text":"承斯男女兄弟姊妹塑画地藏形像、瞻礼功德，"},{"note":"xún jí jiě tuō, shēng rén tiān zhōng, shòu shèng miào lè","text":"寻即解脱，生人天中，受胜妙乐；"},{"note":"shì rén juàn shǔ, rú yǒu fú lì, yǐ shēng rén tiān, shòu shèng miào lè zhě","text":"是人眷属，如有福力，已生人天，受胜妙乐者，"},{"note":"jí chéng sī gōng dé, zhuǎn zēng shèng yīn, shòu wú liàng lè","text":"即承斯功德，转增圣因，受无量乐。"},{"note":"shì rén gèng néng sān qī rì zhōng, yī xīn zhān lǐ dì zàng xíng xiàng","text":"是人更能三七日中，一心瞻礼地藏形像，"},{"note":"niàn qí míng zì, mǎn yú wàn biàn","text":"念其名字，满于万遍。"},{"note":"dāng dé pú sà xiàn wú biān shēn, jù gào shì rén juàn shǔ shēng jiè","text":"当得菩萨现无边身，具告是人眷属生界；"},{"note":"huò yú mèng zhōng, pú sà xiàn dà shén lì, qīn lǐng shì rén yú zhū shì jiè","text":"或于梦中，菩萨现大神力，亲领是人于诸世界，"},{"note":"jiàn zhū juàn shǔ","text":"见诸眷属。"},{"note":"gèng néng měi rì, niàn pú sà míng qiān biàn, zhì yú qiān rì","text":"更能每日，念菩萨名千遍，至于千日。"},{"note":"shì rén dāng dé pú sà qiǎn suǒ zài tǔ dì guǐ shén, zhōng shēn wèi hù","text":"是人当得菩萨遣所在土地鬼神，终身卫护，"},{"note":"xiàn shì yī shí fēng yì, wú zhū jí kǔ, nǎi zhì héng shì bù rù qí mén","text":"现世衣食丰溢，无诸疾苦，乃至横事不入其门，"},{"note":"hé kuàng jí shēn","text":"何况及身？"},{"note":"shì rén bì jìng dé pú sà mó dǐng shòu jì","text":"是人毕竟得菩萨摩顶授记。”"},{"note":"fù cì, guān shì yīn pú sà","text":"“复次，观世音菩萨！"},{"note":"ruò wèi lái shì, yǒu shàn nán zi, shàn nǚ rén, yù fā guǎng dà cí xīn","text":"若未来世，有善男子、善女人，欲发广大慈心，"},{"note":"jiù dù yī qiè zhòng shēng zhě, yù xiū wú shàng pú tí zhě, yù chū lí sān jiè zhě","text":"救度一切众生者，欲修无上菩提者，欲出离三界者。"},{"note":"shì zhū rén děng, jiàn dì zàng xíng xiàng jí wén míng zhě, zhì xīn guī yī","text":"是诸人等，见地藏形像及闻名者，至心皈依，"},{"note":"huò yǐ xiāng huá yī fú, bǎo bèi yǐn shí, gòng yǎng zhān lǐ","text":"或以香华衣服、宝贝饮食，供养瞻礼。"},{"note":"shì shàn nán nǚ děng, suǒ yuàn sù chéng, yǒng wú zhàng ài","text":"是善男女等，所愿速成，永无障碍。”"},{"note":"fù cì, guān shì yīn","text":"“复次，观世音！"},{"note":"ruò wèi lái shì, yǒu shàn nán zi, shàn nǚ rén, yù qiú xiàn zài wèi lái bǎi qiān wàn yì děng yuàn","text":"若未来世，有善男子、善女人，欲求现在未来百千万亿等愿、"},{"note":"bǎi qiān wàn yì děng shì, dàn dāng guī yī, zhān lǐ, gòng yǎng","text":"百千万亿等事，但当皈依、瞻礼、供养、"},{"note":"zàn tàn dì zàng pú sà xíng xiàng, rú shì suǒ yuàn suǒ qiú, xī jiē chéng jiù","text":"赞叹地藏菩萨形像，如是所愿所求，悉皆成就。"},{"note":"fù yuàn dì zàng pú sà, jù dà cí bēi, yǒng yōng hù wǒ, shì rén yú shuì mèng zhōng","text":"复愿地藏菩萨，具大慈悲，永拥护我，是人于睡梦中，"},{"note":"jí dé pú sà mó dǐng shòu jì","text":"即得菩萨摩顶授记。”"},{"note":"fù cì, guān shì yīn pú sà","text":"“复次，观世音菩萨！"},{"note":"ruò wèi lái shì, shàn nán zi, shàn nǚ rén, yú dà chéng jīng diǎn","text":"若未来世，善男子、善女人，于大乘经典，"},{"note":"shēn shēng zhēn zhòng, fā bù sī yì xīn, yù dú yù sòng","text":"深生珍重，发不思议心，欲读欲诵。"},{"note":"zòng yù míng shī, jiào shì lìng shú, xuán dé xuán wàng, dòng jīng nián yuè","text":"纵遇明师，教视令熟，旋得旋忘，动经年月，"},{"note":"bù néng dú sòng","text":"不能读诵。"},{"note":"shì shàn nán zi děng, yǒu sù yè zhàng, wèi dé xiāo chú, gù yú dà chéng jīng diǎn","text":"是善男子等，有宿业障，未得消除，故于大乘经典，"},{"note":"wú dú sòng xìng","text":"无读诵性。"},{"note":"rú shì zhī rén, wén dì zàng pú sà míng, jiàn dì zàng pú sà xiàng","text":"如是之人，闻地藏菩萨名，见地藏菩萨像，"},{"note":"jù yǐ běn xīn gōng jìng chén bái, gèng yǐ xiāng, huá, yī fú","text":"具以本心恭敬陈白，更以香、华、衣服、"},{"note":"yǐn shí, yī qiè wán jù, gòng yǎng pú sà","text":"饮食、一切玩具，供养菩萨。"},{"note":"yǐ jìng shuǐ yī zhǎn, jīng yī rì yī yè, ān pú sà qián, rán hòu hé zhǎng qǐng fú","text":"以净水一盏，经一日一夜，安菩萨前，然后合掌请服，"},{"note":"huí shǒu xiàng nán, lín rù kǒu shí, zhì xīn zhèng zhòng","text":"回首向南，临入口时，至心郑重。"},{"note":"fú shuǐ jì bì, shèn wǔ xīn, jiǔ ròu, xié yín, wàng yǔ","text":"服水既毕，慎五辛、酒肉、邪淫、妄语，"},{"note":"jí zhū shā hài, yī qī rì, huò sān qī rì","text":"及诸杀害，一七日，或三七日。"},{"note":"shì shàn nán zi, shàn nǚ rén, yú shuì mèng zhōng, jù jiàn dì zàng pú sà xiàn wú biān shēn","text":"是善男子、善女人，于睡梦中，具见地藏菩萨现无边身，"},{"note":"yú shì rén chù shòu guàn dǐng shuǐ","text":"于是人处授灌顶水。"},{"note":"qí rén mèng jué, jí huò cōng míng, yīng shì jīng diǎn, yī lì ěr gēn","text":"其人梦觉，即获聪明，应是经典，一历耳根，"},{"note":"jí dāng yǒng jì, gèng bù wàng shī yī jù yī jì","text":"即当永记，更不忘失一句一偈。”"},{"note":"fù cì, guān shì yīn pú sà","text":"“复次，观世音菩萨！"},{"note":"ruò wèi lái shì, yǒu zhū rén děng","text":"若未来世，有诸人等："},{"note":"yī shí bù zú, qiú zhě guāi yuàn","text":"衣食不足，求者乖愿；"},{"note":"huò duō bìng jí, huò duō xiōng shuāi","text":"或多病疾，或多凶衰；"},{"note":"jiā zhái bù ān, juàn shǔ fēn sàn","text":"家宅不安，眷属分散；"},{"note":"huò zhū héng shì, duō lái wǔ shēn","text":"或诸横事，多来忤身；"},{"note":"shuì mèng zhī jiān, duō yǒu jīng bù","text":"睡梦之间，多有惊怖。"},{"note":"rú shì rén děng, wén dì zàng míng, jiàn dì zàng xíng, zhì xīn gōng jìng","text":"如是人等，闻地藏名，见地藏形，至心恭敬，"},{"note":"niàn mǎn wàn biàn","text":"念满万遍。"},{"note":"shì zhū bù rú yì shì, jiàn jiàn xiāo miè, jí dé ān lè, yī shí fēng yì","text":"是诸不如意事，渐渐消灭，即得安乐，衣食丰溢，"},{"note":"nǎi zhì yú shuì mèng zhōng, xī jiē ān lè","text":"乃至于睡梦中，悉皆安乐。”"},{"note":"fù cì, guān shì yīn pú sà","text":"“复次，观世音菩萨！"},{"note":"ruò wèi lái shì, yǒu shàn nán zi, shàn nǚ rén, huò yīn zhì shēng","text":"若未来世，有善男子、善女人，或因治生，"},{"note":"huò yīn gōng sī, huò yīn shēng sǐ, huò yīn jí shì, rù shān lín zhōng","text":"或因公私，或因生死，或因急事，入山林中，"},{"note":"guò dù hé hǎi, nǎi jí dà shuǐ, huò jīng xiǎn dào","text":"过渡河海，乃及大水，或经险道。"},{"note":"shì rén xiān dāng niàn dì zàng pú sà míng wàn biàn, suǒ guò tǔ dì","text":"是人先当念地藏菩萨名万遍，所过土地，"},{"note":"guǐ shén wèi hù, xíng zhù zuò wò, yǒng bǎo ān lè","text":"鬼神卫护，行住坐卧，永保安乐。"},{"note":"nǎi zhì féng yú hǔ láng shī zi, yī qiè dú hài, bù néng sǔn zhī","text":"乃至逢于虎狼师子、一切毒害，不能损之。”"},{"note":"fó gào guān shì yīn pú sà","text":"佛告观世音菩萨："},{"note":"shì dì zàng pú sà, yú yán fú tí, yǒu dà yīn yuán","text":"“是地藏菩萨，于阎浮提，有大因缘。"},{"note":"ruò shuō yú zhū zhòng shēng jiàn wén lì yì děng shì, bǎi qiān jié zhōng","text":"若说于诸众生见闻利益等事，百千劫中，"},{"note":"shuō bù néng jǐn","text":"说不能尽。"},{"note":"shì gù, guān shì yīn","text":"是故，观世音！"},{"note":"rǔ yǐ shén lì, liú bù shì jīng, lìng suō pó shì jiè zhòng shēng","text":"汝以神力，流布是经，令娑婆世界众生，"},{"note":"bǎi qiān wàn jié, yǒng shòu ān lè","text":"百千万劫，永受安乐。”"},{"note":"ěr shí, shì zūn ér shuō jì yán","text":"尔时，世尊而说偈言："},{"note":"wú guān dì zàng wēi shén lì, héng hé shā jié shuō nán jǐn","text":"“吾观地藏威神力， 恒河沙劫说难尽，"},{"note":"jiàn wén zhān lǐ yī niàn jiān, lì yì rén tiān wú liàng shì","text":"见闻瞻礼一念间， 利益人天无量事。"},{"note":"ruò nán ruò nǚ ruò lóng shén, bào jǐn yīng dāng duò è dào","text":"若男若女若龙神， 报尽应当堕恶道，"},{"note":"zhì xīn guī yī dà shì shēn, shòu mìng zhuǎn zēng chú zuì zhàng","text":"至心皈依大士身， 寿命转增除罪障。"},{"note":"shǎo shī fù mǔ ēn ài zhě, wèi zhī hún shén zài hé qù","text":"少失父母恩爱者， 未知魂神在何趣？"},{"note":"xiōng dì zǐ mèi jí zhū qīn, shēng zhǎng yǐ lái jiē bù shí","text":"兄弟姊妹及诸亲， 生长以来皆不识。"},{"note":"huò sù huò huà dà shì shēn, bēi liàn zhān lǐ bù zàn shě","text":"或塑或画大士身， 悲恋瞻礼不暂舍，"},{"note":"sān qī rì zhōng niàn qí míng","text":"三七日中念其名。"},{"note":"pú sà dāng xiàn wú biān tǐ","text":"菩萨当现无边体，"},{"note":"shì qí juàn shǔ suǒ shēng jiè, zòng duò è qù xún chū lí","text":"示其眷属所生界， 纵堕恶趣寻出离。"},{"note":"ruò néng bù tuì shì chū xīn, jí huò mó dǐng shòu shèng jì","text":"若能不退是初心， 即获摩顶受圣记。"},{"note":"yù xiū wú shàng pú tí zhě, nǎi zhì chū lí sān jiè kǔ","text":"欲修无上菩提者， 乃至出离三界苦，"},{"note":"shì rén jì fā dà bēi xīn, xiān dāng zhān lǐ dà shì xiàng","text":"是人既发大悲心， 先当瞻礼大士像，"},{"note":"yī qiè zhū yuàn sù chéng jiù, yǒng wú yè zhàng néng zhē zhǐ","text":"一切诸愿速成就， 永无业障能遮止。"},{"note":"yǒu rén fā xīn niàn jīng diǎn, yù dù qún mí chāo bǐ àn","text":"有人发心念经典， 欲度群迷超彼岸，"},{"note":"suī lì shì yuàn bù sī yì, xuán dú xuán wàng duō fèi shī","text":"虽立是愿不思议， 旋读旋忘多废失。"},{"note":"sī rén yǒu yè zhàng huò gù, yú dà chéng jīng bù néng jì","text":"斯人有业障惑故， 于大乘经不能记。"},{"note":"gòng yǎng dì zàng yǐ xiāng huá, yī fú yǐn shí zhū wán jù","text":"供养地藏以香华， 衣服饮食诸玩具，"},{"note":"yǐ jìng shuǐ ān dà shì qián, yī rì yī yè qiú fú zhī","text":"以净水安大士前， 一日一夜求服之，"},{"note":"fā yīn zhòng xīn shèn wǔ xīn, jiǔ ròu xié yín jí wàng yǔ","text":"发殷重心慎五辛， 酒肉邪淫及妄语，"},{"note":"sān qī rì nèi wù shā hài, zhì xīn sī niàn dà shì míng","text":"三七日内勿杀害， 至心思念大士名。"},{"note":"jí yú mèng zhōng jiàn wú biān, jué lái biàn dé lì gēn ěr","text":"即于梦中见无边， 觉来便得利根耳，"},{"note":"yīng shì jīng jiào lì ěr wén, qiān wàn shēng zhōng yǒng bù wàng","text":"应是经教历耳闻， 千万生中永不忘。"},{"note":"yǐ shì dà shì bù sī yì, néng shǐ sī rén huò cǐ huì","text":"以是大士不思议， 能使斯人获此慧。"},{"note":"pín qióng zhòng shēng jí jí bìng, jiā zhái xiōng shuāi juàn shǔ lí","text":"贫穷众生及疾病， 家宅凶衰眷属离，"},{"note":"shuì mèng zhī zhōng xī bù ān, qiú zhě guāi wéi wú chēng suì","text":"睡梦之中悉不安， 求者乖违无称遂。"},{"note":"zhì xīn zhān lǐ dì zàng xiàng, yī qiè è shì jiē xiāo miè","text":"至心瞻礼地藏像， 一切恶事皆消灭，"},{"note":"zhì yú mèng zhōng jǐn dé ān, yī shí fēng ráo shén guǐ hù","text":"至于梦中尽得安， 衣食丰饶神鬼护。"},{"note":"yù rù shān lín jí dù hǎi, dú è qín shòu jí è rén","text":"欲入山林及渡海， 毒恶禽兽及恶人，"},{"note":"è shén è guǐ bìng è fēng, yī qiè zhū nán zhū kǔ nǎo","text":"恶神恶鬼并恶风， 一切诸难诸苦恼。"},{"note":"dàn dāng zhān lǐ jí gòng yǎng, dì zàng pú sà dà shì xiàng","text":"但当瞻礼及供养， 地藏菩萨大士像，"},{"note":"rú shì shān lín dà hǎi zhōng, yīng shì zhū è jiē xiāo miè","text":"如是山林大海中， 应是诸恶皆消灭。"},{"note":"guān yīn zhì xīn tīng wú shuō, dì zàng wú jǐn bù sī yì","text":"观音至心听吾说， 地藏无尽不思议，"},{"note":"bǎi qiān wàn jié shuō bù zhōu, guǎng xuān dà shì rú shì lì","text":"百千万劫说不周， 广宣大士如是力。"},{"note":"dì zàng míng zì rén ruò wén, nǎi zhì jiàn xiàng zhān lǐ zhě","text":"地藏名字人若闻， 乃至见像瞻礼者，"},{"note":"xiāng huá yī fú yǐn shí fèng, gòng yǎng bǎi qiān shòu miào lè","text":"香华衣服饮食奉， 供养百千受妙乐，"},{"note":"ruò néng yǐ cǐ huí fǎ jiè, bì jìng chéng fó chāo shēng sǐ","text":"若能以此回法界， 毕竟成佛超生死。"},{"note":"shì gù guān yīn rǔ dāng zhī, pǔ gào héng shā zhū guó tǔ","text":"是故观音汝当知， 普告恒沙诸国土。”"}],"ksitigarbha-13":[{"note":"zhǔ lèi rén tiān pǐn dì shí sān","text":"嘱累人天品第十三"},{"note":"ěr shí, shì zūn jǔ jīn sè bì, yòu mó dì zàng pú sà mó hē sà dǐng","text":"尔时，世尊举金色臂，又摩地藏菩萨摩诃萨顶，"},{"note":"ér zuò shì yán","text":"而作是言："},{"note":"dì zàng","text":"“地藏！"},{"note":"dì zàng","text":"地藏！"},{"note":"rǔ zhī shén lì, bù kě sī yì","text":"汝之神力，不可思议；"},{"note":"rǔ zhī cí bēi, bù kě sī yì","text":"汝之慈悲，不可思议；"},{"note":"rǔ zhī zhì huì, bù kě sī yì","text":"汝之智慧，不可思议；"},{"note":"rǔ zhī biàn cái, bù kě sī yì","text":"汝之辩才，不可思议。"},{"note":"zhèng shǐ shí fāng zhū fó, zàn tàn xuān shuō rǔ zhī bù sī yì shì","text":"正使十方诸佛，赞叹宣说汝之不思议事，"},{"note":"qiān wàn jié zhōng, bù néng dé jǐn","text":"千万劫中，不能得尽。"},{"note":"dì zàng","text":"地藏！"},{"note":"dì zàng","text":"地藏！"},{"note":"jì wú jīn rì zài dāo lì tiān zhōng, yú bǎi qiān wàn yì bù kě shuō bù kě shuō yī qiè zhū fó pú sà","text":"记吾今日在忉利天中，于百千万亿不可说不可说一切诸佛菩萨、"},{"note":"tiān lóng bā bù, dà huì zhī zhōng, zài yǐ rén tiān zhū zhòng shēng děng","text":"天龙八部、大会之中，再以人天诸众生等，"},{"note":"wèi chū sān jiè, zài huǒ zhái zhōng zhě, fù zhǔ yú rǔ","text":"未出三界，在火宅中者，付嘱于汝。"},{"note":"wú lìng shì zhū zhòng shēng, duò è qù zhōng yī rì yī yè, hé kuàng gèng luò wǔ wú jiān jí ā bí dì yù","text":"无令是诸众生，堕恶趣中一日一夜，何况更落五无间及阿鼻地狱，"},{"note":"dòng jīng qiān wàn yì jié, wú yǒu chū qī","text":"动经千万亿劫，无有出期。”"},{"note":"dì zàng","text":"“地藏！"},{"note":"shì nán yán fú tí zhòng shēng, zhì xìng wú dìng, xí è zhě duō","text":"是南阎浮提众生，志性无定，习恶者多，"},{"note":"zòng fā shàn xīn, xū yú jí tuì, ruò yù è yuán, niàn niàn zēng zhǎng","text":"纵发善心，须臾即退，若遇恶缘，念念增长。"},{"note":"yǐ shì zhī gù, wú fēn shì xíng, bǎi qiān yì huà dù, suí qí gēn xìng ér dù tuō zhī","text":"以是之故，吾分是形，百千亿化度，随其根性而度脱之。"},{"note":"dì zàng","text":"地藏！"},{"note":"wú jīn yīn qín, yǐ tiān rén zhòng, fù zhǔ yú rǔ","text":"吾今殷勤，以天人众，付嘱于汝。"},{"note":"wèi lái zhī shì, ruò yǒu tiān rén, jí shàn nán zi, shàn nǚ rén","text":"未来之世，若有天人，及善男子、善女人，"},{"note":"yú fó fǎ zhōng, zhǒng shǎo shàn gēn, yī máo yī chén, yī shā yī dì","text":"于佛法中，种少善根，一毛一尘，一沙一渧。"},{"note":"rǔ yǐ dào lì, yōng hù shì rén, jiàn xiū wú shàng, wù lìng tuì shī","text":"汝以道力，拥护是人，渐修无上，勿令退失。"},{"note":"fù cì, dì zàng","text":"复次，地藏！"},{"note":"wèi lái shì zhōng, ruò tiān ruò rén, suí yè bào yīng, luò zài è qù","text":"未来世中，若天若人，随业报应，落在恶趣。"},{"note":"lín duò qù zhōng, huò zhì mén shǒu, shì zhū zhòng shēng, ruò néng niàn dé yī fó míng","text":"临堕趣中，或至门首，是诸众生，若能念得一佛名、"},{"note":"yī pú sà míng, yī jù yī jì dà chéng jīng diǎn","text":"一菩萨名、一句一偈大乘经典。"},{"note":"shì zhū zhòng shēng, rǔ yǐ shén lì, fāng biàn jiù bá","text":"是诸众生，汝以神力，方便救拔。"},{"note":"yú shì rén suǒ, xiàn wú biān shēn, wèi suì dì yù, qiǎn lìng shēng tiān","text":"于是人所，现无边身，为碎地狱，遣令生天，"},{"note":"shòu shèng miào lè","text":"受胜妙乐。”"},{"note":"ěr shí, shì zūn ér shuō jì yán","text":"尔时，世尊而说偈言："},{"note":"xiàn zài wèi lái tiān rén zhòng, wú jīn yīn qín fù zhǔ rǔ","text":"“现在未来天人众， 吾今殷勤付嘱汝，"},{"note":"yǐ dà shén tōng fāng biàn dù, wù lìng duò zài zhū è qù","text":"以大神通方便度， 勿令堕在诸恶趣。”"},{"note":"ěr shí, dì zàng pú sà mó hē sà hú guì hé zhǎng, bái fó yán","text":"尔时，地藏菩萨摩诃萨胡跪合掌，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wéi yuàn shì zūn, bù yǐ wèi lǜ","text":"唯愿世尊，不以为虑。"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, yú fó fǎ zhōng","text":"未来世中，若有善男子、善女人，于佛法中，"},{"note":"yī niàn gōng jìng, wǒ yì bǎi qiān fāng biàn, dù tuō shì rén, yú shēng sǐ zhōng","text":"一念恭敬，我亦百千方便，度脱是人，于生死中，"},{"note":"sù dé jiě tuō","text":"速得解脱。"},{"note":"hé kuàng wén zhū shàn shì, niàn niàn xiū xíng","text":"何况闻诸善事，念念修行？"},{"note":"zì rán yú wú shàng dào, yǒng bù tuì zhuǎn","text":"自然于无上道，永不退转。”"},{"note":"shuō shì yǔ shí, huì zhōng yǒu yī pú sà, míng xū kōng cáng, bái fó yán","text":"说是语时，会中有一菩萨，名虚空藏，白佛言："},{"note":"shì zūn","text":"“世尊！"},{"note":"wǒ zì zhì dāo lì, wén yú rú lái zàn tàn dì zàng pú sà, wēi shén shì lì","text":"我自至忉利，闻于如来赞叹地藏菩萨，威神势力，"},{"note":"bù kě sī yì","text":"不可思议。"},{"note":"wèi lái shì zhōng, ruò yǒu shàn nán zi, shàn nǚ rén, nǎi jí yī qiè tiān lóng","text":"未来世中，若有善男子、善女人，乃及一切天龙，"},{"note":"wén cǐ jīng diǎn, jí dì zàng míng zì, huò zhān lǐ xíng xiàng, dé jǐ zhǒng fú lì","text":"闻此经典，及地藏名字，或瞻礼形像，得几种福利？"},{"note":"wéi yuàn shì zūn, wèi wèi lái xiàn zài yī qiè zhòng děng, lüè ér shuō zhī","text":"唯愿世尊，为未来现在一切众等，略而说之。”"},{"note":"fó gào xū kōng cáng pú sà","text":"佛告虚空藏菩萨："},{"note":"dì tīng","text":"“谛听！"},{"note":"dì tīng","text":"谛听！"},{"note":"wú dāng wèi rǔ fēn bié shuō zhī","text":"吾当为汝分别说之。"},{"note":"ruò wèi lái shì, yǒu shàn nán zi, shàn nǚ rén, jiàn dì zàng xíng xiàng","text":"若未来世，有善男子、善女人，见地藏形像，"},{"note":"jí wén cǐ jīng, nǎi zhì dú sòng, xiāng huá yǐn shí, yī fú zhēn bǎo","text":"及闻此经，乃至读诵，香华饮食、衣服珍宝，"},{"note":"bù shī gòng yǎng, zàn tàn zhān lǐ, dé èr shí bā zhǒng lì yì","text":"布施供养，赞叹瞻礼，得二十八种利益："},{"note":"yī zhě tiān lóng hù niàn, èr zhě shàn guǒ rì zēng, sān zhě jí shèng shàng yīn","text":"一者天龙护念，二者善果日增，三者集圣上因，"},{"note":"sì zhě pú tí bù tuì, wǔ zhě yī shí fēng zú, liù zhě jí yì bù lín","text":"四者菩提不退，五者衣食丰足，六者疾疫不临，"},{"note":"qī zhě lí shuǐ huǒ zāi, bā zhě wú dào zéi è, jiǔ zhě rén jiàn qīn jìng","text":"七者离水火灾，八者无盗贼厄，九者人见钦敬，"},{"note":"shí zhě shén guǐ zhù chí, shí yī zhě nǚ zhuǎn nán shēn, shí èr zhě wèi wáng chén nǚ","text":"十者神鬼助持，十一者女转男身，十二者为王臣女，"},{"note":"shí sān zhě duān zhèng xiāng hǎo, shí sì zhě duō shēng tiān shàng, shí wǔ zhě huò wèi dì wáng","text":"十三者端正相好，十四者多生天上，十五者或为帝王，"},{"note":"shí liù zhě sù zhì mìng tōng, shí qī zhě yǒu qiú jiē cóng, shí bā zhě juàn shǔ huān lè","text":"十六者宿智命通，十七者有求皆从，十八者眷属欢乐，"},{"note":"shí jiǔ zhě zhū héng xiāo miè, èr shí zhě yè dào yǒng chú, èr shí yī zhě qù chù jǐn tōng","text":"十九者诸横消灭，二十者业道永除，二十一者去处尽通，"},{"note":"èr shí èr zhě yè mèng ān lè, èr shí sān zhě xiān wáng lí kǔ","text":"二十二者夜梦安乐，二十三者先亡离苦，"},{"note":"èr shí sì zhě sù fú shòu shēng, èr shí wǔ zhě zhū shèng zàn tàn","text":"二十四者宿福受生，二十五者诸圣赞叹，"},{"note":"èr shí liù zhě cōng míng lì gēn, èr shí qī zhě ráo cí mǐn xīn","text":"二十六者聪明利根，二十七者饶慈愍心，"},{"note":"èr shí bā zhě bì jìng chéng fó","text":"二十八者毕竟成佛。”"},{"note":"fù cì, xū kōng cáng pú sà","text":"“复次，虚空藏菩萨！"},{"note":"ruò xiàn zài wèi lái, tiān lóng guǐ shén, wén dì zàng míng, lǐ dì zàng xíng","text":"若现在未来，天龙鬼神，闻地藏名，礼地藏形，"},{"note":"huò wén dì zàng běn yuàn shì xíng, zàn tàn zhān lǐ, dé qī zhǒng lì yì","text":"或闻地藏本愿事行，赞叹瞻礼，得七种利益："},{"note":"yī zhě sù chāo shèng dì, èr zhě è yè xiāo miè, sān zhě zhū fó hù lín","text":"一者速超圣地，二者恶业销灭，三者诸佛护临，"},{"note":"sì zhě pú tí bù tuì, wǔ zhě zēng zhǎng běn lì, liù zhě sù mìng jiē tōng","text":"四者菩提不退，五者增长本力，六者宿命皆通，"},{"note":"qī zhě bì jìng chéng fó","text":"七者毕竟成佛。”"},{"note":"ěr shí, shí fāng yī qiè zhū lái bù kě shuō bù kě shuō zhū fó rú lái","text":"尔时，十方一切诸来不可说不可说诸佛如来，"},{"note":"jí dà pú sà, tiān lóng bā bù, wén shì jiā móu ní fó, chēng yáng zàn tàn dì zàng pú sà","text":"及大菩萨、天龙八部，闻释迦牟尼佛，称扬赞叹地藏菩萨，"},{"note":"dà wēi shén lì, bù kě sī yì, tàn wèi céng yǒu","text":"大威神力，不可思议，叹未曾有。"},{"note":"shì shí dāo lì tiān, yǔ wú liàng xiāng huá, tiān yī zhū yīng, gòng yǎng shì jiā móu ní fó","text":"是时忉利天，雨无量香华，天衣珠璎，供养释迦牟尼佛，"},{"note":"jí dì zàng pú sà yǐ","text":"及地藏菩萨已。"},{"note":"yī qiè zhòng huì, jù fù zhān lǐ, hé zhǎng ér tuì","text":"一切众会，俱复瞻礼，合掌而退。"}],"vajrasattva-hundred-syllable":[{"note":"ōng bān zhā sà duǒ sà mǎ yǎ, ma nǔ bā lā yǎ","text":"嗡 班扎 萨埵 萨玛雅，嘛努 巴拉雅。"},{"note":"bān zhā sà duǒ dǐ nuò bā, dǐ chā zhī zhuō měi bā wa","text":"班扎 萨埵 底诺巴，底叉 知桌 美巴哇。"},{"note":"sū duǒ kǎ yō měi bā wa, sū bō kǎ yō měi bā wa","text":"苏埵 卡哟 美巴哇，苏波 卡哟 美巴哇，"},{"note":"ā nǔ lā duǒ měi bā wa","text":"阿努 拉埵 美巴哇。"},{"note":"sà wa sī dé mǎ měi zhā yǎ zā, sà wa gā ma sè zā měi","text":"萨哇 斯德玛美 扎雅匝，萨哇 嘎嘛 色匝美。"},{"note":"zé dāng xié yāng gé rè hōng, hā hā hā hā huǒ","text":"则当 协央 格热吽，哈哈 哈哈 伙。"},{"note":"bān gā wèn sà wa dá tā gā dá, bān zhā ma mài mǔ zá","text":"班嘎问 萨哇 达他 嘎达，班扎 嘛麦 母杂。"},{"note":"bān zhā bā wa ma hā, sà mǎ yǎ sà duǒ a","text":"班扎 巴哇 嘛哈，萨玛雅 萨埵 啊。"}],"wenshu-prajna-sutra":[{"note":"rú shì wǒ wén","text":"如是我闻。"},{"note":"yī shí fó zài shě wèi guó qí shù jǐ gū dú yuán","text":"一时佛在舍卫国只树给孤独园。"},{"note":"yǔ dà bǐ qiū zhòng yī wàn rén jù","text":"与大比丘众一万人俱。"},{"note":"jí zhū pú sà mó hē sà shí wàn rén jù","text":"及诸菩萨摩诃萨十万人俱。"},{"note":"jiē xī zhù yú bù tuì zhuǎn dì","text":"皆悉住于不退转地。"},{"note":"jiǔ yǐ gòng yǎng wú liàng zhū fó","text":"久已供养无量诸佛。"},{"note":"yú zhū fó suǒ shēn zhǒng shàn gēn","text":"于诸佛所深种善根。"},{"note":"chéng jiù zhòng shēng jìng fó guó tǔ","text":"成就众生净佛国土。"},{"note":"dé tuó luó ní","text":"得陀罗尼。"},{"note":"huò lè shuō biàn cái","text":"获乐说辩才。"},{"note":"chéng jiù zhì huì jù zú gōng dé","text":"成就智慧具足功德。"},{"note":"yǐ zì zài shén tōng yóu zhū fó shì jiè","text":"以自在神通游诸佛世界。"},{"note":"fàng wú liàng guāng míng shuō wú jǐn miào fǎ","text":"放无量光明说无尽妙法。"},{"note":"jiào zhū pú sà rù yī xiāng mén","text":"教诸菩萨入一相门。"},{"note":"dé wú suǒ wèi","text":"得无所畏。"},{"note":"shàn jiàng zhòng mó jiào huà dù tuō wài dào xié jiàn","text":"善降众魔教化度脱外道邪见。"},{"note":"ruò yǒu zhòng shēng lè shēng wén zhě shuō shēng wén chéng","text":"若有众生乐声闻者说声闻乘。"},{"note":"lè yuán jué zhě shuō yuán jué chéng","text":"乐缘觉者说缘觉乘。"},{"note":"lè shì jiān zhě shuō shì jiān chéng","text":"乐世间者说世间乘。"},{"note":"yǐ bù shī chí jiè rěn rǔ jīng jìn chán dìng zhì huì","text":"以布施持戒忍辱精进禅定智慧。"},{"note":"shè zhū zhòng shēng","text":"摄诸众生。"},{"note":"wèi dù zhě dù","text":"未度者度。"},{"note":"wèi tuō zhě tuō","text":"未脱者脱。"},{"note":"wèi ān zhě ān","text":"未安者安。"},{"note":"wèi ní huán zhě lìng dé ní huán","text":"未泥洹者令得泥洹。"},{"note":"jiū jìng pú sà suǒ xíng","text":"究竟菩萨所行。"},{"note":"shàn rù zhū fó fǎ cáng","text":"善入诸佛法藏。"},{"note":"rú shì zhǒng zhǒng gōng dé jiē xī jù zú","text":"如是种种功德皆悉具足。"},{"note":"qí míng yuē wén shū shī lì fǎ wáng zi pú sà","text":"其名曰文殊师利法王子菩萨。"},{"note":"mí lè pú sà","text":"弥勒菩萨。"},{"note":"pǔ guāng míng pú sà","text":"普光明菩萨。"},{"note":"bù shě yǒng měng jīng jìn pú sà","text":"不舍勇猛精进菩萨。"},{"note":"yào wáng pú sà","text":"药王菩萨。"},{"note":"bǎo zhǎng pú sà","text":"宝掌菩萨。"},{"note":"bǎo yìn pú sà","text":"宝印菩萨。"},{"note":"yuè guāng pú sà","text":"月光菩萨。"},{"note":"rì jìng pú sà","text":"日净菩萨。"},{"note":"dà lì pú sà","text":"大力菩萨。"},{"note":"wú liàng lì pú sà","text":"无量力菩萨。"},{"note":"dé qín jīng jìn pú sà","text":"得勤精进菩萨。"},{"note":"lì chuáng xiāng pú sà","text":"力幢相菩萨。"},{"note":"fǎ xiāng pú sà","text":"法相菩萨。"},{"note":"zì zài wáng pú sà","text":"自在王菩萨。"},{"note":"rú shì děng pú sà mó hē sà shí wàn rén jù","text":"如是等菩萨摩诃萨十万人俱。"},{"note":"bìng yú tiān lóng guǐ shén děng yī qiè dà zhòng","text":"并余天龙鬼神等一切大众。"},{"note":"jiē xī lái jí","text":"皆悉来集。"},{"note":"ěr shí shì zūn yú zhōng yè shí fàng dà guāng míng","text":"尔时世尊于中夜时放大光明。"},{"note":"qīng huáng chì bái zá pǒ lí sè","text":"青黄赤白杂颇梨色。"},{"note":"pǔ zhào shí fāng wú liàng shì jiè","text":"普照十方无量世界。"},{"note":"yī qiè zhòng shēng chù cǐ guāng zhě","text":"一切众生触此光者。"},{"note":"jiē cóng wò qǐ jiàn cǐ guāng míng","text":"皆从卧起见此光明。"},{"note":"jiē dé fǎ xǐ","text":"皆得法喜。"},{"note":"xián shēng yí huò","text":"咸生疑惑。"},{"note":"cǐ guāng hé lái pǔ biàn shì jiè","text":"此光何来普遍世界。"},{"note":"lìng zhū zhòng shēng dé ān yǐn lè","text":"令诸众生得安隐乐。"},{"note":"zuò shì niàn yǐ","text":"作是念已。"},{"note":"yú yī yī guāng fù chū dà guāng míng","text":"于一一光复出大光明。"},{"note":"zhào yào shū tè shèng yú qián guāng","text":"照耀殊特胜于前光。"},{"note":"rú shì zhǎn zhuǎn nǎi zhì shí zhòng","text":"如是展转乃至十重。"},{"note":"yī qiè pú sà jí zhū bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"一切菩萨及诸比丘比丘尼优婆塞优婆夷。"},{"note":"tiān lóng yè chā gàn tà pó ā xiū luó jiā lóu luó jǐn nà luó mó hóu luó qié rén fēi rén děng","text":"天龙夜叉干闼婆阿修罗迦楼罗紧那罗摩睺罗伽人非人等。"},{"note":"xián jiē yǒng yuè dé wèi céng yǒu","text":"咸皆踊跃得未曾有。"},{"note":"gè gè sī niàn bì shì rú lái fàng cǐ guāng míng","text":"各各思念必是如来放此光明。"},{"note":"wǒ děng yīng dāng jí zhì fó suǒ lǐ bài qīn jìn gōng jìng rú lái","text":"我等应当疾至佛所礼拜亲近恭敬如来。"},{"note":"shì shí wén shū shī lì","text":"是时文殊师利。"},{"note":"jí zhū pú sà mó hē sà zhòng yù cǐ guāng zhě","text":"及诸菩萨摩诃萨众遇此光者。"},{"note":"huān xǐ yǒng yuè chōng biàn shēn xīn","text":"欢喜踊跃充遍身心。"},{"note":"gè cóng zhù chù dào qí huán mén","text":"各从住处到祇洹门。"},{"note":"ěr shí shè lì fú","text":"尔时舍利弗。"},{"note":"dà mù qián lián","text":"大目揵连。"},{"note":"fù lóu nà mí duō luó ní zi","text":"富楼那弥多罗尼子。"},{"note":"mó hē jiā shè","text":"摩诃迦叶。"},{"note":"mó hē jiā zhān yán","text":"摩诃迦旃延。"},{"note":"mó hē jù chī luó","text":"摩诃俱絺罗。"},{"note":"jiē cóng zhù chù dào qí huán mén","text":"皆从住处到祇洹门。"},{"note":"dì shì sì tiān wáng shàng zhì ā jiā ní zhà tiān","text":"帝释四天王上至阿迦尼咤天。"},{"note":"yì dǔ guāng míng tàn wèi céng yǒu","text":"亦睹光明叹未曾有。"},{"note":"yǔ qí juàn shǔ jī miào tiān huā tiān xiāng tiān lè tiān bǎo yī","text":"与其眷属赍妙天花天香天乐天宝衣。"},{"note":"yī qiè jiē xī dào qí huán mén","text":"一切皆悉到祇洹门。"},{"note":"qí yú bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí tiān lóng bā bù","text":"其余比丘比丘尼优婆塞优婆夷天龙八部。"},{"note":"yù guāng huān xǐ jiē lái dào mén","text":"遇光欢喜皆来到门。"},{"note":"ěr shí shì zūn yī qiè zhǒng zhì","text":"尔时世尊一切种智。"},{"note":"zhī zhū dà zhòng xī yǐ zài mén wài","text":"知诸大众悉已在门外。"},{"note":"cóng zhù chù qǐ chū zhì mén wài","text":"从住处起出至门外。"},{"note":"zì pù fǎ zuò jié jiā fū zuò","text":"自铺法座结珈趺坐。"},{"note":"gào shè lì fú","text":"告舍利弗。"},{"note":"rǔ jīn chén cháo lái mén wài hū","text":"汝今晨朝来门外乎。"},{"note":"shè lì fú bái fó yán","text":"舍利弗白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wén shū shī lì děng pú sà mó hē sà","text":"文殊师利等菩萨摩诃萨。"},{"note":"jiē xī xiān zhì","text":"皆悉先至。"},{"note":"ěr shí shì zūn gào wén shū shī lì","text":"尔时世尊告文殊师利。"},{"note":"rǔ yú chén cháo xiān zhì mén hū","text":"汝于晨朝先至门乎。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"rú shì shì zūn","text":"如是世尊。"},{"note":"wǒ yú zhōng yè jiàn dà guāng míng shí zhòng zhào yào","text":"我于中夜见大光明十重照耀。"},{"note":"dé wèi céng yǒu xīn huái huān xǐ yǒng yuè wú liàng","text":"得未曾有心怀欢喜踊跃无量。"},{"note":"gù lái lǐ bài qīn jìn rú lái","text":"故来礼拜亲近如来。"},{"note":"bìng yù yuàn wén gān lù miào fǎ","text":"并欲愿闻甘露妙法。"},{"note":"ěr shí shì zūn gào wén shū shī lì","text":"尔时世尊告文殊师利。"},{"note":"rǔ jīn zhēn shí jiàn rú lái hū","text":"汝今真实见如来乎。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"rú lái fǎ shēn běn bù kě jiàn","text":"如来法身本不可见。"},{"note":"wǒ wèi zhòng shēng gù lái jiàn fó","text":"我为众生故来见佛。"},{"note":"fó fǎ shēn zhě bù kě sī yì","text":"佛法身者不可思议。"},{"note":"wú xiāng wú xíng bù lái bù qù","text":"无相无形不来不去。"},{"note":"fēi yǒu fēi wú fēi jiàn fēi bù jiàn","text":"非有非无非见非不见。"},{"note":"rú rú shí jì bù qù bù lái","text":"如如实际不去不来。"},{"note":"fēi wú fēi fēi wú fēi chù fēi fēi chù","text":"非无非非无非处非非处。"},{"note":"fēi yī fēi èr","text":"非一非二。"},{"note":"fēi jìng fēi gòu bù shēng bù miè","text":"非净非垢不生不灭。"},{"note":"wǒ jiàn rú lái yì fù rú shì","text":"我见如来亦复如是。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ jīn rú shì jiàn rú lái hū","text":"汝今如是见如来乎。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ shí wú jiàn yì wú jiàn xiāng","text":"我实无见亦无见相。"},{"note":"ěr shí shè lì fú bái wén shū shī lì","text":"尔时舍利弗白文殊师利。"},{"note":"wǒ jīn bù jiě rǔ zhī suǒ shuō","text":"我今不解汝之所说。"},{"note":"yún hé rú shì jiàn yú rú lái","text":"云何如是见于如来。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"dà dé shè lì fú","text":"大德舍利弗。"},{"note":"wǒ bù rú shì jiàn yú rú lái","text":"我不如是见于如来。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rú rǔ suǒ shuō zhuǎn bù kě jiě","text":"如汝所说转不可解。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"bù kě jiě zhě jí bō rě bō luó mì","text":"不可解者即般若波罗蜜。"},{"note":"bō rě bō luó mì","text":"般若波罗蜜。"},{"note":"fēi shì kě jiě fēi bù kě jiě","text":"非是可解非不可解。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rǔ yú zhòng shēng qǐ cí bēi xīn bù","text":"汝于众生起慈悲心不。"},{"note":"rǔ wèi zhòng shēng xíng liù bō luó mì bù fù wèi zhòng shēng rù niè pán bù","text":"汝为众生行六波罗蜜不复为众生入涅槃不。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"rú rǔ suǒ shuō","text":"如汝所说。"},{"note":"wǒ wèi zhòng shēng qǐ cí bēi xīn","text":"我为众生起慈悲心。"},{"note":"xíng liù bō luó mì","text":"行六波罗蜜。"},{"note":"rù yú niè pán ér zhòng shēng shí bù kě dé","text":"入于涅槃而众生实不可得。"},{"note":"wú xiāng wú xíng bù zēng bù jiǎn","text":"无相无形不增不减。"},{"note":"shè lì fú rǔ cháng zuò shì niàn","text":"舍利弗汝常作是念。"},{"note":"yī yī shì jiè yǒu héng hé shā děng zhū fó","text":"一一世界有恒河沙等诸佛。"},{"note":"zhù shì héng hé shā jié","text":"住世恒河沙劫。"},{"note":"shuō yī yī fǎ","text":"说一一法。"},{"note":"jiào huà dù tuō héng hé shā zhòng shēng","text":"教化度脱恒河沙众生。"},{"note":"yī yī zhòng shēng jiē dé miè dù","text":"一一众生皆得灭度。"},{"note":"rǔ yǒu rú shì niàn bù","text":"汝有如是念不。"},{"note":"shè lì fú yán","text":"舍利弗言。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"wǒ cháng zuò shì niàn","text":"我常作是念。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"rú xū kōng wú shù zhòng shēng yì wú shù","text":"如虚空无数众生亦无数。"},{"note":"xū kōng bù kě dù zhòng shēng yì bù kě dù","text":"虚空不可度众生亦不可度。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhòng shēng yǔ xū kōng děng","text":"一切众生与虚空等。"},{"note":"yún hé zhū fó jiào huà zhòng shēng","text":"云何诸佛教化众生。"},{"note":"shè lì fú yán","text":"舍利弗言。"},{"note":"ruò yī qiè zhòng shēng yǔ xū kōng děng","text":"若一切众生与虚空等。"},{"note":"rǔ hé gù wèi zhòng shēng shuō fǎ lìng dé pú tí","text":"汝何故为众生说法令得菩提。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"pú tí zhě shí bù kě dé","text":"菩提者实不可得。"},{"note":"wǒ dāng shuō hé fǎ shǐ zhòng shēng dé hū","text":"我当说何法使众生得乎。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"pú tí yǔ zhòng shēng bù yī bù èr","text":"菩提与众生不一不二。"},{"note":"wú yì wú wèi wú míng wú xiāng shí wú suǒ yǒu","text":"无异无为无名无相实无所有。"},{"note":"ěr shí shì zūn chū dà rén xiāng ròu jì guāng míng","text":"尔时世尊出大人相肉髻光明。"},{"note":"shū tè xī yǒu bù kě chēng shuō","text":"殊特稀有不可称说。"},{"note":"rù wén shū shī lì pú sà mó hē sà fǎ wáng zi dǐng","text":"入文殊师利菩萨摩诃萨法王子顶。"},{"note":"hái cóng dǐng chū pǔ zhào dà zhòng","text":"还从顶出普照大众。"},{"note":"zhào dà zhòng yǐ nǎi biàn shí fāng yī qiè shì jiè","text":"照大众已乃遍十方一切世界。"},{"note":"shì shí dà zhòng chù cǐ guāng míng","text":"是时大众触此光明。"},{"note":"shēn xīn kuài lè dé wèi céng yǒu","text":"身心快乐得未曾有。"},{"note":"jiē cóng zuò qǐ zhān yǎng shì zūn jí wén shū shī lì","text":"皆从座起瞻仰世尊及文殊师利。"},{"note":"xián zuò shì niàn","text":"咸作是念。"},{"note":"jīn rì rú lái fàng cǐ qí tè wēi miào guāng míng","text":"今日如来放此奇特微妙光明。"},{"note":"rù wén shū shī lì fǎ wáng zi dǐng","text":"入文殊师利法王子顶。"},{"note":"hái cóng dǐng chū pǔ zhào dà zhòng","text":"还从顶出普照大众。"},{"note":"zhào dà zhòng yǐ nǎi biàn shí fāng","text":"照大众已乃遍十方。"},{"note":"fēi wú yīn yuán bì shuō miào fǎ","text":"非无因缘必说妙法。"},{"note":"wǒ děng dàn dāng qín xiū jīng jìn lè rú shuō xíng","text":"我等但当勤修精进乐如说行。"},{"note":"rú shì niàn yǐ","text":"如是念已。"},{"note":"gè bái fó yán","text":"各白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"rú lái jīn rì fàng cǐ guāng míng","text":"如来今日放此光明。"},{"note":"fēi wú yīn yuán bì shuō miào fǎ","text":"非无因缘必说妙法。"},{"note":"wǒ děng kě yǎng lè rú shuō xíng","text":"我等渴仰乐如说行。"},{"note":"rú shì bái yǐ mò rán ér zhù","text":"如是白已默然而住。"},{"note":"ěr shí wén shū shī lì bái fó yán","text":"尔时文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"rú lái fàng guāng jiā wǒ shén lì","text":"如来放光加我神力。"},{"note":"cǐ guāng xī yǒu fēi sè fēi xiāng","text":"此光稀有非色非相。"},{"note":"bù qù bù lái bù dòng bù jìng","text":"不去不来不动不静。"},{"note":"fēi jiàn fēi wén fēi jué fēi zhī","text":"非见非闻非觉非知。"},{"note":"yī qiè zhòng shēng wú suǒ guān jiàn","text":"一切众生无所观见。"},{"note":"wú xǐ wú wèi wú suǒ fēn bié","text":"无喜无畏无所分别。"},{"note":"wǒ dāng chéng fó shèng zhǐ shuō cǐ guāng míng lìng zhū zhòng shēng rù wú xiǎng huì","text":"我当承佛圣旨说此光明令诸众生入无想慧。"},{"note":"ěr shí fó gào wén shū shī lì","text":"尔时佛告文殊师利。"},{"note":"shàn zāi","text":"善哉。"},{"note":"shàn zāi rǔ shàn kuài shuō","text":"善哉汝善快说。"},{"note":"wú zhù rǔ xǐ","text":"吾助汝喜。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"cǐ guāng míng zhě shì bō rě bō luó mì","text":"此光明者是般若波罗蜜。"},{"note":"bō rě bō luó mì zhě shì rú lái","text":"般若波罗蜜者是如来。"},{"note":"rú lái zhě shì yī qiè zhòng shēng","text":"如来者是一切众生。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ rú shì xiū bō rě bō luó mì","text":"我如是修般若波罗蜜。"},{"note":"ěr shí fó gào wén shū shī lì yán","text":"尔时佛告文殊师利言。"},{"note":"shàn nán zi","text":"善男子。"},{"note":"rǔ jīn rú shì shuō shēn bō rě bō luó mì","text":"汝今如是说深般若波罗蜜。"},{"note":"wǒ jīn wèn rǔ","text":"我今问汝。"},{"note":"ruò yǒu rén wèn rǔ yǒu jǐ zhòng shēng jiè","text":"若有人问汝有几众生界。"},{"note":"rǔ yún hé dá","text":"汝云何答。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn ruò rén zuò rú shì wèn","text":"世尊若人作如是问。"},{"note":"wǒ dāng dá yán","text":"我当答言。"},{"note":"zhòng shēng jiè shù rú rú lái jiè","text":"众生界数如如来界。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò fù wèn rǔ zhòng shēng jiè guǎng xiá yún hé","text":"若复问汝众生界广狭云何。"},{"note":"rǔ yún hé dá","text":"汝云何答。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò rén zuò rú shì wèn","text":"若人作如是问。"},{"note":"wǒ dāng dá yán","text":"我当答言。"},{"note":"rú fó jiè guǎng xiá","text":"如佛界广狭。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò fù wèn rǔ zhòng shēng jiè xì zài hé chù","text":"若复问汝众生界系在何处。"},{"note":"dāng yún hé dá","text":"当云何答。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ dāng dá yán","text":"我当答言。"},{"note":"rú rú lái xì zhòng shēng yì ěr","text":"如如来系众生亦尔。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò fù wèn rǔ zhòng shēng jiè zhù zài hé chù","text":"若复问汝众生界住在何处。"},{"note":"dāng yún hé dá","text":"当云何答。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ dāng dá yán","text":"我当答言。"},{"note":"zhù niè pán jiè","text":"住涅槃界。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ rú shì xiū bō rě bō luó mì bō rě bō luó mì yǒu zhù chù bù","text":"汝如是修般若波罗蜜般若波罗蜜有住处不。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"bō rě bō luó mì wú yǒu zhù chù","text":"般若波罗蜜无有住处。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"ruò bō rě bō luó mì wú zhù chù zhě rǔ yún hé xiū","text":"若般若波罗蜜无住处者汝云何修。"},{"note":"yún hé xué","text":"云何学。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bō rě bō luó mì yǒu zhù chù zhě","text":"若般若波罗蜜有住处者。"},{"note":"zé wú xiū xué","text":"则无修学。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ xiū bō rě shí","text":"汝修般若时。"},{"note":"yǒu shàn gēn zēng jiǎn bù","text":"有善根增减不。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wú yǒu shàn gēn kě zēng kě jiǎn","text":"无有善根可增可减。"},{"note":"ruò yǒu zēng jiǎn zé fēi xiū bō rě bō luó mì","text":"若有增减则非修般若波罗蜜。"},{"note":"shì zūn","text":"世尊。"},{"note":"bù wèi fǎ zēng bù wèi fǎ jiǎn","text":"不为法增不为法减。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"bù duàn fán fū fǎ bù qǔ rú lái fǎ","text":"不断凡夫法不取如来法。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shì zūn bō rě bō luó mì","text":"世尊般若波罗蜜。"},{"note":"bù wèi dé fǎ gù xiū","text":"不为得法故修。"},{"note":"bù wèi bù dé fǎ gù xiū","text":"不为不得法故修。"},{"note":"bù wèi xiū fǎ gù xiū","text":"不为修法故修。"},{"note":"bù wèi bù xiū fǎ gù xiū","text":"不为不修法故修。"},{"note":"shì zūn","text":"世尊。"},{"note":"wú dé wú shě","text":"无得无舍。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bù wèi shēng sǐ guò huàn","text":"不为生死过患。"},{"note":"bù wèi niè pán gōng dé gù shì zūn","text":"不为涅槃功德故世尊。"},{"note":"ruò rú shì xiū bō rě bō luó mì","text":"若如是修般若波罗蜜。"},{"note":"bù qǔ bù shòu bù shě bù fàng","text":"不取不受不舍不放。"},{"note":"bù zēng bù jiǎn bù qǐ bù miè gù","text":"不增不减不起不灭故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"zuò shì sī wéi","text":"作是思惟。"},{"note":"cǐ fǎ shàng cǐ fǎ zhōng cǐ fǎ xià","text":"此法上此法中此法下。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wú shàng zhōng xià fǎ gù","text":"无上中下法故。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ rú shì xiū bō rě bō luó mì","text":"我如是修般若波罗蜜。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"yī qiè fó fǎ fēi zēng shàng yé","text":"一切佛法非增上耶。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"fó fǎ pú sà fǎ shēng wén fǎ yuán jué fǎ nǎi zhì fán fū fǎ jiē bù kě dé","text":"佛法菩萨法声闻法缘觉法乃至凡夫法皆不可得。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bì jìng kōng gù","text":"毕竟空故。"},{"note":"bì jìng kōng zhōng","text":"毕竟空中。"},{"note":"wú fó fǎ fán fū fǎ","text":"无佛法凡夫法。"},{"note":"fán fū fǎ zhōng wú bì jìng kōng","text":"凡夫法中无毕竟空。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"kōng bù kōng bù kě dé gù","text":"空不空不可得故。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"fó fǎ wú shàng bù","text":"佛法无上不。"},{"note":"wén shū shī lì bái fó yán shì zūn","text":"文殊师利白佛言世尊。"},{"note":"wú yǒu yī fǎ rú wēi chén xǔ míng wèi wú shàng","text":"无有一法如微尘许名为无上。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"tán bō luó mì tán bō luó mì kōng","text":"檀波罗蜜檀波罗蜜空。"},{"note":"nǎi zhì bō rě bō luó mì bō rě bō luó mì kōng","text":"乃至般若波罗蜜般若波罗蜜空。"},{"note":"shí lì shí lì kōng","text":"十力十力空。"},{"note":"sì wú suǒ wèi shí bā bù gòng fǎ nǎi zhì sà pó ruò sà pó ruò kōng","text":"四无所畏十八不共法乃至萨婆若萨婆若空。"},{"note":"kōng zhōng wú wú shàng","text":"空中无无上。"},{"note":"wú shàng zhōng wú kōng","text":"无上中无空。"},{"note":"kōng bù kōng bì jìng bù kě dé gù","text":"空不空毕竟不可得故。"},{"note":"shì zūn","text":"世尊。"},{"note":"bù kě sī yì fǎ shì bō rě bō luó mì","text":"不可思议法是般若波罗蜜。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ bù sī wéi fó fǎ yé","text":"汝不思惟佛法耶。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ ruò sī wéi fó fǎ wǒ zé jiàn fó fǎ wú shàng","text":"我若思惟佛法我则见佛法无上。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wú shàng wú gù","text":"无上无故。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǔ yīn shí èr rù shí bā jiè bì jìng bù kě dé","text":"五阴十二入十八界毕竟不可得。"},{"note":"yī qiè fó fǎ yì bù kě dé","text":"一切佛法亦不可得。"},{"note":"bù kě dé zhōng wú kě dé bù kě dé gù","text":"不可得中无可得不可得故。"},{"note":"shì zūn","text":"世尊。"},{"note":"bō rě bō luó mì zhōng fán fū nǎi zhì fó","text":"般若波罗蜜中凡夫乃至佛。"},{"note":"wú fǎ wú fēi fǎ","text":"无法无非法。"},{"note":"wǒ dāng sī wéi hé fǎ","text":"我当思惟何法。"},{"note":"fó yán","text":"佛言。"},{"note":"shàn nán zi","text":"善男子。"},{"note":"ruò wú sī wéi","text":"若无思惟。"},{"note":"rǔ bù yīng shuō cǐ fán fū fǎ cǐ yuán jué fǎ","text":"汝不应说此凡夫法此缘觉法。"},{"note":"nǎi zhì bù yīng shuō cǐ shì fó fǎ","text":"乃至不应说此是佛法。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bù kě dé gù","text":"不可得故。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ shí bù shuō fán fū fǎ nǎi zhì fó fǎ","text":"我实不说凡夫法乃至佛法。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bù xiū bō rě bō luó mì gù","text":"不修般若波罗蜜故。"},{"note":"fó yán","text":"佛言。"},{"note":"shàn nán zi","text":"善男子。"},{"note":"rǔ yì bù yīng zuò rú shì yì","text":"汝亦不应作如是意。"},{"note":"cǐ yù jiè cǐ sè jiè cǐ wú sè jiè","text":"此欲界此色界此无色界。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bù kě dé gù","text":"不可得故。"},{"note":"shì zūn","text":"世尊。"},{"note":"yù jiè yù jiè xìng kōng","text":"欲界欲界性空。"},{"note":"nǎi zhì wú sè jiè wú sè jiè xìng kōng","text":"乃至无色界无色界性空。"},{"note":"kōng zhōng wú shuō wǒ yì wú shuō","text":"空中无说我亦无说。"},{"note":"shì zūn","text":"世尊。"},{"note":"xiū bō rě bō luó mì","text":"修般若波罗蜜。"},{"note":"bù jiàn shàng bù jiàn bù shàng","text":"不见上不见不上。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shì zūn","text":"世尊。"},{"note":"xiū bō rě bō luó mì","text":"修般若波罗蜜。"},{"note":"bù qǔ fó fǎ bù shě fán fū fǎ","text":"不取佛法不舍凡夫法。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bì jìng kōng zhōng wú qǔ shě gù","text":"毕竟空中无取舍故。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"rǔ néng rú shì shuō shēn bō rě bō luó mì","text":"汝能如是说深般若波罗蜜。"},{"note":"cǐ shì pú sà mó hē sà yìn","text":"此是菩萨摩诃萨印。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"fēi yú qiān wàn fó suǒ shēn zhǒng shàn gēn dé wén cǐ fǎ","text":"非于千万佛所深种善根得闻此法。"},{"note":"nǎi yú wú liàng wú biān fó suǒ shēn zhǒng shàn gēn nǎi dé wén cǐ shèn shēn bō rě bō luó mì bù shēng bù wèi","text":"乃于无量无边佛所深种善根乃得闻此甚深般若波罗蜜不生怖畏。"},{"note":"wén shū shī lì fù bái fó yán","text":"文殊师利复白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ chéng fó wēi shén dāng gèng shuō shèn shēn bō rě bō luó mì","text":"我承佛威神当更说甚深般若波罗蜜。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"zì tīng rǔ shuō","text":"恣听汝说。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù dé fǎ shēng shì xiū bō rě bō luó mì","text":"若不得法生是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhū fǎ wú yǒu shēng gù","text":"诸法无有生故。"},{"note":"ruò bù dé fǎ zhù shì xiū bō rě bō luó mì","text":"若不得法住是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhū fǎ rú shí gù","text":"诸法如实故。"},{"note":"ruò bù dé miè shì xiū bō rě bō luó mì","text":"若不得灭是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhū fǎ jì miè gù","text":"诸法寂灭故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù dé sè shì xiū bō rě bō luó mì nǎi zhì bù dé shí shì xiū bō rě bō luó mì","text":"若不得色是修般若波罗蜜乃至不得识是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhū fǎ rú huàn rú yàn gù","text":"一切诸法如幻如焰故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù dé yǎn shì xiū bō rě bō luó mì","text":"若不得眼是修般若波罗蜜。"},{"note":"nǎi zhì bù dé yì shì xiū bō rě bō luó mì","text":"乃至不得意是修般若波罗蜜。"},{"note":"ruò bù dé sè nǎi zhì fǎ","text":"若不得色乃至法。"},{"note":"bù dé yǎn jiè sè jiè yǎn shí jiè","text":"不得眼界色界眼识界。"},{"note":"nǎi zhì bù dé fǎ jiè yì shí jiè","text":"乃至不得法界意识界。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"ruò bù dé yù jiè shì xiū bō rě bō luó mì","text":"若不得欲界是修般若波罗蜜。"},{"note":"nǎi zhì wú sè jiè yì rú shì","text":"乃至无色界亦如是。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù dé tán bō luó mì","text":"若不得檀波罗蜜。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"nǎi zhì bù dé bō rě bō luó mì","text":"乃至不得般若波罗蜜。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"ruò bù dé fó shí lì sì wú suǒ wèi nǎi zhì shí bā bù gòng fǎ","text":"若不得佛十力四无所畏乃至十八不共法。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"nèi kōng gù","text":"内空故。"},{"note":"nǎi zhì wú fǎ yǒu fǎ kōng gù","text":"乃至无法有法空故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò dé shēng zhù miè","text":"若得生住灭。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"ruò dé wǔ yīn shí èr rù shí bā jiè","text":"若得五阴十二入十八界。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"ruò dé yù jiè sè jiè wú sè jiè","text":"若得欲界色界无色界。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"ruò dé tán nǎi zhì bō rě","text":"若得檀乃至般若。"},{"note":"ruò dé fó shí lì nǎi zhì shí bā bù gòng fǎ","text":"若得佛十力乃至十八不共法。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yǐ yǒu dé gù","text":"以有得故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"wén cǐ shèn shēn bō rě bō luó mì","text":"闻此甚深般若波罗蜜。"},{"note":"bù jīng bù yí bù bù bù tuì","text":"不惊不疑不怖不退。"},{"note":"dāng zhī shì rén jiǔ yú xiān fó shēn zhǒng shàn gēn","text":"当知是人久于先佛深种善根。"},{"note":"wén shū shī lì fù bái fó yán","text":"文殊师利复白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù jiàn gòu fǎ jìng fǎ bù jiàn shēng sǐ guǒ bù jiàn niè pán guǒ","text":"若不见垢法净法不见生死果不见涅槃果。"},{"note":"bù jiàn fó bù jiàn pú sà bù jiàn yuán jué bù jiàn shēng wén bù jiàn fán fū","text":"不见佛不见菩萨不见缘觉不见声闻不见凡夫。"},{"note":"shì xiū bō rě bō luó mì","text":"是修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhū fǎ wú gòu wú jìng","text":"一切诸法无垢无净。"},{"note":"nǎi zhì wú fán fū gù","text":"乃至无凡夫故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò jiàn gòu jìng nǎi zhì jiàn fán fū","text":"若见垢净乃至见凡夫。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò jiàn gòu fǎ chà bié jìng fǎ chà bié","text":"若见垢法差别净法差别。"},{"note":"nǎi zhì jiàn fó chà bié","text":"乃至见佛差别。"},{"note":"fán fū fǎ chà bié","text":"凡夫法差别。"},{"note":"fēi xiū bō rě bō luó mì","text":"非修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bō rě bō luó mì wú chà bié gù","text":"般若波罗蜜无差别故。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"shì zhēn xiū xíng bō rě bō luó mì","text":"是真修行般若波罗蜜。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"rǔ yún hé gòng yǎng fó","text":"汝云何供养佛。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò huàn rén xīn shù miè wǒ zé gòng yǎng fó","text":"若幻人心数灭我则供养佛。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ bù zhù fó fǎ yé","text":"汝不住佛法耶。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"fó wú fǎ kě zhù","text":"佛无法可住。"},{"note":"wǒ yún hé zhù","text":"我云何住。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"ruò wú fǎ kě dé shuí yǒu fó fǎ","text":"若无法可得谁有佛法。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wú yǒu yǒu fó fǎ zhě","text":"无有有佛法者。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ yǐ dào wú suǒ zhù hū","text":"汝已到无所著乎。"},{"note":"wén shū shī lì bái fó","text":"文殊师利白佛。"},{"note":"wú zhe zé wú dào","text":"无着则无到。"},{"note":"yún hé shì zūn wèn yǐ dào wú zhe","text":"云何世尊问已到无着。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"rǔ zhù pú tí bù","text":"汝住菩提不。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"fó shàng bù zhù pú tí","text":"佛尚不住菩提。"},{"note":"hé kuàng wǒ dāng zhù pú tí hū","text":"何况我当住菩提乎。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ hé suǒ yī zuò rú shì shuō","text":"汝何所依作如是说。"},{"note":"wén shū shī lì bái fó","text":"文殊师利白佛。"},{"note":"wǒ wú suǒ yī zuò rú shì shuō","text":"我无所依作如是说。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"rǔ ruò wú yī wèi hé suǒ shuō","text":"汝若无依为何所说。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"rú shì shì zūn","text":"如是世尊。"},{"note":"wǒ wú suǒ shuō","text":"我无所说。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhū fǎ wú míng zì gù","text":"一切诸法无名字故。"},{"note":"ěr shí zhǎng lǎo shè lì fú bái fó yán","text":"尔时长老舍利弗白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò pú sà mó hē sà wén cǐ shēn fǎ","text":"若菩萨摩诃萨闻此深法。"},{"note":"bù jīng yí bù wèi","text":"不惊疑怖畏。"},{"note":"bì dìng dé jìn ā nòu duō luó sān miǎo sān pú tí bù","text":"必定得近阿耨多罗三藐三菩提不。"},{"note":"ěr shí mí lè pú sà bái fó yán","text":"尔时弥勒菩萨白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò zhū pú sà mó hē sà wén cǐ shēn fǎ","text":"若诸菩萨摩诃萨闻此深法。"},{"note":"bù jīng yí bù wèi","text":"不惊疑怖畏。"},{"note":"dé jìn ā nòu duō luó sān miǎo sān pú tí bù","text":"得近阿耨多罗三藐三菩提不。"},{"note":"ěr shí yǒu tiān nǚ míng wú yuán","text":"尔时有天女名无缘。"},{"note":"bái fó yán","text":"白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò shàn nán zi shàn nǚ rén wén cǐ shēn fǎ","text":"若善男子善女人闻此深法。"},{"note":"bù jīng yí bù wèi","text":"不惊疑怖畏。"},{"note":"dāng dé shēng wén fǎ yuán jué fǎ pú sà fǎ fó fǎ bù","text":"当得声闻法缘觉法菩萨法佛法不。"},{"note":"ěr shí fó gào shè lì fú","text":"尔时佛告舍利弗。"},{"note":"rú shì rú shì","text":"如是如是。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"ruò zhū pú sà mó hē sà wén cǐ shēn fǎ","text":"若诸菩萨摩诃萨闻此深法。"},{"note":"bù jīng yí bù wèi","text":"不惊疑怖畏。"},{"note":"bì dìng dāng dé ā nòu duō luó sān miǎo sān pú tí","text":"必定当得阿耨多罗三藐三菩提。"},{"note":"shì shàn nán zi shàn nǚ rén","text":"是善男子善女人。"},{"note":"dāng wèi dà shī zhǔ dì yī shī zhǔ shèng shī zhǔ","text":"当为大施主第一施主胜施主。"},{"note":"dāng jù zú jiè rěn rǔ jīng jìn chán dìng zhì huì","text":"当具足戒忍辱精进禅定智慧。"},{"note":"dāng jù zhū gōng dé chéng jiù xiāng hǎo","text":"当具诸功德成就相好。"},{"note":"zì bù bù wèi lìng rén bù bù wèi","text":"自不怖畏令人不怖畏。"},{"note":"jiū jìng bō rě bō luó mì","text":"究竟般若波罗蜜。"},{"note":"yǐ bù kě dé wú xiāng wú wèi chéng jiù dì yī bù kě sī yì fǎ gù","text":"以不可得无相无为成就第一不可思议法故。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ hé suǒ jiàn hé suǒ lè","text":"汝何所见何所乐。"},{"note":"qiú ā nòu duō luó sān miǎo sān pú tí","text":"求阿耨多罗三藐三菩提。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ wú jiàn wú lè gù qiú pú tí","text":"我无见无乐故求菩提。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"ruò wú jiàn wú lè yì yīng wú qiú","text":"若无见无乐亦应无求。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"rú shì shì zūn","text":"如是世尊。"},{"note":"wǒ shí wú qiú","text":"我实无求。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"ruò yǒu qiú zhě shì fán fū xiāng","text":"若有求者是凡夫相。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ jīn zhēn shí bù qiú pú tí yé","text":"汝今真实不求菩提耶。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"wǒ zhēn shí bù qiú pú tí","text":"我真实不求菩提。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"ruò qiú pú tí shì fán fū xiāng","text":"若求菩提是凡夫相。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ wèi dìng qiú wèi dìng bù qiú","text":"汝为定求为定不求。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"ruò yán dìng qiú dìng bù qiú","text":"若言定求定不求。"},{"note":"dìng qiú bù qiú dìng","text":"定求不求定。"},{"note":"fēi qiú fēi bù qiú","text":"非求非不求。"},{"note":"shì fán fū xiāng","text":"是凡夫相。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"pú tí wú zhù chù gù","text":"菩提无住处故。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"rǔ néng rú shì shuō bō rě bō luó mì","text":"汝能如是说般若波罗蜜。"},{"note":"rǔ xiān yǐ yú wú liàng fó suǒ","text":"汝先已于无量佛所。"},{"note":"shēn zhǒng shàn gēn jiǔ xiū fàn xíng","text":"深种善根久修梵行。"},{"note":"zhū pú sà mó hē sà yīng rú rǔ suǒ shuō xíng","text":"诸菩萨摩诃萨应如汝所说行。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"wǒ bù zhǒng shàn gēn bù xiū fàn xíng","text":"我不种善根不修梵行。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wǒ ruò zhǒng shàn gēn zé yī qiè zhòng shēng yì zhǒng shàn gēn","text":"我若种善根则一切众生亦种善根。"},{"note":"wǒ ruò xiū fàn xíng zé yī qiè zhòng shēng yì xiū fàn xíng","text":"我若修梵行则一切众生亦修梵行。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhòng shēng zé fàn xíng xiāng","text":"一切众生则梵行相。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ hé jiàn hé zhèng shuō rú shì yǔ","text":"汝何见何证说如是语。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"wǒ wú jiàn wú zhèng yì wú suǒ shuō","text":"我无见无证亦无所说。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ bù jiàn fán fū bù jiàn xué bù jiàn wú xué","text":"我不见凡夫不见学不见无学。"},{"note":"bù jiàn fēi xué fēi wú xué","text":"不见非学非无学。"},{"note":"bù jiàn gù bù zhèng","text":"不见故不证。"},{"note":"ěr shí shè lì fú bái wén shū shī lì","text":"尔时舍利弗白文殊师利。"},{"note":"rǔ jiàn fó bù","text":"汝见佛不。"},{"note":"wén shū dá shè lì fú","text":"文殊答舍利弗。"},{"note":"wǒ shàng bù jiàn shēng wén rén","text":"我尚不见声闻人。"},{"note":"hé kuàng wǒ dāng jiàn fó","text":"何况我当见佛。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bù jiàn zhū fǎ gù wèi wèi pú sà","text":"不见诸法故谓为菩萨。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rǔ jīn jué dìng bù jiàn zhū fǎ yé","text":"汝今决定不见诸法耶。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"dà dé dà bǐ qiū","text":"大德大比丘。"},{"note":"rǔ zhǐ bù xū fù shuō","text":"汝止不须复说。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"wèi wèi fó zhě shì shuí yǔ yán","text":"谓为佛者是谁语言。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"fó fēi fó bù kě dé","text":"佛非佛不可得。"},{"note":"wú yǒu yán zhě wú yǒu shuō zhě","text":"无有言者无有说者。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"pú tí zhě bù kě yǐ yán shuō","text":"菩提者不可以言说。"},{"note":"hé kuàng yǒu fó kě yán kě shuō","text":"何况有佛可言可说。"},{"note":"fù cì dà dé shè lì fú","text":"复次大德舍利弗。"},{"note":"rǔ shuō fó zhě shì shuí yǔ yán","text":"汝说佛者是谁语言。"},{"note":"cǐ yǔ yán bù hé bù sàn","text":"此语言不合不散。"},{"note":"bù shēng bù miè bù qù bù lái","text":"不生不灭不去不来。"},{"note":"wú yǒu yī fǎ kě yǔ xiāng yīng","text":"无有一法可与相应。"},{"note":"wú zì wú jù","text":"无字无句。"},{"note":"dà dé shè lì fú yù jiàn fó zhě dāng rú shì xué","text":"大德舍利弗欲见佛者当如是学。"},{"note":"ěr shí shè lì fú bái fó yán","text":"尔时舍利弗白佛言。"},{"note":"shì zūn cǐ wén shū shī lì suǒ shuō","text":"世尊此文殊师利所说。"},{"note":"xīn fā yì pú sà suǒ bù néng jiě","text":"新发意菩萨所不能解。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"rú shì rú shì","text":"如是如是。"},{"note":"dà dé shè lì fú","text":"大德舍利弗。"},{"note":"pú tí fēi kě jiě","text":"菩提非可解。"},{"note":"xīn fā yì zhě yún hé dāng jiě","text":"新发意者云何当解。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"zhū fó rú lái bù jué fǎ jiè yé","text":"诸佛如来不觉法界耶。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"zhū fó shàng bù kě dé","text":"诸佛尚不可得。"},{"note":"yún hé yǒu fó jué fǎ jiè","text":"云何有佛觉法界。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"fǎ jiè shàng bù kě dé","text":"法界尚不可得。"},{"note":"yún hé fǎ jiè wèi zhū fó suǒ jué","text":"云何法界为诸佛所觉。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"fǎ jiè zhě jí shì pú tí","text":"法界者即是菩提。"},{"note":"pú tí zhě jí shì fǎ jiè","text":"菩提者即是法界。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhū fǎ wú jiè gù","text":"诸法无界故。"},{"note":"dà dé shè lì fú","text":"大德舍利弗。"},{"note":"fǎ jiè fó jìng jiè wú yǒu chà bié","text":"法界佛境界无有差别。"},{"note":"wú chà bié zhě jí shì wú zuò","text":"无差别者即是无作。"},{"note":"wú zuò zhě jí shì wú wèi","text":"无作者即是无为。"},{"note":"wú wèi zhě jí shì wú shuō","text":"无为者即是无说。"},{"note":"wú shuō zhě jí wú suǒ yǒu","text":"无说者即无所有。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"yī qiè fǎ jiè jí fó jìng jiè","text":"一切法界及佛境界。"},{"note":"xī wú suǒ yǒu yé","text":"悉无所有耶。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"wú yǒu wú bù yǒu","text":"无有无不有。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yǒu jí bù yǒu yī xiāng wú xiāng wú yī wú èr gù","text":"有及不有一相无相无一无二故。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rú shì xué zhě dāng dé pú tí yé","text":"如是学者当得菩提耶。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"rú shì xué wú suǒ xué","text":"如是学无所学。"},{"note":"bù shēng shàn dào bù duò è qù","text":"不生善道不堕恶趣。"},{"note":"bù dé pú tí bù rù niè pán","text":"不得菩提不入涅槃。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shè lì fú","text":"舍利弗。"},{"note":"bō rě bō luó mì bì jìng kōng gù","text":"般若波罗蜜毕竟空故。"},{"note":"bì jìng kōng zhōng wú yī wú èr wú sān wú sì","text":"毕竟空中无一无二无三无四。"},{"note":"wú yǒu qù lái bù kě sī yì","text":"无有去来不可思议。"},{"note":"dà dé shè lì fú","text":"大德舍利弗。"},{"note":"ruò yán wǒ dé pú tí shì zēng shàng màn shuō","text":"若言我得菩提是增上慢说。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wú dé wèi dé gù","text":"无得谓得故。"},{"note":"rú shì zēng shàng màn rén bù kān shòu rén xìn shī","text":"如是增上慢人不堪受人信施。"},{"note":"yǒu xìn rén bù yīng gòng yǎng","text":"有信人不应供养。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rǔ hé suǒ yī zuò rú shì shuō","text":"汝何所依作如是说。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"wǒ wú suǒ yī zuò rú shì shuō","text":"我无所依作如是说。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bō rě bō luó mì yǔ zhū fǎ děng gù","text":"般若波罗蜜与诸法等故。"},{"note":"zhū fǎ wú suǒ yī yǐ píng děng gù","text":"诸法无所依以平等故。"},{"note":"shè lì fú bái wén shū shī lì","text":"舍利弗白文殊师利。"},{"note":"rǔ bù yǐ zhì huì chú duàn fán nǎo yé","text":"汝不以智慧除断烦恼耶。"},{"note":"wén shū shī lì dá shè lì fú","text":"文殊师利答舍利弗。"},{"note":"rǔ shì lòu jǐn ā luó hàn bù","text":"汝是漏尽阿罗汉不。"},{"note":"shè lì fú yán","text":"舍利弗言。"},{"note":"bù yě","text":"不也。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"wǒ yì bù yǐ zhì huì chú duàn fán nǎo","text":"我亦不以智慧除断烦恼。"},{"note":"shè lì fú yán rǔ hé suǒ yī zuò rú shì shuō","text":"舍利弗言汝何所依作如是说。"},{"note":"bù bù bù wèi","text":"不怖不畏。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"wǒ shàng bù kě dé","text":"我尚不可得。"},{"note":"dāng yǒu hé wǒ ér shēng bù wèi","text":"当有何我而生怖畏。"},{"note":"shè lì fú yán","text":"舍利弗言。"},{"note":"shàn zāi wén shū shī lì","text":"善哉文殊师利。"},{"note":"kuài shuō rú shì shén shēn bō rě bō luó mì","text":"快说如是什深般若波罗蜜。"},{"note":"ěr shí fó gào wén shū shī lì yán","text":"尔时佛告文殊师利言。"},{"note":"shàn nán zi","text":"善男子。"},{"note":"yǒu pú sà mó hē sà zhù pú tí xīn qiú wú shàng pú tí bù","text":"有菩萨摩诃萨住菩提心求无上菩提不。"},{"note":"wén shū shī lì bái fó yán shì zūn","text":"文殊师利白佛言世尊。"},{"note":"wú pú sà zhù pú tí xīn qiú wú shàng pú tí","text":"无菩萨住菩提心求无上菩提。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"pú tí xīn bù kě dé","text":"菩提心不可得。"},{"note":"wú shàng pú tí yì bù kě dé","text":"无上菩提亦不可得。"},{"note":"wǔ wú jiān zuì shì pú tí xìng","text":"五无间罪是菩提性。"},{"note":"wú yǒu pú sà qǐ wú jiān xīn qiú wú jiān zuì guǒ","text":"无有菩萨起无间心求无间罪果。"},{"note":"yún hé yǒu pú sà zhù pú tí xīn qiú wú shàng pú tí","text":"云何有菩萨住菩提心求无上菩提。"},{"note":"pú tí zhě shì yī qiè zhū fǎ","text":"菩提者是一切诸法。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"sè fēi sè bù kě dé gù","text":"色非色不可得故。"},{"note":"nǎi zhì shí fēi shí yì bù kě dé","text":"乃至识非识亦不可得。"},{"note":"yǎn bù kě dé nǎi zhì yì bù kě dé sè bù kě dé nǎi zhì fǎ bù kě dé yǎn jiè nǎi zhì fǎ jiè yì bù kě dé","text":"眼不可得乃至意不可得色不可得乃至法不可得眼界乃至法界亦不可得。"},{"note":"shēng bù kě dé nǎi zhì lǎo sǐ yì bù kě dé","text":"生不可得乃至老死亦不可得。"},{"note":"tán bō luó mì bù kě dé","text":"檀波罗蜜不可得。"},{"note":"nǎi zhì bō rě bō luó mì yì bù kě dé","text":"乃至般若波罗蜜亦不可得。"},{"note":"fó shí lì bù kě dé","text":"佛十力不可得。"},{"note":"nǎi zhì shí bā bù gòng fǎ yì bù kě dé","text":"乃至十八不共法亦不可得。"},{"note":"pú tí xīn wú shàng pú tí jiē bù kě dé","text":"菩提心无上菩提皆不可得。"},{"note":"bù kě dé zhōng wú kě dé bù kě dé","text":"不可得中无可得不可得。"},{"note":"shì gù shì zūn","text":"是故世尊。"},{"note":"wú pú sà zhù pú tí xīn qiú wú shàng pú tí zhě","text":"无菩萨住菩提心求无上菩提者。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ yì wèi rú lái shì rǔ shī bù","text":"汝意谓如来是汝师不。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"wǒ wú yǒu yì wèi fó shì wǒ shī","text":"我无有意谓佛是我师。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ shàng bù kě dé","text":"我尚不可得。"},{"note":"hé kuàng dāng yǒu yì wèi fó shì wǒ shī","text":"何况当有意谓佛是我师。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ yú wǒ yǒu yí bù","text":"汝于我有疑不。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ shàng wú jué dìng","text":"我尚无决定。"},{"note":"hé kuàng dāng yǒu yí","text":"何况当有疑。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"xiān dìng hòu yí gù","text":"先定后疑故。"},{"note":"fó gào wén shū rǔ bù dìng yán rú lái shēng yé","text":"佛告文殊汝不定言如来生耶。"},{"note":"wén shū bái fó","text":"文殊白佛。"},{"note":"rú lái ruò shēng fǎ jiè yì yīng shēng","text":"如来若生法界亦应生。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"fǎ jiè rú lái yī xiāng wú èr xiāng","text":"法界如来一相无二相。"},{"note":"èr xiāng bù kě dé gù","text":"二相不可得故。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"rǔ xìn zhū fó rú lái rù niè pán bù","text":"汝信诸佛如来入涅槃不。"},{"note":"wén shū yán","text":"文殊言。"},{"note":"yī qiè zhū fó jí niè pán xiāng","text":"一切诸佛即涅槃相。"},{"note":"niè pán xiāng zhě wú rù wú bù rù","text":"涅槃相者无入无不入。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ yán zhū fó yǒu liú zhuǎn bù","text":"汝言诸佛有流转不。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn bù liú zhuǎn shàng bù kě dé","text":"世尊不流转尚不可得。"},{"note":"hé kuàng liú zhuǎn dāng kě dé","text":"何况流转当可得。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rú lái wú xīn","text":"如来无心。"},{"note":"wéi rú lái qián kě shuō cǐ yán huò lòu jǐn ā luó hàn jí bù tuì pú sà qián kě shuō cǐ yán","text":"唯如来前可说此言或漏尽阿罗汉及不退菩萨前可说此言。"},{"note":"ruò yú rén wén","text":"若余人闻。"},{"note":"cǐ yǔ zé bù shēng xìn qǐ jīng yí","text":"此语则不生信起惊疑。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"cǐ shèn shēn bō rě bō luó mì","text":"此甚深般若波罗蜜。"},{"note":"nán xìn nán jiě gù","text":"难信难解故。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"fù hé děng rén néng xìn cǐ shèn shēn fǎ","text":"复何等人能信此甚深法。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"yī qiè fán fū néng xìn cǐ fǎ","text":"一切凡夫能信此法。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"rú lái wú xīn yī qiè fán fū yì wú xīn gù","text":"如来无心一切凡夫亦无心故。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"hé gù zuò rú shì shuō fǎ","text":"何故作如是说法。"},{"note":"xīn fā yì pú sà jí ā luó hàn xián jiē yǒu yí","text":"新发意菩萨及阿罗汉咸皆有疑。"},{"note":"yuàn wén jiě shuō","text":"愿闻解说。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"rú shí xiāng fǎ xìng fǎ zhù fǎ wèi shí jì zhōng yǒu fó yǒu fán fū chà bié bù","text":"如实相法性法住法位实际中有佛有凡夫差别不。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"bù yě shì zūn","text":"不也世尊。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"ruò wú chà bié hé gù shēng yí","text":"若无差别何故生疑。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn wú chà bié zhōng yǒu fó yǒu fán fū bù","text":"世尊无差别中有佛有凡夫不。"},{"note":"fó yán yǒu","text":"佛言有。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"fó yǔ fán fū wú èr wú chà bié","text":"佛与凡夫无二无差别。"},{"note":"yī xiāng wú xiāng gù","text":"一相无相故。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"rǔ xìn rú lái yú yī qiè zhòng shēng zhōng zuì shèng bù","text":"汝信如来于一切众生中最胜不。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ xìn rú lái yú yī qiè zhòng shēng zhōng zuì shèng","text":"我信如来于一切众生中最胜。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò wǒ xìn rú lái yú yī qiè zhòng shēng zhōng zuì shèng","text":"若我信如来于一切众生中最胜。"},{"note":"zé rú lái chéng bù zuì shèng","text":"则如来成不最胜。"},{"note":"fó gào wén shū","text":"佛告文殊。"},{"note":"rǔ xìn rú lái chéng jiù yī qiè bù kě sī yì fǎ bù","text":"汝信如来成就一切不可思议法不。"},{"note":"wén shū shī lì bái fó yán","text":"文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ xìn rú lái chéng jiù yī qiè bù kě sī yì fǎ","text":"我信如来成就一切不可思议法。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ ruò xìn rú lái chéng jiù yī qiè bù kě sī yì fǎ","text":"我若信如来成就一切不可思议法。"},{"note":"rú lái zé chéng kě sī yì","text":"如来则成可思议。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ xìn yī qiè shēng wén shì rú lái suǒ jiào huà bù","text":"汝信一切声闻是如来所教化不。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ xìn yī qiè shēng wén shì rú lái suǒ jiào huà","text":"我信一切声闻是如来所教化。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ ruò xìn yī qiè shēng wén shì rú lái suǒ jiào huà","text":"我若信一切声闻是如来所教化。"},{"note":"zé fǎ jiè chéng kě jiào huà","text":"则法界成可教化。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ xìn rú lái shì wú shàng fú tián bù","text":"汝信如来是无上福田不。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ xìn rú lái shì wú shàng fú tián","text":"我信如来是无上福田。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ ruò xìn rú lái shì wú shàng fú tián","text":"我若信如来是无上福田。"},{"note":"rú lái zé fēi fú tián","text":"如来则非福田。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rǔ hé suǒ yī zuò rú shì dá wǒ","text":"汝何所依作如是答我。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ wú suǒ yī zuò rú shì dá","text":"我无所依作如是答。"},{"note":"shì zūn","text":"世尊。"},{"note":"wú suǒ yī zhōng wú shèng wú bù shèng","text":"无所依中无胜无不胜。"},{"note":"wú kě sī yì wú bù kě sī yì","text":"无可思议无不可思议。"},{"note":"wú jiào huà wú bù jiào huà","text":"无教化无不教化。"},{"note":"wú fú tián wú fēi fú tián","text":"无福田无非福田。"},{"note":"shì shí yǐ fó shén lì dì liù zhǒng zhèn dòng","text":"是时以佛神力地六种震动。"},{"note":"yī wàn liù qiān bǐ qiū zhòng","text":"一万六千比丘众。"},{"note":"yǐ wú kě qǔ xīn dé jiě tuō qī bǎi bǐ qiū ní zhòng","text":"以无可取心得解脱七百比丘尼众。"},{"note":"sān qiān yōu pó sāi sì wàn yōu pó yí zhòng","text":"三千优婆塞四万优婆夷众。"},{"note":"yuǎn chén lí gòu dé fǎ yǎn jìng","text":"远尘离垢得法眼净。"},{"note":"liù wàn yì nà yóu tā zhū tiān","text":"六万亿那由他诸天。"},{"note":"yuǎn chén lí gòu dé fǎ yǎn jìng","text":"远尘离垢得法眼净。"},{"note":"shì shí zhǎng lǎo ā nán jí cóng zuò qǐ","text":"是时长老阿难即从座起。"},{"note":"piān tǎn yòu jiān yòu xī zhe dì","text":"偏袒右肩右膝着地。"},{"note":"hé zhǎng gōng jìng bái fó yán","text":"合掌恭敬白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"hé yīn hé yuán cǐ dì dà dòng","text":"何因何缘此地大动。"},{"note":"ěr shí fó gào ā nán","text":"尔时佛告阿难。"},{"note":"cǐ shuō bō rě bō luó mì","text":"此说般若波罗蜜。"},{"note":"wǎng gǔ zhū fó jiē yú cǐ chù shuō cǐ fǎ","text":"往古诸佛皆于此处说此法。"},{"note":"yǐ shì yīn yuán gù cǐ dì zhèn dòng","text":"以是因缘故此地震动。"},{"note":"ěr shí zhǎng lǎo shè lì fú bái fó yán","text":"尔时长老舍利弗白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"cǐ wén shū shī lì suǒ shuō bù kě sī yì","text":"此文殊师利所说不可思议。"},{"note":"ěr shí shì zūn gào wén shū shī lì","text":"尔时世尊告文殊师利。"},{"note":"rú shè lì fú suǒ shuō","text":"如舍利弗所说。"},{"note":"cǐ wén shū shī lì suǒ shuō bù kě sī yì","text":"此文殊师利所说不可思议。"},{"note":"ěr shí wén shū shī lì bái fó yán","text":"尔时文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò bù kě sī yì zé bù kě shuō","text":"若不可思议则不可说。"},{"note":"ruò kě shuō zé kě sī yì","text":"若可说则可思议。"},{"note":"bù kě sī yì zhě wú suǒ yǒu","text":"不可思议者无所有。"},{"note":"bǐ yī qiè shēng yì bù kě sī yì","text":"彼一切声亦不可思议。"},{"note":"bù kě sī yì zhě wú shēng","text":"不可思议者无声。"},{"note":"fó yán","text":"佛言。"},{"note":"rǔ rù bù sī yì sān mèi yé","text":"汝入不思议三昧耶。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"bù yě shì zūn","text":"不也世尊。"},{"note":"wǒ jí bù sī yì","text":"我即不思议。"},{"note":"bù jiàn yǒu xīn néng sī yì zhě","text":"不见有心能思议者。"},{"note":"yún hé ér yán rù bù sī yì sān mèi","text":"云何而言入不思议三昧。"},{"note":"wǒ chū fā xīn yù rù shì dìng","text":"我初发心欲入是定。"},{"note":"ér jīn sī wéi","text":"而今思惟。"},{"note":"shí wú xīn xiāng ér rù sān mèi","text":"实无心相而入三昧。"},{"note":"rú rén xué shè jiǔ xí zé qiǎo","text":"如人学射久习则巧。"},{"note":"hòu suī wú xīn yǐ jiǔ xí gù jiàn fā jiē zhōng","text":"后虽无心以久习故箭发皆中。"},{"note":"wǒ yì rú shì","text":"我亦如是。"},{"note":"chū xué bù sī yì sān mèi xì xīn yī yuán","text":"初学不思议三昧系心一缘。"},{"note":"ruò jiǔ xí chéng jiù gèng wú xīn xiǎng héng yǔ dìng hé","text":"若久习成就更无心想恒与定合。"},{"note":"shè lì fú yǔ wén shū shī lì yán","text":"舍利弗语文殊师利言。"},{"note":"gèng yǒu shèng miào jì miè dìng bù","text":"更有胜妙寂灭定不。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"ruò yǒu bù sī yì dìng zhě","text":"若有不思议定者。"},{"note":"rǔ kě wèn yán gèng yǒu jì miè dìng bù","text":"汝可问言更有寂灭定不。"},{"note":"rú wǒ yì jiě","text":"如我意解。"},{"note":"bù kě sī yì dìng shàng bù kě dé","text":"不可思议定尚不可得。"},{"note":"yún hé wèn wǒ jì miè dìng hū","text":"云何问我寂灭定乎。"},{"note":"shè lì fú yán","text":"舍利弗言。"},{"note":"bù sī yì dìng bù kě dé yé","text":"不思议定不可得耶。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"sī yì dìng zhě shì kě dé xiāng","text":"思议定者是可得相。"},{"note":"bù kě sī yì dìng zhě bù kě dé xiāng","text":"不可思议定者不可得相。"},{"note":"yī qiè zhòng shēng shí chéng jiù bù kě sī yì dìng","text":"一切众生实成就不可思议定。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè xīn xiāng jí fēi xīn gù","text":"一切心相即非心故。"},{"note":"shì míng bù sī yì dìng","text":"是名不思议定。"},{"note":"shì gù yī qiè zhòng shēng xiāng jí bù sī yì sān mèi xiāng","text":"是故一切众生相及不思议三昧相。"},{"note":"děng wú fēn bié","text":"等无分别。"},{"note":"fó zàn wén shū shī lì yán","text":"佛赞文殊师利言。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"rǔ yú zhū fó","text":"汝于诸佛。"},{"note":"jiǔ zhí shàn gēn jìng xiū fàn xíng","text":"久殖善根净修梵行。"},{"note":"nǎi néng yǎn shuō shèn shēn sān mèi","text":"乃能演说甚深三昧。"},{"note":"rǔ jīn ān zhù rú shì bō rě bō luó mì zhōng","text":"汝今安住如是般若波罗蜜中。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"ruò wǒ zhù bō rě bō luó mì zhōng","text":"若我住般若波罗蜜中。"},{"note":"néng zuò shì shuō","text":"能作是说。"},{"note":"jí shì yǒu xiǎng biàn zhù wǒ xiǎng","text":"即是有想便住我想。"},{"note":"ruò zhù yǒu xiǎng wǒ xiǎng zhōng zhě","text":"若住有想我想中者。"},{"note":"bō rě bō luó mì biàn yǒu chù suǒ","text":"般若波罗蜜便有处所。"},{"note":"bō rě bō luó mì ruò zhù yú wú","text":"般若波罗蜜若住于无。"},{"note":"yì shì wǒ xiǎng yì míng chù suǒ","text":"亦是我想亦名处所。"},{"note":"lí cǐ èr chù zhù wú suǒ zhù","text":"离此二处住无所住。"},{"note":"rú zhū fó zhù ān chù jì miè fēi sī yì jìng jiè","text":"如诸佛住安处寂灭非思议境界。"},{"note":"rú shì bù sī yì","text":"如是不思议。"},{"note":"míng bō rě bō luó mì zhù chù","text":"名般若波罗蜜住处。"},{"note":"bō rě bō luó mì chù","text":"般若波罗蜜处。"},{"note":"yī qiè fǎ wú xiāng","text":"一切法无相。"},{"note":"yī qiè fǎ wú zuò","text":"一切法无作。"},{"note":"bō rě bō luó mì jí bù sī yì","text":"般若波罗蜜即不思议。"},{"note":"bù sī yì jí fǎ jiè","text":"不思议即法界。"},{"note":"fǎ jiè jí wú xiāng","text":"法界即无相。"},{"note":"wú xiāng jí bù sī yì","text":"无相即不思议。"},{"note":"bù sī yì jí bō rě bō luó mì","text":"不思议即般若波罗蜜。"},{"note":"bō rě bō luó mì fǎ jiè wú èr wú bié wú èr wú bié jí fǎ jiè","text":"般若波罗蜜法界无二无别无二无别即法界。"},{"note":"fǎ jiè jí wú xiāng","text":"法界即无相。"},{"note":"wú xiāng jí bō rě bō luó mì jiè","text":"无相即般若波罗蜜界。"},{"note":"bō rě bō luó mì jiè jí bù sī yì jiè","text":"般若波罗蜜界即不思议界。"},{"note":"bù sī yì jiè jí wú shēng wú miè jiè","text":"不思议界即无生无灭界。"},{"note":"wú shēng wú miè jiè jí bù sī yì jiè","text":"无生无灭界即不思议界。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"rú lái jiè jí wǒ jiè jí bù èr xiāng","text":"如来界及我界即不二相。"},{"note":"rú shì xiū bō rě bō luó mì zhě","text":"如是修般若波罗蜜者。"},{"note":"jí bù qiú pú tí","text":"即不求菩提。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"pú tí xiāng lí jí bō rě bō luó mì gù","text":"菩提相离即般若波罗蜜故。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò zhī wǒ xiāng ér bù kě zhe","text":"若知我相而不可着。"},{"note":"wú zhī wú zhe shì fó suǒ zhī","text":"无知无着是佛所知。"},{"note":"bù kě sī yì wú zhī wú zhe jí fó suǒ zhī","text":"不可思议无知无着即佛所知。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhī tǐ běn xìng wú suǒ yǒu xiāng","text":"知体本性无所有相。"},{"note":"yún hé néng zhuǎn fǎ jiè","text":"云何能转法界。"},{"note":"ruò zhī běn xìng wú tǐ wú zhù zhě","text":"若知本性无体无著者。"},{"note":"jí míng wú wù","text":"即名无物。"},{"note":"ruò wú yǒu wù shì wú chù suǒ wú yī wú zhù wú yī wú zhù jí wú shēng wú miè","text":"若无有物是无处所无依无住无依无住即无生无灭。"},{"note":"wú shēng wú miè jí shì yǒu wèi gōng dé","text":"无生无灭即是有为功德。"},{"note":"ruò rú shì zhī zé wú xīn xiǎng","text":"若如是知则无心想。"},{"note":"wú xīn xiǎng zhě yún hé dāng zhī","text":"无心想者云何当知。"},{"note":"yǒu wèi wú wèi gōng dé","text":"有为无为功德。"},{"note":"wú zhī jí bù sī yì","text":"无知即不思议。"},{"note":"bù sī yì zhě shì fó suǒ zhī","text":"不思议者是佛所知。"},{"note":"yì wú qǔ wú bù qǔ bù jiàn sān shì qù lái děng xiāng","text":"亦无取无不取不见三世去来等相。"},{"note":"bù qǔ shēng miè jí zhū qǐ zuò","text":"不取生灭及诸起作。"},{"note":"yì bù duàn bù cháng","text":"亦不断不常。"},{"note":"rú shì zhī zhě shì míng zhèng zhì bù sī yì zhì","text":"如是知者是名正智不思议智。"},{"note":"rú xū kōng wú cǐ wú bǐ","text":"如虚空无此无彼。"},{"note":"bù kě bǐ lèi","text":"不可比类。"},{"note":"wú hǎo è","text":"无好恶。"},{"note":"wú děng děng","text":"无等等。"},{"note":"wú xiāng wú mào","text":"无相无貌。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"ruò rú shì zhī míng bù tuì zhì","text":"若如是知名不退智。"},{"note":"wén shū shī lì yán","text":"文殊师利言。"},{"note":"wú zuò zhì míng bù tuì zhì","text":"无作智名不退智。"},{"note":"yóu rú jīn chán xiān jiā chuí dǎ fāng zhī hǎo è","text":"犹如金鋋先加搥打方知好恶。"},{"note":"ruò bù zhì dǎ wú néng zhī zhě","text":"若不治打无能知者。"},{"note":"bù tuì zhì xiāng yì fù rú shì","text":"不退智相亦复如是。"},{"note":"yào xíng jìng jiè","text":"要行境界。"},{"note":"bù niàn bù zhe wú qǐ wú zuò","text":"不念不着无起无作。"},{"note":"jù zú bù dòng bù shēng bù miè","text":"具足不动不生不灭。"},{"note":"ěr nǎi xiǎn xiàn","text":"尔乃显现。"},{"note":"ěr shí fó gào wén shū shī lì yán","text":"尔时佛告文殊师利言。"},{"note":"zhū rú lái zì shuō jǐ zhì","text":"诸如来自说己智。"},{"note":"shuí dāng néng xìn","text":"谁当能信。"},{"note":"wén shū yán","text":"文殊言。"},{"note":"rú shì zhì zhě fēi niè pán fǎ fēi shēng sǐ fǎ","text":"如是智者非涅槃法非生死法。"},{"note":"shì jì miè xíng","text":"是寂灭行。"},{"note":"bù duàn tān yù chēn huì yú chī","text":"不断贪欲瞋恚愚痴。"},{"note":"yì fēi bù duàn","text":"亦非不断。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wú jǐn wú miè","text":"无尽无灭。"},{"note":"bù lí shēng sǐ yì fēi bù lí","text":"不离生死亦非不离。"},{"note":"bù lí xiū dào fēi bù xiū dào","text":"不离修道非不修道。"},{"note":"zuò shì jiě zhě míng wèi zhèng xìn fó gào wén shū shī lì yán","text":"作是解者名为正信佛告文殊师利言。"},{"note":"shàn zāi shàn zāi","text":"善哉善哉。"},{"note":"rú rǔ suǒ shuō","text":"如汝所说。"},{"note":"shēn jiě sī yì","text":"深解斯义。"},{"note":"ěr shí zhǎng lǎo mó hē jiā shè bái fó yán","text":"尔时长老摩诃迦叶白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wèi lái shì shuí néng xìn cǐ shēn fǎ","text":"未来世谁能信此深法。"},{"note":"shuí lè tīng cǐ fǎ","text":"谁乐听此法。"},{"note":"fó gào jiā shè","text":"佛告迦叶。"},{"note":"jí jīn rì sì zhòng bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"即今日四众比丘比丘尼优婆塞优婆夷。"},{"note":"yú wèi lái shì néng xìn cǐ fǎ","text":"于未来世能信此法。"},{"note":"wén shuō cǐ shēn bō rě bō luó mì","text":"闻说此深般若波罗蜜。"},{"note":"dāng zhī cǐ fǎ dāng qiú cǐ fǎ","text":"当知此法当求此法。"},{"note":"jiā shè pì rú zhǎng zhě huò zhǎng zhě zi","text":"迦叶譬如长者或长者子。"},{"note":"yǐ shī yī dà bǎo zhū jià zhí yì wàn liǎng jīn","text":"已失一大宝珠价直亿万两金。"},{"note":"dà shēng yōu nǎo","text":"大生忧恼。"},{"note":"jīn gèng hái dé shēng dà huān xǐ yōu nǎo xī miè","text":"今更还得生大欢喜忧恼悉灭。"},{"note":"rú shì jiā shè","text":"如是迦叶。"},{"note":"bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"比丘比丘尼优婆塞优婆夷。"},{"note":"yú wèi lái shì wén cǐ zuì shēn bō rě bō luó mì jīng","text":"于未来世闻此最深般若波罗蜜经。"},{"note":"yǔ bō rě xiāng yīng","text":"与般若相应。"},{"note":"wén yǐ shēng xǐ xīn dé ān lè","text":"闻已生喜心得安乐。"},{"note":"wú fù yōu nǎo yì fù rú shì","text":"无复忧恼亦复如是。"},{"note":"dāng zuò shì yán","text":"当作是言。"},{"note":"wǒ děng jīn rì dé jiàn rú lái gòng yǎng rú lái","text":"我等今日得见如来供养如来。"},{"note":"suǒ yǐ zhě hé","text":"所以者何。"},{"note":"yǐ dé wén cǐ shèn shēn wēi miào liù bō luó mì gù","text":"以得闻此甚深微妙六波罗蜜故。"},{"note":"jiā shè","text":"迦叶。"},{"note":"pì rú sān shí sān tiān jiàn bō lì zhì duō luó shù chū shēng pào shí","text":"譬如三十三天见波利质多罗树初生疱时。"},{"note":"zuò rú shì niàn","text":"作如是念。"},{"note":"cǐ pào bù jiǔ bì dāng kāi fū","text":"此疱不久必当开敷。"},{"note":"rú shì jiā shè","text":"如是迦叶。"},{"note":"bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"比丘比丘尼优婆塞优婆夷。"},{"note":"wén cǐ bō rě bō luó mì jīng xīn shēng huān xǐ","text":"闻此般若波罗蜜经心生欢喜。"},{"note":"yì fù rú shì","text":"亦复如是。"},{"note":"wǒ yú lái shì bì dé cǐ fǎ","text":"我于来世必得此法。"},{"note":"jiā shè","text":"迦叶。"},{"note":"cǐ shēn bō rě bō luó mì rú lái miè hòu","text":"此深般若波罗蜜如来灭后。"},{"note":"dāng zhù bù miè chù chù liú xíng","text":"当住不灭处处流行。"},{"note":"jiā shè","text":"迦叶。"},{"note":"yǐ fó lì gù","text":"以佛力故。"},{"note":"wèi lái shì zhōng ruò shàn nán zi shàn nǚ rén","text":"未来世中若善男子善女人。"},{"note":"dāng dé cǐ shēn bō rě bō luó mì","text":"当得此深般若波罗蜜。"},{"note":"jiā shè","text":"迦叶。"},{"note":"rú mó ní zhū shī jiàn mó ní bǎo xīn shēng huān xǐ","text":"如摩尼珠师见摩尼宝心生欢喜。"},{"note":"bù jiǎ sī liàng jí zhī zhēn wěi","text":"不假思量即知真伪。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yǐ chuàn jiàn gù","text":"以串见故。"},{"note":"rú shì jiā shè","text":"如是迦叶。"},{"note":"ruò rén wén cǐ bō rě bō luó mì xiāng yīng fǎ","text":"若人闻此般若波罗蜜相应法。"},{"note":"wén yǐ huān xǐ shēng xìn lè xīn","text":"闻已欢喜生信乐心。"},{"note":"dāng zhī cǐ rén xiān shì yǐ wén cǐ bō rě bō luó mì cóng jiǔ yuǎn jié lái yǐ céng gòng yǎng zhū fó","text":"当知此人先世已闻此般若波罗蜜从久远劫来已曾供养诸佛。"},{"note":"jiā shè bái fó yán","text":"迦叶白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"cǐ shàn nán zi shàn nǚ rén jīn wén cǐ fǎ","text":"此善男子善女人今闻此法。"},{"note":"yú wèi lái shì zhuǎn fù xìn jiě","text":"于未来世转复信解。"},{"note":"fó gào mó hē jiā shè","text":"佛告摩诃迦叶。"},{"note":"rú shì rú shì","text":"如是如是。"},{"note":"rú rǔ suǒ shuō","text":"如汝所说。"},{"note":"ěr shí wén shū shī lì bái fó yán","text":"尔时文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"cǐ fǎ wú xíng wú xiāng","text":"此法无行无相。"},{"note":"shuō cǐ fǎ zhě yì wú xíng wú xiāng","text":"说此法者亦无行无相。"},{"note":"yún hé shì zūn","text":"云何世尊。"},{"note":"shuō yǒu xíng xiāng","text":"说有行相。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"wǒ běn xíng","text":"我本行。"},{"note":"pú sà dào shí","text":"菩萨道时。"},{"note":"xiū zhū shàn gēn","text":"修诸善根。"},{"note":"yù zhù ā wéi yuè zhì dì","text":"欲住阿惟越致地。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù chéng ā nòu duō luó sān miǎo sān pú tí","text":"欲成阿耨多罗三藐三菩提。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"ruò shàn nán zi shàn nǚ rén yù jiě yī qiè fǎ xiāng","text":"若善男子善女人欲解一切法相。"},{"note":"yù zhī yī qiè zhòng shēng xīn jiè jiē xī tóng děng","text":"欲知一切众生心界皆悉同等。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"wén shū shī lì yù xué yī qiè fó fǎ jù zú wú ài","text":"文殊师利欲学一切佛法具足无碍。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù xué yī qiè fó chéng ā nòu duō luó sān miǎo sān pú tí shí xiāng hǎo wēi yí wú liàng fǎ shì","text":"欲学一切佛成阿耨多罗三藐三菩提时相好威仪无量法式。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù zhī yī qiè fó bù chéng ā nòu duō luó sān miǎo sān pú tí yī qiè fǎ shì jí zhū wēi yí dāng xué bō rě bō luó mì","text":"欲知一切佛不成阿耨多罗三藐三菩提一切法式及诸威仪当学般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"shì kōng fǎ zhōng bù jiàn zhū fó pú tí děng gù","text":"是空法中不见诸佛菩提等故。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"yù zhī rú shì děng xiāng wú yí huò zhě","text":"欲知如是等相无疑惑者。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"bō rě bō luó mì","text":"般若波罗蜜。"},{"note":"bù jiàn zhū fǎ ruò shēng ruò miè ruò gòu ruò jìng","text":"不见诸法若生若灭若垢若净。"},{"note":"shì gù shàn nán zi shàn nǚ rén","text":"是故善男子善女人。"},{"note":"yīng zuò rú shì xué bō rě bō luó mì","text":"应作如是学般若波罗蜜。"},{"note":"yù zhī yī qiè fǎ wú guò qù wèi lái xiàn zài děng xiāng","text":"欲知一切法无过去未来现在等相。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"fǎ jiè xìng xiāng wú qù lái xiàn zài gù","text":"法界性相无去来现在故。"},{"note":"yù zhī yī qiè fǎ tóng rù fǎ jiè xīn wú guà ài","text":"欲知一切法同入法界心无罣碍。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù dé sān zhuǎn shí èr xíng fǎ zhuǎn yì zì zhèng zhī ér bù qǔ zhe","text":"欲得三转十二行法转亦自证知而不取着。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù dé cí xīn biàn fù yī qiè zhòng shēng ér wú xiàn qí yì bù zuò niàn yǒu zhòng shēng xiāng","text":"欲得慈心遍覆一切众生而无限齐亦不作念有众生相。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù dé yú yī qiè zhòng shēng bù qǐ zhèng lùn yì fù bù qǔ wú zhèng lùn xiāng","text":"欲得于一切众生不起诤论亦复不取无诤论相。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"yù zhī shì chù fēi chù shí lì wú wèi zhù fó zhì huì dé wú ài biàn","text":"欲知是处非处十力无畏住佛智慧得无碍辩。"},{"note":"dāng xué bō rě bō luó mì","text":"当学般若波罗蜜。"},{"note":"ěr shí wén shū shī lì bái fó yán","text":"尔时文殊师利白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"wǒ guān zhèng fǎ","text":"我观正法。"},{"note":"wú wèi wú xiāng wú dé wú lì","text":"无为无相无得无利。"},{"note":"wú shēng wú miè wú qù wú lái","text":"无生无灭无去无来。"},{"note":"wú zhī zhě wú jiàn zhě wú zuò zhě","text":"无知者无见者无作者。"},{"note":"bù jiàn bō rě bō luó mì","text":"不见般若波罗蜜。"},{"note":"yì bù jiàn bō rě bō luó mì jìng jiè","text":"亦不见般若波罗蜜境界。"},{"note":"fēi zhèng fēi bù zhèng bù zuò xì lùn wú yǒu fēn bié","text":"非证非不证不作戏论无有分别。"},{"note":"yī qiè fǎ wú jǐn lí jǐn","text":"一切法无尽离尽。"},{"note":"wú fán fū fǎ wú shēng wén fǎ wú pì zhī fó fǎ","text":"无凡夫法无声闻法无辟支佛法。"},{"note":"fēi dé fēi bù dé","text":"非得非不得。"},{"note":"bù shě shēng sǐ bù zhèng niè pán","text":"不舍生死不证涅槃。"},{"note":"fēi sī yì fēi bù sī yì","text":"非思议非不思议。"},{"note":"fēi zuò fēi bù zuò","text":"非作非不作。"},{"note":"fǎ xiāng rú shì","text":"法相如是。"},{"note":"bù zhī yún hé dāng xué bō rě bō luó mì","text":"不知云何当学般若波罗蜜。"},{"note":"ěr shí fó gào wén shū shī lì","text":"尔时佛告文殊师利。"},{"note":"ruò néng rú shì zhī zhū fǎ xiāng","text":"若能如是知诸法相。"},{"note":"shì míng xué bō rě bō luó mì","text":"是名学般若波罗蜜。"},{"note":"pú sà mó hē sà ruò yù xué pú tí zì zài sān mèi","text":"菩萨摩诃萨若欲学菩提自在三昧。"},{"note":"dé shì sān mèi yǐ","text":"得是三昧已。"},{"note":"zhào míng yī qiè shèn shēn fó fǎ jí zhī yī qiè zhū fó míng zì","text":"照明一切甚深佛法及知一切诸佛名字。"},{"note":"yì xī le dá zhū fó shì jiè wú yǒu zhàng ài","text":"亦悉了达诸佛世界无有障碍。"},{"note":"dāng rú wén shū suǒ shuō bō rě bō luó mì zhōng xué","text":"当如文殊所说般若波罗蜜中学。"},{"note":"wén shū bái fó yán","text":"文殊白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"hé gù míng bō rě bō luó mì","text":"何故名般若波罗蜜。"},{"note":"fó yán bō rě bō luó mì wú biān wú jì wú míng wú xiāng fēi sī liàng","text":"佛言般若波罗蜜无边无际无名无相非思量。"},{"note":"wú guī yī wú zhōu zhǔ wú fàn wú fú wú huì wú míng","text":"无归依无洲渚无犯无福无晦无明。"},{"note":"rú fǎ jiè wú yǒu fēn qí yì wú xiàn shù shì míng bō rě bō luó mì","text":"如法界无有分齐亦无限数是名般若波罗蜜。"},{"note":"yì míng pú sà mó hē sà xíng chù","text":"亦名菩萨摩诃萨行处。"},{"note":"fēi xíng fēi bù xíng chù","text":"非行非不行处。"},{"note":"xī rù yī chéng míng fēi xíng chù","text":"悉入一乘名非行处。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"wú niàn wú zuò gù","text":"无念无作故。"},{"note":"jí shì yī qiè zhū fó zhī mǔ","text":"即是一切诸佛之母。"},{"note":"yī qiè zhū fó suǒ cóng shēng gù","text":"一切诸佛所从生故。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yǐ wú shēng gù","text":"以无生故。"},{"note":"shì gù wén shū shī lì","text":"是故文殊师利。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"yù xíng pú sà xíng jù zú zhū bō luó mì","text":"欲行菩萨行具足诸波罗蜜。"},{"note":"dāng xiū cǐ bō rě bō luó mì","text":"当修此般若波罗蜜。"},{"note":"ruò yù dé zuò dào chǎng chéng wú shàng pú tí","text":"若欲得坐道场成无上菩提。"},{"note":"dāng xiū cǐ bō rě bō luó mì","text":"当修此般若波罗蜜。"},{"note":"ruò yù yǐ dà cí dà bēi biàn fù yī qiè zhòng shēng","text":"若欲以大慈大悲遍覆一切众生。"},{"note":"dāng xiū cǐ bō rě bō luó mì","text":"当修此般若波罗蜜。"},{"note":"ruò yù qǐ yī qiè dìng fāng biàn","text":"若欲起一切定方便。"},{"note":"dāng xiū cǐ bō rě bō luó mì","text":"当修此般若波罗蜜。"},{"note":"ruò yù dé yī qiè sān mó bá tí","text":"若欲得一切三摩跋提。"},{"note":"dāng xiū cǐ bō rě bō luó mì","text":"当修此般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"zhū sān mó tí wú suǒ wèi gù","text":"诸三摩提无所为故。"},{"note":"yī qiè zhū fǎ wú chū lí wú chū lí chù","text":"一切诸法无出离无出离处。"},{"note":"ruò rén yù suí zhú cǐ yǔ","text":"若人欲随逐此语。"},{"note":"dāng xiū bō rě bō luó mì","text":"当修般若波罗蜜。"},{"note":"yī qiè zhū fǎ rú shí bù kě dé","text":"一切诸法如实不可得。"},{"note":"ruò yù lè rú shì zhī","text":"若欲乐如是知。"},{"note":"dāng xiū bō rě bō luó mì","text":"当修般若波罗蜜。"},{"note":"yī qiè zhòng shēng wèi pú tí gù xiū pú tí dào","text":"一切众生为菩提故修菩提道。"},{"note":"ér shí wú zhòng shēng yì wú pú tí","text":"而实无众生亦无菩提。"},{"note":"ruò rén yù xìn lè cǐ fǎ","text":"若人欲信乐此法。"},{"note":"dāng xiū bō rě bō luó mì","text":"当修般若波罗蜜。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yī qiè zhū fǎ rú shí yǔ pú tí děng rú","text":"一切诸法如实与菩提等如。"},{"note":"fēi zhòng shēng xíng bù shě zì xìng bǐ zhòng shēng xíng shì fēi xíng","text":"非众生行不舍自性彼众生行是非行。"},{"note":"bǐ fēi xíng shì pú tí","text":"彼非行是菩提。"},{"note":"bǐ pú tí shì fǎ jiè","text":"彼菩提是法界。"},{"note":"ruò yù bù zhe cǐ fǎ","text":"若欲不着此法。"},{"note":"dāng xiū bō rě bō luó mì","text":"当修般若波罗蜜。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"若比丘比丘尼优婆塞优婆夷。"},{"note":"ruò shòu chí bō rě bō luó mì yī sì jù jì wèi tā rén shuō","text":"若受持般若波罗蜜一四句偈为他人说。"},{"note":"wǒ shuō cǐ rén dé bù duò fǎ","text":"我说此人得不堕法。"},{"note":"hé kuàng rú shí xiū xíng","text":"何况如实修行。"},{"note":"dāng zhī bǐ shàn nán zi shàn nǚ rén zhù fó jìng jiè","text":"当知彼善男子善女人住佛境界。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"wén cǐ shèn shēn bō rě bō luó mì","text":"闻此甚深般若波罗蜜。"},{"note":"bù shēng bù wèi","text":"不生怖畏。"},{"note":"dāng zhī cǐ rén shòu fó fǎ yìn","text":"当知此人受佛法印。"},{"note":"cǐ fǎ yìn zhě shì fó suǒ zào shì fó suǒ guì","text":"此法印者是佛所造是佛所贵。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"yǐ cǐ fǎ yìn yìn wú zhe fǎ gù","text":"以此法印印无着法故。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"wèi cǐ yìn suǒ yìn","text":"为此印所印。"},{"note":"dāng zhī shì rén suí pú sà chéng jué dìng bù tuì","text":"当知是人随菩萨乘决定不退。"},{"note":"bù duò shēng wén pì zhī fó dì","text":"不堕声闻辟支佛地。"},{"note":"ěr shí shì tí huán yīn jí zhū tiān zi","text":"尔时释提桓因及诸天子。"},{"note":"cóng sān shí sān tiān","text":"从三十三天。"},{"note":"yǔ xì mò zhān tán jí xì mò jīn xiè","text":"雨细末栴檀及细末金屑。"},{"note":"yòu sàn yù bō luó huá bō tóu mó huá jū wù tuó huá fēn tuó lì huá jí màn tuó luó huá","text":"又散郁波罗华钵头摩华拘物陀华分陀利华及曼陀罗华。"},{"note":"yǐ gòng yǎng bō rě bō luó mì","text":"以供养般若波罗蜜。"},{"note":"gòng yǎng yǐ zuò rú shì yán","text":"供养已作如是言。"},{"note":"wǒ yǐ gòng yǎng wú shàng wú zhe zuì dì yī fǎ","text":"我已供养无上无着最第一法。"},{"note":"yuàn wǒ lái shì gèng wén cǐ shēn bō rě bō luó mì","text":"愿我来世更闻此深般若波罗蜜。"},{"note":"ruò rén yǐ wèi cǐ shēn bō rě bō luó mì yìn zhī suǒ yìn","text":"若人已为此深般若波罗蜜印之所印。"},{"note":"yuàn qí wèi lái fù dé tīng shòu","text":"愿其未来复得听受。"},{"note":"jiū jìng chéng jiù sà pó ruò zhì","text":"究竟成就萨婆若智。"},{"note":"ěr shí shì tí huán yīn bái fó yán","text":"尔时释提桓因白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"ruò shàn nán zi shàn nǚ rén","text":"若善男子善女人。"},{"note":"wén cǐ bō rě bō luó mì yī jīng yú ěr","text":"闻此般若波罗蜜一经于耳。"},{"note":"wǒ wèi zēng zhǎng fó fǎ gù","text":"我为增长佛法故。"},{"note":"shǒu hù bǐ rén","text":"守护彼人。"},{"note":"miàn bǎi yóu xún bù lìng fēi rén dé qí biàn yě","text":"面百由旬不令非人得其便也。"},{"note":"shì shàn nán zi shàn nǚ rén","text":"是善男子善女人。"},{"note":"jiū jìng dāng dé ā nòu duō luó sān miǎo sān pú tí","text":"究竟当得阿耨多罗三藐三菩提。"},{"note":"wǒ dāng rì rì wǎng dào qí suǒ ér shè gòng yǎng","text":"我当日日往到其所而设供养。"},{"note":"ěr shí fó gào shì tí huán yīn","text":"尔时佛告释提桓因。"},{"note":"rú shì rú shì","text":"如是如是。"},{"note":"jiāo shī jiā","text":"憍尸迦。"},{"note":"dāng zhī bǐ shàn nán zi shàn nǚ rén jù zú fó fǎ","text":"当知彼善男子善女人具足佛法。"},{"note":"bì dìng dé zhì ā nòu duō luó sān miǎo sān pú tí","text":"必定得至阿耨多罗三藐三菩提。"},{"note":"ěr shí wén shū shī lì bái fó yán","text":"尔时文殊师利白佛言。"},{"note":"wéi yuàn shì zūn","text":"唯愿世尊。"},{"note":"yǐ wēi shén lì chí cǐ bō rě bō luó mì jiǔ zhù yú shì","text":"以威神力持此般若波罗蜜久住于世。"},{"note":"wèi yù ráo yì zhū zhòng shēng gù","text":"为欲饶益诸众生故。"},{"note":"wén shū shī lì shuō cǐ yǔ shí","text":"文殊师利说此语时。"},{"note":"yǐ fó shén lì dà dì liù zhǒng zhèn dòng","text":"以佛神力大地六种震动。"},{"note":"ěr shí shì zūn jí biàn wēi xiào fàng dà guāng míng","text":"尔时世尊即便微笑放大光明。"},{"note":"biàn zhào sān qiān dà qiān shì jiè","text":"遍照三千大千世界。"},{"note":"yǐ wēi shén lì chí cǐ bō rě bō luó mì lìng jiǔ zhù shì","text":"以威神力持此般若波罗蜜令久住世。"},{"note":"ěr shí wén shū shī lì fù bái fó yán","text":"尔时文殊师利复白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"fàng cǐ guāng míng shì chí bō rě bō luó mì xiāng","text":"放此光明是持般若波罗蜜相。"},{"note":"fó gào wén shū shī lì","text":"佛告文殊师利。"},{"note":"rú shì dāng rú shì","text":"如是当如是。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"wǒ fàng cǐ guāng míng shì chí bō rě bō luó mì xiāng","text":"我放此光明是持般若波罗蜜相。"},{"note":"wén shū shī lì","text":"文殊师利。"},{"note":"rǔ jīn dāng zhī zhī wǒ yǐ chí cǐ bō rě bō luó mì jiǔ zhù yú shì","text":"汝今当知知我已持此般若波罗蜜久住于世。"},{"note":"ruò yǒu rén bù qīng huǐ cǐ fǎ bù shuō qí guò","text":"若有人不轻毁此法不说其过。"},{"note":"dāng zhī shì rén yǐ wèi cǐ shēn bō rě bō luó mì yìn zhī suǒ yìn","text":"当知是人已为此深般若波罗蜜印之所印。"},{"note":"shì gù wén shū shī lì","text":"是故文殊师利。"},{"note":"wǒ yú jiǔ yuǎn ān zhù cǐ yìn","text":"我于久远安住此印。"},{"note":"ruò rén yǐ wèi cǐ yìn suǒ yìn","text":"若人已为此印所印。"},{"note":"dāng zhī shì rén bù wèi mó wáng zhī suǒ dé biàn","text":"当知是人不为魔王之所得便。"},{"note":"fó gào dì shì","text":"佛告帝释。"},{"note":"rǔ dāng shòu chí dú sòng cǐ jīng guǎng xuān liú bù","text":"汝当受持读诵此经广宣流布。"},{"note":"shǐ wèi lái shì zhū shàn nán zi shàn nǚ rén dé cǐ fǎ yìn","text":"使未来世诸善男子善女人得此法印。"},{"note":"fù gào ā nán","text":"复告阿难。"},{"note":"rǔ yì shòu chí dú sòng guǎng wèi rén shuō","text":"汝亦受持读诵广为人说。"},{"note":"shí tiān dì shì jí zhǎng lǎo ā nán bái fó yán","text":"时天帝释及长老阿难白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"dāng hé míng cǐ jīng","text":"当何名此经。"},{"note":"wǒ děng yún hé fèng chí","text":"我等云何奉持。"},{"note":"fó yán","text":"佛言。"},{"note":"cǐ jīng míng wén shū shī lì suǒ shuō","text":"此经名文殊师利所说。"},{"note":"yì míng bō rě bō luó mì","text":"亦名般若波罗蜜。"},{"note":"rú shì shòu chí","text":"如是受持。"},{"note":"shàn nán zi shàn nǚ rén yú héng shā jié","text":"善男子善女人于恒沙劫。"},{"note":"yǐ wú jià bǎo zhū bù shī héng hé shā děng zhòng shēng","text":"以无价宝珠布施恒河沙等众生。"},{"note":"zhòng shēng shòu yǐ xī fā dào xīn","text":"众生受已悉发道心。"},{"note":"shì shí shī zhǔ suí qí suǒ yí shì jiào lì xǐ","text":"是时施主随其所宜示教利喜。"},{"note":"lìng dé xū tuó huán guǒ zhì ā luó hàn guǒ","text":"令得须陀洹果至阿罗汉果。"},{"note":"shì rén suǒ dé gōng dé níng wèi duō bù","text":"是人所得功德宁为多不。"},{"note":"ā nán bái fó yán","text":"阿难白佛言。"},{"note":"shèn duō","text":"甚多。"},{"note":"shì zūn","text":"世尊。"},{"note":"fó yán","text":"佛言。"},{"note":"shàn nán zi","text":"善男子。"},{"note":"ruò rén qǐ yī niàn xīn","text":"若人起一念心。"},{"note":"xìn cǐ bō rě bō luó mì jīng bù fěi bàng zhě","text":"信此般若波罗蜜经不诽谤者。"},{"note":"bǐ qián gōng dé","text":"比前功德。"},{"note":"chū guò bǎi bèi qiān bèi bǎi qiān wàn yì bèi","text":"出过百倍千倍百千万亿倍。"},{"note":"nǎi zhì suàn shù pì yù suǒ bù néng zhī hé kuàng jù zú shòu chí dú sòng wèi rén jiě shuō","text":"乃至算数譬喻所不能知何况具足受持读诵为人解说。"},{"note":"shì rén suǒ dé gōng dé wú liàng wú biān","text":"是人所得功德无量无边。"},{"note":"zhū fó rú lái shuō bù néng jǐn","text":"诸佛如来说不能尽。"},{"note":"hé yǐ gù","text":"何以故。"},{"note":"néng shēng yī qiè zhū fó sà pó ruò gù","text":"能生一切诸佛萨婆若故。"},{"note":"ruò xū kōng yǒu jǐn","text":"若虚空有尽。"},{"note":"zé cǐ jīng gōng dé jǐn","text":"则此经功德尽。"},{"note":"ruò fǎ xìng yǒu jǐn","text":"若法性有尽。"},{"note":"zé cǐ jīng gōng dé jǐn","text":"则此经功德尽。"},{"note":"shì gù wén shū shī lì","text":"是故文殊师利。"},{"note":"shàn nán zi shàn nǚ rén yīng qín xíng jīng jìn shǒu hù cǐ jīng","text":"善男子善女人应懃行精进守护此经。"},{"note":"cǐ jīng néng miè shēng sǐ yī qiè bù wèi","text":"此经能灭生死一切怖畏。"},{"note":"néng cuī tiān mó suǒ lì shèng chuáng","text":"能摧天魔所立胜幢。"},{"note":"néng jiāng pú sà dào niè pán guǒ","text":"能将菩萨到涅槃果。"},{"note":"shì jiào xùn dǎo lí yú èr chéng","text":"示教训导离于二乘。"},{"note":"ěr shí dì shì zhǎng lǎo ā nán jù bái fó yán","text":"尔时帝释长老阿难俱白佛言。"},{"note":"shì zūn","text":"世尊。"},{"note":"rú shì rú shì chéng rú fó yán","text":"如是如是诚如佛言。"},{"note":"wǒ děng dāng dǐng dài shòu chí guǎng xuān liú bù","text":"我等当顶戴受持广宣流布。"},{"note":"wéi yuàn rú lái bù yǐ wèi lǜ","text":"唯愿如来不以为虑。"},{"note":"rú shì sān bái yán","text":"如是三白言。"},{"note":"yuàn bù wèi lǜ","text":"愿不为虑。"},{"note":"wǒ děng dāng dǐng dài shòu chí","text":"我等当顶戴受持。"},{"note":"fó shuō cǐ jīng jìng","text":"佛说此经竟。"},{"note":"wén shū shī lì děng zhū pú sà mó hē sà","text":"文殊师利等诸菩萨摩诃萨。"},{"note":"shè lì fú děng bǐ qiū bǐ qiū ní yōu pó sāi yōu pó yí","text":"舍利弗等比丘比丘尼优婆塞优婆夷。"},{"note":"tiān lóng yè chā gàn tà pó ā xiū luó jiā lóu luó jǐn nà luó mó hóu luó qié rén fēi rén děng yī qiè dà zhòng","text":"天龙夜叉干闼婆阿修罗迦楼罗紧那罗摩睺罗伽人非人等一切大众。"},{"note":"wén fó suǒ shuō jiē dà huān xǐ","text":"闻佛所说皆大欢喜。"},{"note":"xìn shòu fèng chí","text":"信受奉持。"}]};
